# ── Liquidity monitoring ─────────────────────────────────────────────────────
# Tracks requested vs actually filled contract counts to measure real Kalshi liquidity.
# At small balance ($172) the $300 hard cap is theoretical — fills are easy.
# When balance grows and Kelly bets approach $300, actual fill rates may diverge.
# _liquidity_obs: per-prefix list of (requested_cents, filled_cents) tuples (last 200).
# Used by /api/liquidity endpoint and to dynamically warn when cap needs adjusting.
_liquidity_obs: dict[str, list] = {px: [] for px in (
    "KXBTC15M", "KXETH15M", "KXXRP15M", "KXSOL15M", "KXDOGE15M",
    "KXBNB15M", "KXHYPE15M", "KXADA15M", "KXAVAX15M",
    "KXBTC-", "KXETH-", "KXXRP-", "KXDOGE-",  # hourly range markets
    "KXBTCD", "KXETHD", "KXXRPD",             # directional BTC/ETH/XRP
    "KXSOLD", "KXSOLE-", "KXBNBD", "KXBNB-",  # SOL/BNB hourly+daily
    "KXHYPED", "KXHYPE-", "KXDOGED",          # HYPE/DOGE directional
)}
_LIQUIDITY_OBS_MAX = 200  # rolling window per coin

# LP rewards cache — polled every 5 minutes during auto-scan.
# Tracks daily_lp_score (Kalshi Volume Incentive Program) + estimated_payout.
# Bot's resting limit orders earn maker rewards; $2K/day pool shared by all makers.
_lp_rewards: dict = {
    "daily_lp_score": 0.0,
    "estimated_payout": 0.0,
    "last_fetched_utc": None,
    "error": None,
}


def _record_liquidity(ticker: str, requested_cents: int, filled_cents: int) -> None:
    """Record a fill observation so we can track whether the $300 cap matches reality.

    WHAT IS "LIQUIDITY" IN PREDICTION MARKETS?
      Liquidity means: how many contracts can you buy/sell without moving the price?
      In a liquid market, you can buy 100 contracts at 55¢ without difficulty.
      In an illiquid market, the first 10 contracts fill at 55¢, but to buy
      more you'd have to "walk up the book" to 58¢, 61¢, etc.

      Kalshi has limited liquidity, especially for smaller-coin markets.
      If we place an order for $300 worth of YES contracts but only $150 fills
      (because there weren't enough sellers at our price), that's a fill rate of 50%.

      WHY DOES THIS MATTER?
        Kelly sizing assumes your full bet gets filled. If only half fills,
        your actual position is too small relative to what Kelly recommended —
        which might be fine, or might mean you miss the target profit.

        More importantly: as our balance grows, Kelly bets grow too. If we
        bet $500 on BTC 15M but Kalshi only has $200 of liquidity at that
        price, our cap needs to be adjusted downward to match reality.
        This function tracks fill rates over time so /api/liquidity can
        warn us when the theoretical bet cap exceeds actual market depth.
    """
    for px, obs in _liquidity_obs.items():
        if ticker.startswith(px):
            obs.append((requested_cents, filled_cents))
            if len(obs) > _LIQUIDITY_OBS_MAX:
                obs.pop(0)
            break


def _liquidity_summary() -> dict:
    """Compute per-coin avg fill rate and suggested cap. Used by /api/liquidity."""
    result = {}
    for px, obs in _liquidity_obs.items():
        if not obs:
            result[px] = {"samples": 0, "fill_rate": None, "suggested_cap_cents": 50_000}
            continue
        fill_rates = [f / max(r, 1) for r, f in obs if r > 0]
        avg_fill = sum(fill_rates) / len(fill_rates) if fill_rates else 1.0
        avg_req = sum(r for r, _ in obs) / len(obs)
        # Suggested cap: if fill rate < 90%, cap at avg_req × fill_rate × 0.9 safety margin
        if avg_fill >= 0.90:
            suggested = 50_000
        else:
            suggested = max(500, int(avg_req * avg_fill * 0.90))
        result[px] = {
            "samples": len(obs),
            "avg_requested_cents": round(avg_req),
            "fill_rate": round(avg_fill, 3),
            "suggested_cap_cents": suggested,
        }
    return result


# ── Cross-asset lag detector ─────────────────────────────────────────────────
