def _wxx_write_trade_db(
    db_path: str, bot_id: str, ticker: str, side: str,
    entry_price: int, exit_price, count: int,
    pnl_cents, won, entry_time: str, exit_time: str,
    edge_cents=None, fair_prob=None,
) -> None:
    """Persist a settled shadow trade to the given wave DB."""
    try:
        import sqlite3 as _sq3wxx
        _wxxdb = _sq3wxx.connect(db_path)
        _wxxdb.execute("""CREATE TABLE IF NOT EXISTS trades (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            ts          INTEGER NOT NULL,
            bot_id      TEXT NOT NULL,
            ticker      TEXT NOT NULL,
            side        TEXT NOT NULL,
            entry_price INTEGER NOT NULL,
            exit_price  INTEGER,
            count       INTEGER NOT NULL,
            pnl_cents   INTEGER,
            won         INTEGER,
            entry_time  TEXT NOT NULL,
            exit_time   TEXT,
            edge_cents  REAL,
            fair_prob   REAL
        )""")
        _wxxdb.commit()
        import time as _twxx
        _wxxdb.execute(
            """INSERT INTO trades
               (ts,bot_id,ticker,side,entry_price,exit_price,count,pnl_cents,won,entry_time,exit_time,edge_cents,fair_prob)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (int(_twxx.time()), bot_id, ticker, side, entry_price, exit_price,
             count, pnl_cents, (1 if won else 0) if won is not None else None,
             entry_time, exit_time, edge_cents, fair_prob),
        )
        _wxxdb.commit()
        _wxxdb.close()
    except Exception:
        pass


def _w16_write_trade_db(bot_id, ticker, side, entry_price, exit_price, count, pnl_cents, won, entry_time, exit_time, edge_cents=None, fair_prob=None):
    _wxx_write_trade_db(_W16_DB_PATH, bot_id, ticker, side, entry_price, exit_price, count, pnl_cents, won, entry_time, exit_time, edge_cents, fair_prob)

