def _w24_build_bots() -> dict:
    """W24: 1000 bots — regime-proxy via min_ps_strength, min_cs_strength, require_agree."""
    import random as _rnd24

    def _mk24(id, label, **kw):
        _wps = kw.get("wp_sig", 0.70); _rem = 1.0 - _wps
        cfg = {
            "id": id, "label": label,
            "edge":          kw.get("edge",     10.0),
            "kelly":         kw.get("kelly",     0.35),
            "ceiling":       kw.get("ceiling",    5),
            "wp":            kw.get("wp",         0.60),
            "coins":         kw.get("coins",      None),
            "time_dz":       kw.get("time_dz",    True),
            "bad_hours":     kw.get("bad_hours",   None),
            "max_pct":       kw.get("max_pct",     0.10),
            "vol_scale":     kw.get("vol_scale",   True),
            "spread_adj":    kw.get("spread_adj",  True),
            "corr_defl":     kw.get("corr_defl",   True),
            "wp_sig":        _wps,
            "wm_sig":        kw.get("wm_sig", round(_rem * 0.667, 4)),
            "wi_sig":        kw.get("wi_sig", round(_rem * 0.223, 4)),
            "wf_sig":        kw.get("wf_sig", round(max(0.0, 1.0 - _wps
                                                        - kw.get("wm_sig", round(_rem*0.667,4))
                                                        - kw.get("wi_sig", round(_rem*0.223,4))), 4)),
            "min_p_price":   kw.get("min_p_price", 0.0),
            "max_spread":    kw.get("max_spread",   99),
            "min_imbalance": kw.get("min_imbalance",0.0),
            "stop_loss_pct": kw.get("stop_loss_pct",0.0),
            "gain_lock_pct": kw.get("gain_lock_pct",0.0),
            "peak_dd_pct":   kw.get("peak_dd_pct",  0.0),
            "min_ps_strength": kw.get("min_ps_strength", 0.0),
            "min_cs_strength": kw.get("min_cs_strength", 0.0),
            "require_agree":   kw.get("require_agree",   0),
            "flat_cents":      kw.get("flat_cents",       0),
            "fund_amp":        kw.get("fund_amp",         1.0),
        }
        _s = cfg["wp_sig"] + cfg["wm_sig"] + cfg["wi_sig"] + cfg["wf_sig"]
        if abs(_s - 1.0) > 0.01:
            cfg["wm_sig"] = round(cfg["wm_sig"] / _s, 4)
            cfg["wi_sig"] = round(cfg["wi_sig"] / _s, 4)
            cfg["wf_sig"] = round(cfg["wf_sig"] / _s, 4)
            cfg["wp_sig"] = round(1.0 - cfg["wm_sig"] - cfg["wi_sig"] - cfg["wf_sig"], 4)
        return cfg

    cfgs = []
    cfgs.append(_mk24("w24_ctrl", "W24_CTRL_WP60_E11_K35", wp=0.60, edge=11.0, kelly=0.35, wp_sig=0.95))

    # A: min_ps_strength × min_cs_strength × E (6×5×5 = 150)
    for _ps in [0.0, 0.05, 0.08, 0.10, 0.15, 0.20]:
        for _cs in [0.0, 0.05, 0.08, 0.12, 0.18]:
            for _e in [7.0, 9.0, 11.0, 13.0, 15.0]:
                cfgs.append(_mk24(
                    f"w24_a_ps{int(_ps*100)}_cs{int(_cs*100)}_e{int(_e*10)}",
                    f"W24_PS{int(_ps*100)}_CS{int(_cs*100)}_E{int(_e*10)}",
                    min_ps_strength=_ps, min_cs_strength=_cs, edge=_e, wp=0.60, kelly=0.35))

    # B: WP × E × min_ps (5×7×4 = 140)
    for _wp in [0.55, 0.58, 0.60, 0.62, 0.65]:
        for _e in [7.0, 8.0, 9.0, 10.0, 11.0, 12.0, 13.0]:
            for _ps in [0.0, 0.05, 0.10, 0.15]:
                cfgs.append(_mk24(
                    f"w24_b_wp{int(_wp*100)}_e{int(_e*10)}_ps{int(_ps*100)}",
                    f"W24_WP{int(_wp*100)}_E{int(_e*10)}_PS{int(_ps*100)}",
                    wp=_wp, edge=_e, min_ps_strength=_ps, kelly=0.35))

    # C: min_p_price × WP × K (7×5×5 = 175)
    for _mpp in [0.55, 0.58, 0.60, 0.62, 0.65, 0.68, 0.70]:
        for _wp in [0.55, 0.58, 0.60, 0.62, 0.65]:
            for _k in [0.25, 0.30, 0.35, 0.40, 0.45]:
                cfgs.append(_mk24(
                    f"w24_c_pp{int(_mpp*100)}_wp{int(_wp*100)}_k{int(_k*100)}",
                    f"W24_PP{int(_mpp*100)}_WP{int(_wp*100)}_K{int(_k*100)}",
                    min_p_price=_mpp, wp=_wp, kelly=_k, edge=10.0))

    # D: stop_loss + gain_lock with WP60/E10-11 (4×4×3 = 48)
    for _sl in [0.10, 0.15, 0.20, 0.30]:
        for _gl in [0.20, 0.40, 0.70, 1.00]:
            for _e in [9.0, 11.0, 13.0]:
                cfgs.append(_mk24(
                    f"w24_d_sl{int(_sl*100)}_gl{int(_gl*100)}_e{int(_e*10)}",
                    f"W24_SL{int(_sl*100)}_GL{int(_gl*100)}_E{int(_e*10)}",
                    stop_loss_pct=_sl, gain_lock_pct=_gl, edge=_e, wp=0.60, kelly=0.35))

    # E: require_agree × E × WP (3×6×5 = 90)
    for _ra in [1, 2, 3]:
        for _e in [7.0, 9.0, 10.0, 11.0, 13.0, 15.0]:
            for _wp in [0.55, 0.58, 0.60, 0.62, 0.65]:
                cfgs.append(_mk24(
                    f"w24_e_ra{_ra}_e{int(_e*10)}_wp{int(_wp*100)}",
                    f"W24_AGREE{_ra}_E{int(_e*10)}_WP{int(_wp*100)}",
                    require_agree=_ra, edge=_e, wp=_wp, kelly=0.35))

    # F: High-wp_sig (PRICE_ONLY proxy) + regime filters (5×4×3 = 60)
    for _wps in [0.85, 0.90, 0.93, 0.96, 0.99]:
        _r = 1.0 - _wps
        for _mpp in [0.0, 0.58, 0.62, 0.65]:
            for _e in [9.0, 11.0, 13.0]:
                cfgs.append(_mk24(
                    f"w24_f_wps{int(_wps*100)}_pp{int(_mpp*100)}_e{int(_e*10)}",
                    f"W24_WPS{int(_wps*100)}_PP{int(_mpp*100)}_E{int(_e*10)}",
                    wp_sig=_wps, wm_sig=round(_r*0.667,4), wi_sig=round(_r*0.223,4), wf_sig=round(_r*0.110,4),
                    min_p_price=_mpp, edge=_e, wp=0.60, kelly=0.35))

    # Z: Random combos to fill to 1000
    _rnd24.seed(24)
    for _zi in range(1000 - len(cfgs)):
        _e   = round(_rnd24.uniform(6.0, 16.0), 1)
        _k   = round(_rnd24.uniform(0.20, 0.50), 2)
        _wp  = round(_rnd24.uniform(0.52, 0.68), 2)
        _mpp = round(_rnd24.uniform(0.50, 0.72), 2) if _rnd24.random() > 0.4 else 0.0
        _ps  = round(_rnd24.uniform(0.0, 0.18), 2)
        _cs  = round(_rnd24.uniform(0.0, 0.15), 2)
        _ra  = _rnd24.choice([0, 0, 1, 2])
        _wps = round(_rnd24.uniform(0.50, 0.99), 3)
        _r   = 1.0 - _wps
        _wm  = round(_r * _rnd24.uniform(0.40, 0.80), 4)
        _wf  = round(_r * _rnd24.uniform(0.00, 0.12), 4)
        _wi  = max(0.001, round(1.0 - _wps - _wm - _wf, 4))
        _sl  = round(_rnd24.uniform(0.0, 0.25), 2)
        cfgs.append(_mk24(f"w24_z_{_zi:03d}", f"W24_COMBO_{_zi:03d}",
            edge=_e, kelly=_k, wp=_wp, min_p_price=_mpp,
            min_ps_strength=_ps, min_cs_strength=_cs, require_agree=_ra,
            wp_sig=_wps, wm_sig=_wm, wi_sig=_wi, wf_sig=_wf, stop_loss_pct=_sl))

    result = {}
    for _cfg in cfgs:
        result[_cfg["id"]] = {
            "balance": _W24_INIT_BAL, "positions": {}, "trades": [],
            "peak": _W24_INIT_BAL, "config": _cfg, "pruned": False,
        }
    return result

