# ── Wave 25 — 1000 bots: funding & imbalance ablation + zero-noise formula ───
_W25_INIT_BAL: int = 8_000
_W25_DB_PATH: str  = _os_wxx2.path.join(_os_wxx2.path.dirname(__file__), "..", "data", "w25_tournament.db")
def _w25_write_trade_db(bot_id, ticker, side, ep, xp, cnt, pnl, won, et, xt, ec=None, fp=None):
    _wxx_write_trade_db2(_W25_DB_PATH, bot_id, ticker, side, ep, xp, cnt, pnl, won, et, xt, ec, fp)

def _w25_build_bots() -> dict:
    """W25: 1000 bots — funding ablation, imbalance ablation, pure price×market formula."""
    import random as _rnd25

    def _mk25(id, label, **kw):
        _wps = kw.get("wp_sig", 0.70)
        _wm  = kw.get("wm_sig", 0.20)
        _wi  = kw.get("wi_sig", 0.07)
        _wf  = kw.get("wf_sig", 0.03)
        _s   = _wps + _wm + _wi + _wf
        if abs(_s - 1.0) > 0.005:
            _wm = round(_wm / _s, 4); _wi = round(_wi / _s, 4)
            _wf = round(_wf / _s, 4); _wps = round(1.0 - _wm - _wi - _wf, 4)
        cfg = {
            "id": id, "label": label,
            "edge":          kw.get("edge",     10.0),
            "kelly":         kw.get("kelly",     0.35),
            "ceiling":       kw.get("ceiling",    5),
            "wp":            kw.get("wp",         0.60),
            "coins":         kw.get("coins",      None),
            "time_dz":       kw.get("time_dz",    True),
            "bad_hours":     kw.get("bad_hours",   None),
            "max_pct":       kw.get("max_pct",     0.10),
            "vol_scale":     kw.get("vol_scale",   True),
            "spread_adj":    kw.get("spread_adj",  True),
            "corr_defl":     kw.get("corr_defl",   True),
            "wp_sig": _wps, "wm_sig": _wm, "wi_sig": _wi, "wf_sig": _wf,
            "min_p_price":   kw.get("min_p_price", 0.0),
            "max_spread":    kw.get("max_spread",   99),
            "min_imbalance": kw.get("min_imbalance",0.0),
            "stop_loss_pct": kw.get("stop_loss_pct",0.0),
            "gain_lock_pct": kw.get("gain_lock_pct",0.0),
            "peak_dd_pct":   kw.get("peak_dd_pct",  0.0),
            "min_ps_strength": kw.get("min_ps_strength", 0.0),
            "min_cs_strength": kw.get("min_cs_strength", 0.0),
            "require_agree":   kw.get("require_agree",   0),
            "flat_cents":      kw.get("flat_cents",       0),
            "fund_amp":        kw.get("fund_amp",         1.0),
        }
        return cfg

    cfgs = []
    cfgs.append(_mk25("w25_ctrl", "W25_CTRL_WP60_E11_K35", wp_sig=0.70, wm_sig=0.20, wi_sig=0.07, wf_sig=0.03,
                       edge=11.0, kelly=0.35, wp=0.60))

    # A: Funding ablation — wp_sig × wf_sig × E (7×8×4 = 224)
    for _wps in [0.45, 0.50, 0.55, 0.60, 0.65, 0.70, 0.75]:
        for _wf in [0.00, 0.01, 0.02, 0.03, 0.05, 0.07, 0.10, 0.15]:
            _rem = 1.0 - _wps - _wf
            if _rem < 0.05: continue
            _wm = round(_rem * 0.75, 4); _wi = max(0.001, round(_rem - _wm, 4))
            for _e in [8.0, 10.0, 11.0, 13.0]:
                cfgs.append(_mk25(
                    f"w25_a_wps{int(_wps*100)}_wf{int(_wf*100)}_e{int(_e*10)}",
                    f"W25_WPS{int(_wps*100)}_WF{int(_wf*100)}_E{int(_e*10)}",
                    wp_sig=_wps, wm_sig=_wm, wi_sig=_wi, wf_sig=_wf, edge=_e, kelly=0.35, wp=0.60))

    # B: Imbalance ablation — wp_sig × wi_sig × E (7×7×3 = 147)
    for _wps in [0.45, 0.50, 0.55, 0.60, 0.65, 0.70, 0.75]:
        for _wi in [0.00, 0.02, 0.05, 0.07, 0.10, 0.15, 0.20]:
            _rem = 1.0 - _wps - _wi
            if _rem < 0.05: continue
            _wm = round(_rem * 0.80, 4); _wf = max(0.001, round(_rem - _wm, 4))
            for _e in [9.0, 11.0, 13.0]:
                cfgs.append(_mk25(
                    f"w25_b_wps{int(_wps*100)}_wi{int(_wi*100)}_e{int(_e*10)}",
                    f"W25_WPS{int(_wps*100)}_WI{int(_wi*100)}_E{int(_e*10)}",
                    wp_sig=_wps, wm_sig=_wm, wi_sig=_wi, wf_sig=_wf, edge=_e, kelly=0.35, wp=0.60))

    # C: Pure price × market (wf=0, wi=0) — wp_sig × E × K (13×7×3 = 273)
    for _wps in [0.30, 0.35, 0.40, 0.45, 0.50, 0.55, 0.60, 0.65, 0.70, 0.75, 0.80, 0.85, 0.90]:
        _wm = round(1.0 - _wps, 4)
        for _e in [7.0, 8.0, 9.0, 10.0, 11.0, 12.0, 13.0]:
            for _k in [0.28, 0.35, 0.42]:
                cfgs.append(_mk25(
                    f"w25_c_wps{int(_wps*100)}_e{int(_e*10)}_k{int(_k*100)}",
                    f"W25_PM_WPS{int(_wps*100)}_E{int(_e*10)}_K{int(_k*100)}",
                    wp_sig=_wps, wm_sig=_wm, wi_sig=0.0, wf_sig=0.0, edge=_e, kelly=_k, wp=0.60))

    # Z: Random combos to fill to 1000
    _rnd25.seed(25)
    for _zi in range(1000 - len(cfgs)):
        _wps = round(_rnd25.uniform(0.35, 0.90), 3)
        _wf  = round(_rnd25.uniform(0.0, 0.10), 3)
        _wi  = round(_rnd25.uniform(0.0, 0.15), 3)
        _rem = max(0.05, 1.0 - _wps - _wf - _wi)
        _wm  = round(_rem, 4)
        _e   = round(_rnd25.uniform(7.0, 15.0), 1)
        _k   = round(_rnd25.uniform(0.20, 0.50), 2)
        _wp  = round(_rnd25.uniform(0.52, 0.68), 2)
        cfgs.append(_mk25(f"w25_z_{_zi:03d}", f"W25_COMBO_{_zi:03d}",
            wp_sig=_wps, wm_sig=_wm, wi_sig=_wi, wf_sig=_wf, edge=_e, kelly=_k, wp=_wp))

    result = {}
    for _cfg in cfgs:
        result[_cfg["id"]] = {
            "balance": _W25_INIT_BAL, "positions": {}, "trades": [],
            "peak": _W25_INIT_BAL, "config": _cfg, "pruned": False,
        }
    return result

