def _w26_build_bots() -> dict:
    """W26: 1049 bots — comprehensive combos; brings total to 15 000."""
    import random as _rnd26

    def _mk26(id, label, **kw):
        _wps = kw.get("wp_sig", 0.70)
        _wm  = kw.get("wm_sig", 0.20)
        _wi  = kw.get("wi_sig", 0.07)
        _wf  = kw.get("wf_sig", 0.03)
        _s   = _wps + _wm + _wi + _wf
        if abs(_s - 1.0) > 0.005:
            _wm = round(_wm / _s, 4); _wi = round(_wi / _s, 4)
            _wf = round(_wf / _s, 4); _wps = round(1.0 - _wm - _wi - _wf, 4)
        cfg = {
            "id": id, "label": label,
            "edge":          kw.get("edge",     10.0),
            "kelly":         kw.get("kelly",     0.35),
            "ceiling":       kw.get("ceiling",    5),
            "wp":            kw.get("wp",         0.60),
            "coins":         kw.get("coins",      None),
            "time_dz":       kw.get("time_dz",    True),
            "bad_hours":     kw.get("bad_hours",   None),
            "max_pct":       kw.get("max_pct",     0.10),
            "vol_scale":     kw.get("vol_scale",   True),
            "spread_adj":    kw.get("spread_adj",  True),
            "corr_defl":     kw.get("corr_defl",   True),
            "wp_sig": _wps, "wm_sig": _wm, "wi_sig": _wi, "wf_sig": _wf,
            "min_p_price":   kw.get("min_p_price", 0.0),
            "max_spread":    kw.get("max_spread",   99),
            "min_imbalance": kw.get("min_imbalance",0.0),
            "stop_loss_pct": kw.get("stop_loss_pct",0.0),
            "gain_lock_pct": kw.get("gain_lock_pct",0.0),
            "peak_dd_pct":   kw.get("peak_dd_pct",  0.0),
            "min_ps_strength": kw.get("min_ps_strength", 0.0),
            "min_cs_strength": kw.get("min_cs_strength", 0.0),
            "require_agree":   kw.get("require_agree",   0),
            "flat_cents":      kw.get("flat_cents",       0),
            "fund_amp":        kw.get("fund_amp",         1.0),
        }
        return cfg

    cfgs = []
    cfgs.append(_mk26("w26_ctrl", "W26_CTRL_WP60_E11_K35", wp=0.60, edge=11.0, kelly=0.35))

    # A: WP × E × min_p_price × K (5×5×5×4 = 500, sample to ~200)
    _rnd26.seed(26)
    _seen26 = set()
    _a_wp   = [0.55, 0.58, 0.60, 0.62, 0.65]
    _a_e    = [7.0, 9.0, 10.0, 11.0, 13.0]
    _a_mpp  = [0.0, 0.58, 0.60, 0.63, 0.68]
    _a_k    = [0.28, 0.32, 0.35, 0.40]
    for _wp in _a_wp:
        for _e in _a_e:
            for _mpp in _a_mpp:
                for _k in _a_k:
                    _bid = f"w26_a_wp{int(_wp*100)}_e{int(_e*10)}_pp{int(_mpp*100)}_k{int(_k*100)}"
                    if _bid in _seen26: continue
                    _seen26.add(_bid)
                    cfgs.append(_mk26(_bid,
                        f"W26_WP{int(_wp*100)}_E{int(_e*10)}_PP{int(_mpp*100)}_K{int(_k*100)}",
                        wp=_wp, edge=_e, min_p_price=_mpp, kelly=_k))

    # B: Pure price formula (wm_sig only) × WP × E × K (9×3×5×3 = 405, add ~200)
    _count_b = 0
    for _wps in [0.40, 0.45, 0.50, 0.55, 0.60, 0.65, 0.70, 0.75, 0.80]:
        _wm = round(1.0 - _wps, 4)
        for _wp in [0.55, 0.60, 0.65]:
            for _e in [7.0, 9.0, 10.0, 11.0, 13.0]:
                for _k in [0.28, 0.35, 0.42]:
                    if _count_b >= 200: break
                    _bid = f"w26_b_wps{int(_wps*100)}_wp{int(_wp*100)}_e{int(_e*10)}_k{int(_k*100)}"
                    if _bid in _seen26: continue
                    _seen26.add(_bid)
                    cfgs.append(_mk26(_bid,
                        f"W26_PM_WPS{int(_wps*100)}_WP{int(_wp*100)}_E{int(_e*10)}_K{int(_k*100)}",
                        wp_sig=_wps, wm_sig=_wm, wi_sig=0.0, wf_sig=0.0,
                        wp=_wp, edge=_e, kelly=_k))
                    _count_b += 1
                if _count_b >= 200: break
            if _count_b >= 200: break
        if _count_b >= 200: break

    # Z: Random combos to fill to 1049
    for _zi in range(1049 - len(cfgs)):
        _e   = round(_rnd26.uniform(6.0, 17.0), 1)
        _k   = round(_rnd26.uniform(0.18, 0.55), 2)
        _wp  = round(_rnd26.uniform(0.50, 0.70), 2)
        _mpp = round(_rnd26.uniform(0.50, 0.72), 2) if _rnd26.random() > 0.5 else 0.0
        _wps = round(_rnd26.uniform(0.35, 0.99), 3)
        _r   = 1.0 - _wps
        _wm  = round(_r * _rnd26.uniform(0.30, 0.90), 4)
        _wf  = round(_r * _rnd26.uniform(0.0, 0.15), 4)
        _wi  = max(0.0, round(1.0 - _wps - _wm - _wf, 4))
        _ps  = round(_rnd26.uniform(0.0, 0.18), 2)
        _ra  = _rnd26.choice([0, 0, 0, 1, 2])
        _sl  = round(_rnd26.uniform(0.0, 0.30), 2)
        cfgs.append(_mk26(f"w26_z_{_zi:04d}", f"W26_COMBO_{_zi:04d}",
            edge=_e, kelly=_k, wp=_wp, min_p_price=_mpp,
            wp_sig=_wps, wm_sig=_wm, wi_sig=_wi, wf_sig=_wf,
            min_ps_strength=_ps, require_agree=_ra, stop_loss_pct=_sl))

    result = {}
    for _cfg in cfgs:
        result[_cfg["id"]] = {
            "balance": _W26_INIT_BAL, "positions": {}, "trades": [],
            "peak": _W26_INIT_BAL, "config": _cfg, "pruned": False,
        }
    return result

