def _w27_build_bots() -> dict:
    """W27: 1000 bots — coin-specific, low-edge, time-of-day, spread filters. Brings total to 15 000."""
    def _mk27(id, label, **kw):
        _wps = kw.get("wp_sig", 0.70)
        _wm  = kw.get("wm_sig", 0.20)
        _wi  = kw.get("wi_sig", 0.07)
        _wf  = kw.get("wf_sig", 0.03)
        _s   = _wps + _wm + _wi + _wf
        if abs(_s - 1.0) > 0.005:
            _wm = round(_wm / _s, 4); _wi = round(_wi / _s, 4)
            _wf = round(_wf / _s, 4); _wps = round(1.0 - _wm - _wi - _wf, 4)
        cfg = {
            "id": id, "label": label,
            "edge":          kw.get("edge",     10.0),
            "kelly":         kw.get("kelly",     0.35),
            "ceiling":       kw.get("ceiling",    5),
            "wp":            kw.get("wp",         0.60),
            "coins":         kw.get("coins",      None),
            "time_dz":       kw.get("time_dz",    True),
            "bad_hours":     kw.get("bad_hours",   None),
            "max_pct":       kw.get("max_pct",     0.10),
            "vol_scale":     kw.get("vol_scale",   True),
            "spread_adj":    kw.get("spread_adj",  True),
            "corr_defl":     kw.get("corr_defl",   True),
            "wp_sig": _wps, "wm_sig": _wm, "wi_sig": _wi, "wf_sig": _wf,
            "min_p_price":   kw.get("min_p_price", 0.0),
            "max_spread":    kw.get("max_spread",   99),
            "min_imbalance": kw.get("min_imbalance",0.0),
            "stop_loss_pct": kw.get("stop_loss_pct",0.0),
            "gain_lock_pct": kw.get("gain_lock_pct",0.0),
            "peak_dd_pct":   kw.get("peak_dd_pct",  0.0),
            "min_ps_strength": kw.get("min_ps_strength", 0.0),
            "min_cs_strength": kw.get("min_cs_strength", 0.0),
            "require_agree":   kw.get("require_agree",   0),
            "flat_cents":      kw.get("flat_cents",       0),
            "fund_amp":        kw.get("fund_amp",         1.0),
        }
        return cfg

    cfgs = []
    cfgs.append(_mk27("w27_ctrl", "W27_CTRL_WP60_E11_K35", wp=0.60, edge=11.0, kelly=0.35))

    # A: Coin-specific bots (5 coins × WP × E × K = 5×3×5×4 = 300)
    _a_coins = {
        "BTC": ["KXBTC"], "ETH": ["KXETH"], "SOL": ["KXSOL"],
        "DOGE": ["KXDOGE"], "HYPE": ["KXHYPE"],
    }
    _a_wp  = [0.55, 0.60, 0.65]
    _a_e   = [8.0, 9.0, 10.0, 11.0, 13.0]
    _a_k   = [0.28, 0.32, 0.35, 0.40]
    for _cn, _cpfx in _a_coins.items():
        for _wp in _a_wp:
            for _e in _a_e:
                for _k in _a_k:
                    _bid = f"w27_a_{_cn.lower()}_wp{int(_wp*100)}_e{int(_e*10)}_k{int(_k*100)}"
                    cfgs.append(_mk27(_bid,
                        f"W27_{_cn}_WP{int(_wp*100)}_E{int(_e*10)}_K{int(_k*100)}",
                        coins=_cpfx, wp=_wp, edge=_e, kelly=_k))

    # B: Aggressive low-edge (E5–E8) × WP × K — does relaxing edge gate help? (5×4×5 = 100)
    _b_e  = [5.0, 6.0, 7.0, 7.5, 8.0]
    _b_wp = [0.55, 0.60, 0.63, 0.65]
    _b_k  = [0.20, 0.25, 0.30, 0.35, 0.40]
    for _e in _b_e:
        for _wp in _b_wp:
            for _k in _b_k:
                _bid = f"w27_b_e{int(_e*10)}_wp{int(_wp*100)}_k{int(_k*100)}"
                cfgs.append(_mk27(_bid,
                    f"W27_LOWE_E{int(_e*10)}_WP{int(_wp*100)}_K{int(_k*100)}",
                    edge=_e, wp=_wp, kelly=_k))

    # C: Time-of-day aware — skip choppy hours (0-2 UTC, 12-14 UTC) × WP × E (4×3×4 = 48)
    _c_bad_hour_sets = [
        [0, 1, 2, 3],           # skip dead early hours
        [12, 13, 14],           # skip midday lull
        [0, 1, 12, 13],         # skip both
        [0, 1, 2, 3, 12, 13, 14],  # aggressive avoidance
    ]
    _c_wp = [0.55, 0.60, 0.65]
    _c_e  = [9.0, 10.0, 11.0, 13.0]
    for _bhi, _bh in enumerate(_c_bad_hour_sets):
        for _wp in _c_wp:
            for _e in _c_e:
                _bid = f"w27_c_bh{_bhi}_wp{int(_wp*100)}_e{int(_e*10)}"
                cfgs.append(_mk27(_bid,
                    f"W27_TOD{_bhi}_WP{int(_wp*100)}_E{int(_e*10)}",
                    bad_hours=_bh, wp=_wp, edge=_e, kelly=0.35))

    # D: Max spread filter × WP × E × K — tighter spread = better fill quality (4×3×4×3 = 144)
    _d_ms = [5, 8, 12, 18]   # max allowed spread in cents
    _d_wp = [0.55, 0.60, 0.65]
    _d_e  = [8.0, 9.0, 11.0, 13.0]
    _d_k  = [0.28, 0.35, 0.42]
    for _ms in _d_ms:
        for _wp in _d_wp:
            for _e in _d_e:
                for _k in _d_k:
                    _bid = f"w27_d_ms{_ms}_wp{int(_wp*100)}_e{int(_e*10)}_k{int(_k*100)}"
                    cfgs.append(_mk27(_bid,
                        f"W27_SP{_ms}_WP{int(_wp*100)}_E{int(_e*10)}_K{int(_k*100)}",
                        max_spread=_ms, wp=_wp, edge=_e, kelly=_k))

    # E: Kelly extremes × WP × E — test K0.45–0.60 range (5×3×4 = 60)
    _e_k  = [0.45, 0.48, 0.50, 0.55, 0.60]
    _e_wp = [0.55, 0.60, 0.65]
    _e_e  = [9.0, 10.0, 11.0, 13.0]
    for _k in _e_k:
        for _wp in _e_wp:
            for _e in _e_e:
                _bid = f"w27_e_k{int(_k*100)}_wp{int(_wp*100)}_e{int(_e*10)}"
                cfgs.append(_mk27(_bid,
                    f"W27_HIGHK_K{int(_k*100)}_WP{int(_wp*100)}_E{int(_e*10)}",
                    kelly=_k, wp=_wp, edge=_e))

    # F: fill to exactly 1000 with controlled random combos
    import random as _rnd27
    _rnd27.seed(27)
    _seen27 = {c["id"] for c in cfgs}
    _fi = 0
    while len(cfgs) < 1000:
        _e   = round(_rnd27.uniform(6.0, 15.0), 1)
        _k   = round(_rnd27.uniform(0.20, 0.55), 2)
        _wp  = round(_rnd27.uniform(0.50, 0.70), 2)
        _ms  = _rnd27.choice([5, 8, 12, 18, 99])
        _bh  = _rnd27.choice([None, [0,1,2], [12,13,14], [0,1,12,13]])
        _wps = round(_rnd27.uniform(0.50, 0.95), 3)
        _wm  = round((1.0 - _wps) * 0.6, 4)
        _wi  = round((1.0 - _wps) * 0.3, 4)
        _wf  = max(0.0, round(1.0 - _wps - _wm - _wi, 4))
        _bid = f"w27_f_{_fi:04d}"
        if _bid in _seen27: _fi += 1; continue
        _seen27.add(_bid)
        cfgs.append(_mk27(_bid, f"W27_RAND_{_fi:04d}",
            edge=_e, kelly=_k, wp=_wp, max_spread=_ms, bad_hours=_bh,
            wp_sig=_wps, wm_sig=_wm, wi_sig=_wi, wf_sig=_wf))
        _fi += 1

    result = {}
    for _cfg in cfgs:
        result[_cfg["id"]] = {
            "balance": _W27_INIT_BAL, "positions": {}, "trades": [],
            "peak": _W27_INIT_BAL, "config": _cfg, "pruned": False,
        }
    return result

