# ─────────────────────────────────────────────────────────────────────────────
# Wave 33 — 200-bot focused tournament (replaces W7–W32 which are now disabled)
# ─────────────────────────────────────────────────────────────────────────────
# Design rationale (from DB analysis of 37,828 shadow trades):
#   - W12 top performers: J2 (P85/I10/F05, avg+131¢), A_P88 (+94¢), B_M05 (+95¢)
#   - NO trades massively outperform YES (avg +82¢ vs +23¢ on W12)
#   - HYPE is catastrophically bad (-207¢/trade); BTC/XRP/DOGE are strong
#   - Price weight 0.85-0.90 (no market term) beats P70 by 2x
#   - Edge sweet spot: E11-E15; higher edge (E20+) fails due to low trade volume
#   - Kelly K25-K35 optimal; K40+ is riskier with diminishing returns
#   - Dead zone DZ0 (no gate) or DZ55 are better than DZ60+
#
# Config format: {"id":..., "label":..., "wp":..., "wm":..., "wi":..., "wf":...,
#                 "edge":..., "kelly":..., "dz":..., "time_dz":...}
#   wp+wm+wi+wf must sum to exactly 1.0 (verified by assert in _w12_build_bots helper)
#   wp = price weight, wm = market/consensus weight, wi = imbalance, wf = funding
#
# AUTO-PROMOTION: After 4+ consecutive 15-min winning windows (= 1 profitable hour),
#   the leading W33 bot's config is promoted to live globals via _w33_check_promote().
#   Tracked by _w33_profitable_since dict (bot_id -> epoch_ts of first profit window).
#   Promotion requires: pnl > 0, ≥4 settled trades, win_rate ≥ 0.45.
#
# Legacy waves W7–W32 are zeroed out (empty dicts) — they don't run but their
#   build functions and settlement loops remain intact for historical reference.
_W33_INIT_BAL: int = 8_000  # $80.00 virtual starting balance
_W33_DB_PATH: str = os.path.join(os.path.dirname(__file__), "..", "data", "w33_tournament.db")

# Auto-promotion tracking
_w33_profitable_since: dict = {}   # bot_id -> epoch_ts when it first went profitable this streak
_w33_last_promote_check: float = 0.0  # epoch_ts of last auto-promotion check
_w33_last_promoted_bot: str = ""      # last bot promoted to live

def _w33_write_trade_db(b, t, s, ep, xp, c, p, w, et, xt, ec=None, fp=None):
    """Persist a settled W33 shadow trade to data/w33_tournament.db."""
    _wxx_write_trade_db2(_W33_DB_PATH, b, t, s, ep, xp, c, p, w, et, xt, ec, fp)

def _w33_build_bots() -> dict:
    """Build 200 W33 shadow bots — the definitive focused tournament.

    Legacy waves W7-W32 are disabled (empty dicts). This wave supersedes all prior
    experiments with 200 precisely designed configurations informed by full DB history.

    GROUP A — Best performer extrapolations (40 bots):
      SW73-SW90 weight range (price-heavy, no market term like W12 J-group winners),
      E11-E15 edge sweep, K25-K35, DZ0 and DZ55 dead zones.
      Insight: W12 J2 (P85/I10/F05) is the historical leader at +131¢/trade avg.

    GROUP B — Price weight fine-grid (40 bots):
      P55-P85 in steps of ~3%, market/imbalance/funding proportional to remainder.
      E12, K30, DZ0. Tests the exact optimal price weight across 40 points.

    GROUP C — Edge floor sweep (30 bots):
      Fixed P70 signal (halfway between P90 live and P73 W11 winner), E8-E20 sweep.
      K30, DZ0, time_dz=True. Finds the edge floor sweet spot cleanly.

    GROUP D — Kelly sweep (20 bots):
      Fixed P70/E13/DZ0, K15-K50. Maps Kelly curve exhaustively.

    GROUP E — Dead zone experiments (20 bots):
      Fixed P73/E13/K30, DZ0/DZ55/DZ57/DZ60/DZ63/DZ65. Also tests NO-only variant.

    GROUP F — Coin set experiments (20 bots):
      Same signal (P70/E13/K30/DZ0) but different coin filters.
      Tests: BTC+SOL+DOGE (best 3), BTC+ETH+SOL+DOGE, all-except-HYPE, HYPE-only, all.

    GROUP G — Regime-specific (30 bots):
      Trend-following (high P weight, high edge), mean-reversion (NO-bias, low edge),
      momentum burst (high edge E20+, big Kelly K40), and 4-signal balanced combos.
    """
    # Helper: build config, verify weights sum to 1.0
    def _b33(id, label, wp, wm, wi, wf, edge=10.0, kelly=0.30, dz=0.0,
             time_dz=True, coins=None):
        _s = round(wp + wm + wi + wf, 6)
        assert abs(_s - 1.0) < 0.002, f"W33 {id}: weights sum to {_s}"
        cfg = {
            "id": id, "label": label,
            "wp": round(wp, 4), "wm": round(wm, 4),
            "wi": round(wi, 4), "wf": round(wf, 4),
            "edge": float(edge), "kelly": float(kelly),
            "dz": float(dz), "time_dz": bool(time_dz),
            "coins": coins,
        }
        return cfg

    cfgs = []

    # ── CONTROL (1): exact live formula P90/I07/F03 (no market term) ──────────
    cfgs.append(_b33("w33_ctrl", "W33_CTRL_P90_I07_F03_LIVE",
                     0.90, 0.00, 0.07, 0.03, edge=13.0, kelly=0.30))

    # ── GROUP A: Best performers extrapolated — 40 bots ───────────────────────
