        (0.73, 0.17, 0.07, 0.03, 13.0, 0.30, 0.0),
        (0.73, 0.17, 0.07, 0.03, 13.0, 0.25, 0.0),
        (0.73, 0.17, 0.07, 0.03, 15.0, 0.30, 0.0),
        (0.73, 0.17, 0.07, 0.03, 13.0, 0.30, 0.68),
        (0.90, 0.00, 0.07, 0.03, 12.0, 0.30, 0.0),
