def _save_shadow_state() -> None:
    """Persist all 49 shadow bot states + autotrade flag to data/shadow_state.json."""
    import json as _json_mod
    state: dict = {}
    g = globals()
    for _bid in _SHADOW_BOT_IDS:
        state[_bid] = {
            "balance_cents": g.get(f"_shadow_{_bid}_balance_cents", 8_000),
            "peak_cents":    g.get(f"_shadow_{_bid}_peak_cents",    8_000),
            "trades":        list(g.get(f"_shadow_{_bid}_trades",   [])),
            "positions":     dict(g.get(f"_shadow_{_bid}_positions", {})),
        }
    # Persist trading flags so restarts don't silently disable live trading
    state["_meta"] = {
        "auto_trade_enabled": _cache.get("auto_trade_enabled", False),
        "auto_scan_enabled":  _cache.get("auto_scan_enabled",  False),
        "live_min_edge_cents": _cache.get("live_min_edge_cents", 4),
        "live_kelly_base":    _cache.get("live_kelly_base", 0.30),
    }
    try:
        with open(_SHADOW_STATE_FILE, "w") as _f:
            _json_mod.dump(state, _f)
    except Exception as _e:
        import logging as _log; _log.getLogger(__name__).warning(f"[shadow] save failed: {_e}")

def _load_shadow_state() -> None:
    """Restore shadow bot state from data/shadow_state.json on startup."""
    import json as _json_mod
    if not os.path.exists(_SHADOW_STATE_FILE):
        return
    try:
        with open(_SHADOW_STATE_FILE) as _f:
            state = _json_mod.load(_f)
    except Exception as _e:
        import logging as _log; _log.getLogger(__name__).warning(f"[shadow] load failed: {_e}")
        return
    g = globals()
    loaded = 0
    for _bid, _s in state.items():
        if _bid not in _SHADOW_BOT_IDS:
            continue
        g[f"_shadow_{_bid}_balance_cents"] = int(_s.get("balance_cents", 8_000))
        g[f"_shadow_{_bid}_peak_cents"]    = int(_s.get("peak_cents",    8_000))
        g[f"_shadow_{_bid}_trades"]        = list(_s.get("trades",       []))
        # Restore all positions — let the settlement loop and stale purge (45 min grace)
        # handle them naturally. Aggressively dropping positions on load without refunding
        # the entry cost permanently corrupts balances across restarts.
        # Only skip tombstones (_stopped_out=True) that are far past close_time.
        import time as _tm, datetime as _dt
        _now_utc = _dt.datetime.now(_dt.timezone.utc)
        _raw_pos = _s.get("positions", {})
        _kept_pos = {}
        for _tk, _pos in _raw_pos.items():
            if _pos.get("_stopped_out"):
                # Clean up tombstones that are >10 min past close (market is fully done)
                _ct = _pos.get("close_time", "")
                try:
                    _close_dt = _dt.datetime.fromisoformat(_ct.replace("Z", "+00:00"))
                    if (_now_utc - _close_dt).total_seconds() < 600:
                        _kept_pos[_tk] = _pos
                except Exception:
                    pass  # drop tombstones with unparseable close_time
            else:
                # Keep all live positions — settlement loop will process them
                _kept_pos[_tk] = _pos
        g[f"_shadow_{_bid}_positions"] = _kept_pos
        loaded += 1
    # Restore trading flags
    _meta = state.get("_meta", {})
    if _meta.get("auto_trade_enabled"):
        _cache["auto_trade_enabled"] = True
    if _meta.get("auto_scan_enabled"):
        _cache["auto_scan_enabled"] = True
    if _meta.get("live_min_edge_cents") is not None:
        _cache["live_min_edge_cents"] = _meta["live_min_edge_cents"]
    if _meta.get("live_kelly_base") is not None:
        _cache["live_kelly_base"] = _meta["live_kelly_base"]
    import logging as _log
    _log.getLogger(__name__).info(
        f"[shadow] Restored {loaded} bots from {_SHADOW_STATE_FILE} "
        f"({sum(len(state[b].get('trades', [])) for b in _SHADOW_BOT_IDS if b in state)} total trades) "
        f"autotrade={_meta.get('auto_trade_enabled')} autoscan={_meta.get('auto_scan_enabled')}"
    )

