# ── Gap 1/2: Adaptive signal weights + calibration ──────────────────────────
# Stores raw signal components + outcome for each settled 15M trade.
# Every 50 new outcomes, logistic regression refits the blend weights.
# Starting values match the empirical defaults until enough data accumulates.
_shadow_outcome_log: list[dict] = []          # [{price_sig, consensus, tod, won}, ...]
_shadow_signal_weights: list[float] = [0.62, 0.23, 0.05]  # [price, consensus, tod]
_shadow_weights_fitted: bool = False


def _fit_shadow_signal_weights() -> None:
    """Refit signal blend weights via logistic regression on settled outcomes.

    WHAT IS ADAPTIVE SIGNAL WEIGHTING?
      The 5-signal blend (price 62%, funding 20%, imbalance 8%, consensus 5%,
      tod 5%) starts with manually tuned weights. But are those weights optimal?
      Maybe in THIS market regime, the funding rate signal is actually more
      predictive than the price signal? We don't know until we observe outcomes.

      This function uses LOGISTIC REGRESSION — a machine learning algorithm
      that finds the optimal weights by looking at past outcomes. Specifically:
        - Input: the 5 signal values at the time of each trade entry
        - Output: did that trade WIN or LOSE?
        - The logistic regression finds the weights that would have best
          predicted the outcomes in the training data.

      After every 50 new settled trades, the weights are re-fit.
      The result: signal weights that ADAPT to which signals are actually
      predictive in recent market conditions, rather than being fixed forever.

      What is logistic regression?
        It's the simplest ML classifier — it finds a weighted sum of inputs
        that best separates "wins" from "losses" as a probability. Think of
        it as: "what combination of signal weights makes the final fair_prob
        most accurately predict whether we won?"

      Why wait for 50 settled trades?
        With fewer data points, the fitted weights would be unreliable (high
        variance — any one bad trade could swing the weights dramatically).
        50 trades gives enough statistical power to trust the fit.
    """
    global _shadow_signal_weights, _shadow_weights_fitted
    if len(_shadow_outcome_log) < 50:
        return
    try:
        import numpy as _np
        from sklearn.linear_model import LogisticRegression as _LR
        from sklearn.preprocessing import FunctionTransformer as _FT
        import math as _m2

        def _logit_clip(x):
            return _m2.log(max(0.001, min(0.999, x)) / (1 - max(0.001, min(0.999, x))))

        X = _np.array([
            [_logit_clip(r["price_sig"]),
             _logit_clip(r["consensus"]),
             _logit_clip(r["tod"])]
            for r in _shadow_outcome_log
        ])
        y = _np.array([1 if r["won"] else 0 for r in _shadow_outcome_log])
        # Fit intercept=False so coefficients directly multiply the logit features
        lr = _LR(fit_intercept=False, C=1.0, max_iter=500, solver="lbfgs")
        lr.fit(X, y)
        raw = lr.coef_[0]
        # Keep weights positive and normalize so max = 1 (preserves relative magnitudes)
        raw = [max(0.01, float(w)) for w in raw]
        mx = max(raw)
        if mx > 0:
            _shadow_signal_weights = [w / mx for w in raw]
            _shadow_weights_fitted = True
            import logging as _lg2
            _lg2.getLogger("bot.server").info(
                f"[shadow] Weights fitted (n={len(_shadow_outcome_log)}): "
                f"price={_shadow_signal_weights[0]:.3f} "
                f"consensus={_shadow_signal_weights[1]:.3f} "
                f"tod={_shadow_signal_weights[2]:.3f}"
            )
    except Exception as _wfe:
        import logging as _lg3
        _lg3.getLogger("bot.server").debug(f"[shadow] Weight fitting failed: {_wfe}")


# Throttle dict for expired-position force-checks. Prevents querying Kalshi every
# second — each expired ticker is re-queried at most once per 60 seconds.
_shadow_expiry_checked: dict[str, float] = {}  # ticker -> last-check epoch


def _record_crypto_outcome(ticker: str, entry_hour: int, won: bool) -> None:
    """Record a settled crypto 15m outcome into hourly and coin stats."""
    _hourly_stats[entry_hour % 24]["total"] += 1
    if won:
        _hourly_stats[entry_hour % 24]["wins"] += 1
    for prefix in ("KXBTC15M", "KXETH15M", "KXXRP15M", "KXSOL15M", "KXDOGE15M",
                   "KXBNB15M", "KXHYPE15M", "KXADA15M", "KXAVAX15M",
                   "KXBTCD", "KXETHD", "KXXRPD",
                   "KXBTC-", "KXETH-", "KXXRP-", "KXDOGE-",
                   "KXSOLD", "KXSOLE-", "KXBNBD", "KXBNB-",
                   "KXHYPED", "KXHYPE-", "KXDOGED"):
        if ticker.startswith(prefix):
            _coin_stats[prefix]["total"] += 1
            if won:
                _coin_stats[prefix]["wins"] += 1
            break


_shadow_trades_table_created = False

def _write_shadow_trade_db(bot_id: str, ticker: str, pos: dict, exit_price: int, pnl_cents: int, won: bool, exit_time: str) -> None:
    """Persist a settled shadow trade to the shadow_trades table in bot.db."""
    global _shadow_trades_table_created
    try:
        import sqlite3 as _sq3
        _sdb = _sq3.connect("data/bot.db")
        if not _shadow_trades_table_created:
            _sdb.execute("""CREATE TABLE IF NOT EXISTS shadow_trades (
                id          INTEGER PRIMARY KEY AUTOINCREMENT,
                created_at  TEXT DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
                bot_id      TEXT NOT NULL,
                ticker      TEXT,
                side        TEXT,
                entry_price INTEGER,
                exit_price  INTEGER,
                contracts   INTEGER,
                pnl_cents   INTEGER,
                won         INTEGER,
                fair_prob   REAL,
                market_prob REAL,
                entry_time  TEXT,
                exit_time   TEXT
            )""")
            _sdb.commit()
            _shadow_trades_table_created = True
        _sdb.execute(
            """INSERT INTO shadow_trades
               (bot_id,ticker,side,entry_price,exit_price,contracts,pnl_cents,won,fair_prob,market_prob,entry_time,exit_time)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)""",
            (bot_id, ticker, pos.get("side",""), pos.get("entry_price", 0), exit_price,
             pos.get("count", 1), pnl_cents, int(won),
             pos.get("fair_prob", 0.0), pos.get("market_prob", 0.0),
             pos.get("entry_time", ""), exit_time),
        )
        _sdb.commit()
        _sdb.close()
    except Exception:
        pass


_scan_signals_table_created = False

def _write_scan_signal(
    ticker: str,
    side: str | None,
    fair_prob: float,
    market_prob: float,
    edge_cents: float,
    price: int,
    skip_reason: str | None,
    secs_remaining: int,
    kelly: float | None = None,
    bet_cents: int | None = None,
) -> None:
    """Persist every scan signal (skips and placements) to scan_signals table."""
    global _scan_signals_table_created
    try:
        import sqlite3 as _sq3, time as _tm, datetime as _dt
        _sdb = _sq3.connect("data/bot.db")
        if not _scan_signals_table_created:
            _sdb.execute("""CREATE TABLE IF NOT EXISTS scan_signals (
                id            INTEGER PRIMARY KEY AUTOINCREMENT,
                ts            INTEGER NOT NULL,
                iso           TEXT NOT NULL,
                ticker        TEXT,
                side          TEXT,
                fair_prob     REAL,
                market_prob   REAL,
                edge_cents    REAL,
                price         INTEGER,
                skip_reason   TEXT,
                secs_remaining INTEGER,
                kelly         REAL,
                bet_cents     INTEGER
            )""")
            _scan_signals_table_created = True
        _sdb.execute(
            "INSERT INTO scan_signals "
            "(ts,iso,ticker,side,fair_prob,market_prob,edge_cents,price,skip_reason,secs_remaining,kelly,bet_cents) "
            "VALUES (?,?,?,?,?,?,?,?,?,?,?,?)",
            (
                int(_tm.time()),
                _dt.datetime.now(_dt.timezone.utc).isoformat(),
                ticker, side,
                round(fair_prob, 6), round(market_prob, 6),
                round(edge_cents, 4), price,
                skip_reason, int(secs_remaining),
                round(kelly, 6) if kelly is not None else None,
                bet_cents,
            ),
        )
        _sdb.commit()
        _sdb.close()
    except Exception:
        pass


def _hourly_entry_params(hour: int) -> tuple[float, float, float]:
    """Return (entry_threshold, exit_threshold, kelly_fraction) tuned for this UTC hour.

    With < 15 settled trades in a given hour we don't have enough data to move
    away from safe defaults. Once we have data, tighten the threshold in poor
    hours and let it relax in good hours. Kelly fraction scales similarly so
    position sizes naturally shrink in historically bad hours.

    Returns:
        entry_threshold: minimum combined_prob to bet YES (NO uses 1 - this)
        exit_threshold:  maximum combined_prob to bet NO
        kelly_fraction:  fraction of full Kelly to use for sizing

    WHY tune parameters by hour?
      Prediction markets have intraday rhythms. The US equity open (9:30am ET =
      13:30 UTC), the London close (4:30pm = 16:30 UTC), and the late-night Asian
      session all have different volatility profiles and information environments.
      Some hours historically show higher win rates for our specific signals.
      Rather than manually figuring out which hours are good, the bot learns from
      live results: if 14:00 UTC has 60%+ win rate after 15+ trades, it rewards
      that hour with a slightly larger Kelly fraction. If an hour is consistently
      below 50%, it tightens the threshold — effectively telling the bot "only
      take the highest-confidence trades in this hour, and bet smaller."

      IMPORTANT: This NEVER stops trading in bad hours. It only adjusts sizing
      and selectivity. The bot keeps learning and can reverse its judgment if a
      previously bad hour improves.
    """
    h = _hourly_stats.get(hour, {"wins": 0, "total": 0})
    if h["total"] < 15:
        # Insufficient data — use conservative defaults
        return 0.65, 0.35, 0.25

    win_rate = h["wins"] / h["total"]

    if win_rate >= 0.60:
        # Good hour — confident, normal thresholds, slightly larger Kelly
        return 0.65, 0.35, 0.28
    elif win_rate >= 0.50:
        # Average hour — normal
        return 0.65, 0.35, 0.25
    elif win_rate >= 0.42:
        # Below average — tighten threshold slightly, shrink size
        return 0.67, 0.33, 0.20
    else:
        # Poor hour — require stronger signal, much smaller size
        # Still trades — just more selective and smaller
        return 0.68, 0.32, 0.15

def _audit_log(event_type: str, details: str, user_action: bool = False):
    """Append an entry to the system audit log (max 500 entries)."""
    entry = {
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "event_type": event_type,
        "details": details,
        "user_action": user_action,
    }
    _cache.setdefault("audit_log", []).append(entry)
    if len(_cache["audit_log"]) > 500:
        _cache["audit_log"] = _cache["audit_log"][-500:]


async def _load_performance_from_kalshi() -> int:
    """Populate PerformanceTracker from Kalshi executed order history.

    Called at startup and on POST /api/performance/reload. Fetches up to
    200 executed orders, cross-references settled market results, and
    records each completed trade into the PerformanceTracker so the
    performance tab shows real historical data instead of being empty.

    Returns the number of trades successfully loaded.

    WHY DO WE NEED TO "LOAD" PERFORMANCE FROM KALSHI?
      The PerformanceTracker lives in memory. Every time the server restarts,
      it starts empty — no trade history. But Kalshi stores our complete order
      history in their database.

      At startup, this function:
        1. Fetches our last 200 executed orders from Kalshi
        2. Groups them by market ticker: most recent BUY = entry, most recent
           SELL = exit (if we sold early). If no SELL exists, we check if the
           market is settled and use the settlement result as exit.
        3. Computes P&L for each completed trade and loads it into the tracker.

      Result: the Performance tab shows accurate historical P&L from the moment
      the server starts, without needing to wait for new trades to complete.

      "Cross-reference settled market results" means: for trades we held to
      expiry (no SELL order), we look up the market's final YES/NO result and
      treat it as: exit_price = 100¢ (won) or 0¢ (lost).
    """
    if not kalshi or not performance:
        return 0
    try:
        orders = await asyncio.to_thread(kalshi.get_executed_orders, 200)
        if not orders:
            logger.info("[performance] No executed orders found in Kalshi history")
            return 0

        # Group by ticker: most recent BUY is the entry, most recent SELL is the exit
        entries: dict[str, dict] = {}
        exits_map: dict[str, dict] = {}
        for o in orders:
            ticker = o.get("ticker", "")
            action = (o.get("action") or "").lower()
            side = (o.get("side") or "yes").lower()
            fill_count = o.get("fill_count", 0) or 0
            yes_price = o.get("yes_price", 0) or 0
            no_price = o.get("no_price", 0) or 0
            created = o.get("created_time", "") or ""
            if not ticker or not fill_count:
                continue
            price_cents = yes_price if side == "yes" else no_price
            if action == "buy" and ticker not in entries:
                entries[ticker] = {
                    "side": side,
                    "price": price_cents / 100,
                    "count": fill_count,
                    "time": created,
                }
            elif action == "sell" and ticker not in exits_map:
                exits_map[ticker] = {
                    "price": price_cents / 100,
                    "count": fill_count,
                    "time": created,
                }

        # Avoid re-recording tickers already in the tracker OR in the DB.
        # Bug fix: after a restart, performance.trades is empty so the in-memory
        # check misses all previously-settled records. We also query the DB so
        # Kalshi-sync records don't duplicate records already written at settlement time.
        already_recorded = {t.ticker for t in performance.trades}
        if db and hasattr(db, '_conn') and db._conn:
            try:
                _db_tickers = {row[0] for row in db._conn.execute(
                    "SELECT DISTINCT ticker FROM trades WHERE mode='live'"
                ).fetchall()}
                already_recorded = already_recorded | _db_tickers
            except Exception:
                pass
        loaded = 0

        for ticker, entry in entries.items():
            if ticker in already_recorded:
                continue
            exit_info = exits_map.get(ticker)
            if exit_info:
                exit_price = exit_info["price"]
                exit_time = exit_info["time"]
            else:
                # Check market settlement result
                try:
                    mkt = await asyncio.to_thread(kalshi.get_market, ticker)
                    if not mkt or mkt.result not in ("yes", "no"):
                        continue  # Still open or result unknown
                    won = (mkt.result == entry["side"])
                    exit_price = 1.0 if won else 0.0
                    exit_time = mkt.close_time or ""
                except Exception:
                    continue

            # Determine category from ticker prefix
            cat = ""
            for pfx in ("KXBTC15M", "KXETH15M", "KXXRP15M", "KXSOL15M",
                        "KXDOGE15M", "KXBNB15M", "KXHYPE15M", "KXADA15M", "KXAVAX15M"):
                if ticker.startswith(pfx):
                    cat = "Crypto"
                    break

            performance.record_trade(
                ticker=ticker,
                side=entry["side"],
                entry_price=entry["price"],
                exit_price=exit_price,
                contracts=entry["count"],
                entry_time=entry["time"],
                exit_time=exit_time,
                category=cat,
            )
            already_recorded.add(ticker)
            loaded += 1

        logger.info(f"[performance] Loaded {loaded} trades from Kalshi history ({len(entries)} entries found)")
        return loaded
    except Exception as e:
        logger.warning(f"[performance] Could not load Kalshi trade history: {e}")
        return 0


def _safe_int_env(key: str, default: int) -> int:
    try:
        return int(os.getenv(key, str(default)))
    except (ValueError, TypeError):
        return default


def _safe_float_env(key: str, default: float) -> float:
    try:
        return float(os.getenv(key, str(default)))
    except (ValueError, TypeError):
        return default


# Alert thresholds from env vars (Task 37)
ALERT_MAX_DAILY_LOSS = _safe_int_env("ALERT_MAX_DAILY_LOSS_CENTS", 7500)  # $75 daily loss = pause

# ── Proportional scaling: limits grow/shrink with live bankroll ──
# BET_PCT_OF_BALANCE: per-trade hard ceiling as % of balance (gates check_signal rejection).
# DAILY_LOSS_PCT_OF_BALANCE: daily loss halt as % of balance.
