_live_signal_wf: float = 0.03        # funding weight in live fair_prob formula

# ── RF Live Bot — parallel 20% capital bot targeting 99.9% win rate tier ────
# Enabled independently from the quant crypto bot. Uses the RF/GB ensemble model
# to bet only when model confidence >= 0.70, the tier with 99.9% historical win rate
# (1,186 samples in calibration). Budget = 20% of live balance.
_rf_live_bot_enabled: bool = False          # master on/off toggle
_shadow_tick_running: bool = False          # guard: one shadow task at a time
_shadow_scan_cycle: int = 0                 # counts live scan cycles; shadow only runs every 10th
# v9_range_ctrl — shadow tracker that mirrors every live range bracket entry
# Records to shadow_trades so range WR/PnL can be compared against 15m bots
_shadow_range_positions: dict = {}          # ticker → entry data; cleared on settlement

# Wave 9 dynamic-edge shadow bots — each bot uses a different gate function of secs_remaining.
# Gate = required edge in cents to enter. All bots use directional logic (fair_prob > 0.5 → side).
# v9_dyn_lin:   gate decreases linearly from 13¢ at window open to 4¢ at 30s
# v9_dyn_exp:   gate decreases quadratically (slower drop early, sharper near close)
# v9_dyn_step3: 3-step: 13¢ (>5min), 8¢ (5min–90s), 4¢ (<90s)
# v9_dyn_live:  mirrors current live 2-step logic (15¢ / 4¢ at 90s)
_SHADOW_DYN_BOTS: dict = {
    "v9_dyn_lin":   lambda s: max(4.0, 4.0 + 9.0 * max(0.0, s - 30.0) / 660.0),
    "v9_dyn_exp":   lambda s: max(4.0, 4.0 + 9.0 * (max(0.0, s - 30.0) / 660.0) ** 2),
    "v9_dyn_step3": lambda s: 13.0 if s > 300.0 else (8.0 if s > 90.0 else 4.0),
    "v9_dyn_live":  lambda s: 4.0 if s <= 90.0 else 12.0,
}
_shadow_dyn_positions: dict = {bot_id: {} for bot_id in ["v9_dyn_lin", "v9_dyn_exp", "v9_dyn_step3", "v9_dyn_live"]}

_paper_scan_cycle: int = 0                  # paper trader scan throttle — runs every 7th cycle (~1s)
_rf_live_min_confidence: float = 0.70       # ≥0.70 → 99.9% historical win rate
_rf_live_budget_pct: float = 0.20           # fraction of live balance reserved for RF bot
_rf_bot_session_trades: int = 0             # trades placed this server session
_rf_bot_session_wins: int = 0              # wins recorded this session
_rf_bot_session_pnl_cents: int = 0         # net P&L this session
ALERT_CONSECUTIVE_LOSSES = _safe_int_env("ALERT_CONSECUTIVE_LOSSES", 8)  # 8 consecutive losses = pause
ALERT_DRAWDOWN_PCT = _safe_float_env("ALERT_DRAWDOWN_PCT", 0.25)  # 25% drawdown = pause

# ── Platform risk controls ──
# MAX_PLATFORM_EXPOSURE_CENTS: hard ceiling on total open-position value at any moment.
# Caps how much is at risk if Kalshi freezes, fails to settle, or goes insolvent.
# Sits on top of the 40% percentage budget — whichever is smaller wins.
# Default $10,000. Adjust via MAX_PLATFORM_EXPOSURE_CENTS in .env.
# At 40% budget: binding above a $25,000 balance. Below that, the 40% cap is the real constraint.
_MAX_PLATFORM_EXPOSURE = _safe_int_env("MAX_PLATFORM_EXPOSURE_CENTS", 1_000_000)

# WITHDRAWAL_ALERT_CENTS: when Kalshi cash balance exceeds this, log a prominent
# warning to withdraw the excess — limits idle funds at counterparty risk.
