                    # ── Stop-loss bots KE and LE: exit only when position looks near-terminal ──
                    # Only cut losses when the bid has collapsed to <= stop_threshold cents,
                    # implying the market has priced this as a near-certain loser.
                    # Winners are always held to settlement — never cut short.
                    # KE: stop at <=15c (position down ~75%+ from typical 60c entry)
                    # LE: stop at <=10c (tighter stop, exits only near-certain losers)
                    for (_xe_pos, _xe_trades, _xe_bal_attr, _xe_threshold) in [
                        (_shadow_ke_positions, _shadow_ke_trades, "_shadow_ke_balance_cents", 15),  # stop if bid <= 15c
                        (_shadow_le_positions, _shadow_le_trades, "_shadow_le_balance_cents", 10),  # stop if bid <= 10c
                    ]:
                        for _xetk in list(_xe_pos.keys()):
                            _xesp  = _xe_pos[_xetk]
                            if _xesp.get("_stopped_out"):
                                _xemkt_check = shadow_mkt_lookup.get(_xetk)
                                if not _xemkt_check or _xemkt_check.status not in ("open", "active"):
                                    del _xe_pos[_xetk]
                                continue
                            _xemkt = shadow_mkt_lookup.get(_xetk)
                            if not _xemkt:
                                try:
                                    _xegone = await asyncio.to_thread(kalshi.get_market, _xetk)
                                    if _xegone and _xegone.result in ("yes", "no"):
                                        _xewon = (_xegone.result == _xesp.get("side", "yes"))
                                        _xeval = 100 if _xewon else 0
                                        _xe_entry = _xesp.get("entry_price", 50)
                                        _xepnl = int((_xeval - _xe_entry) * _xesp["count"])
                                        globals()[_xe_bal_attr] += int(_xeval * _xesp["count"])
                                        _xe_trades.append({
                                            "time": now, "action": "settled",
                                            "ticker": _xetk, "side": _xesp.get("side", "yes"),
                                            "entry_price": _xe_entry, "exit_price": _xeval,
                                            "pnl_cents": _xepnl,
                                            "reason": f"settled_{_xegone.result}", "won": _xewon,
                                        })
                                        del _xe_pos[_xetk]
                                except Exception:
                                    pass
                                continue
                            # Stop-loss check: exit only if bid has collapsed to near zero
                            _xe_side = _xesp.get("side", "yes")
                            _xe_entry = _xesp.get("entry_price", 50)
                            if _xe_side == "yes":
                                _xe_cur_bid = _xemkt.yes_bid or 0
                            else:
                                _xe_cur_bid = _xemkt.no_bid or 0
                            if 0 < _xe_cur_bid <= _xe_threshold:
                                # Stop-loss: salvage remaining value before it hits zero
                                _xe_proceeds = int(_xe_cur_bid * _xesp["count"])
                                globals()[_xe_bal_attr] += _xe_proceeds
                                _xe_pnl = _xe_proceeds - int(_xe_entry * _xesp["count"])
                                _xe_trades.append({
                                    "time": now, "action": "stop_loss",
                                    "ticker": _xetk, "side": _xe_side,
                                    "entry_price": _xe_entry,
                                    "exit_price": _xe_cur_bid,
                                    "pnl_cents": _xe_pnl,
                                    "reason": f"stop_loss_bid<={_xe_threshold}c",
                                    "won": False,
                                })
                                # ════════════════════════════════════════════════
                                # TOMBSTONE PATTERN — prevents re-entry loops
                                # ════════════════════════════════════════════════
                                # Tombstone: keep ticker to block re-entry this candle
                                #
                                # WHAT IS A "TOMBSTONE" IN THIS CONTEXT?
                                #   When a stop-loss fires, we exit the position but we
                                #   DON'T immediately delete it from the positions dict.
                                #   Instead, we replace it with a "tombstone" — a
                                #   minimal dict with _stopped_out=True.
                                #
                                #   WHY NOT JUST DELETE IT?
                                #   Here's the bug it prevents ("re-entry loop"):
                                #
                                #   1. Bot enters BTC YES at 65¢
                                #   2. Price drops, stop-loss fires at 30¢ — we exit
                                #   3. We DELETE the position from the dict
                                #   4. On the VERY NEXT scan (0.3 seconds later), the
                                #      model still says "enter YES on BTC" (because the
                                #      market hasn't moved much in 0.3s)
                                #   5. Bot ENTERS AGAIN at 30¢
                                #   6. Stop-loss fires immediately again at 25¢ — loops
                                #
                                #   The tombstone prevents step 4-6: the ticker is still
                                #   in the positions dict (marked as stopped), so the
                                #   "already holding this ticker" check blocks re-entry.
                                #
                                #   The tombstone stays until the MARKET CLOSES. When the
                                #   market settles or expires, the tombstone is cleaned up
                                #   (see "Clean up stop-loss tombstones" below). On the
                                #   NEXT different market (same coin, next 15-minute window),
                                #   there's no tombstone and normal entry logic applies.
                                #
                                #   This is essentially a "once per candle" rule:
                                #   if we stop out of a position, we don't re-enter
                                #   the SAME market. We wait for the next one.
                                # ════════════════════════════════════════════════
                                _xe_pos[_xetk] = {"_stopped_out": True, "close_time": _xesp.get("close_time")}
                                continue
                            # Normal settlement check
                            if _xemkt.status == "settled" and _xemkt.result in ("yes", "no"):
                                _xewon = (_xemkt.result == _xe_side)
                                _xeval = 100 if _xewon else 0
                                _xepnl = int((_xeval - _xe_entry) * _xesp["count"])
                                globals()[_xe_bal_attr] += int(_xeval * _xesp["count"])
                                _xe_trades.append({
                                    "time": now, "action": "settled",
                                    "ticker": _xetk, "side": _xe_side,
                                    "entry_price": _xe_entry, "exit_price": _xeval,
                                    "pnl_cents": _xepnl,
                                    "reason": f"settled_{_xemkt.result}", "won": _xewon,
                                })
                                del _xe_pos[_xetk]

                    # ── Wave 6: shared settlement loop (all 49 bots) ────────────────────────
                    for (_sz_pos, _sz_trades, _sz_bal_attr) in [
                        # Controls
                        (_shadow_r_positions,      _shadow_r_trades,      "_shadow_r_balance_cents"),
                        (_shadow_sw2_positions,    _shadow_sw2_trades,    "_shadow_sw2_balance_cents"),
                        (_shadow_m_positions,      _shadow_m_trades,      "_shadow_m_balance_cents"),
                        (_shadow_lw3_positions,    _shadow_lw3_trades,    "_shadow_lw3_balance_cents"),
                        (_shadow_n_positions,      _shadow_n_trades,      "_shadow_n_balance_cents"),
                        # Group 1: Kelly scale
                        (_shadow_k35_positions,    _shadow_k35_trades,    "_shadow_k35_balance_cents"),
                        (_shadow_k40_positions,    _shadow_k40_trades,    "_shadow_k40_balance_cents"),
                        (_shadow_k45_positions,    _shadow_k45_trades,    "_shadow_k45_balance_cents"),
                        (_shadow_k50_positions,    _shadow_k50_trades,    "_shadow_k50_balance_cents"),
                        # Group 2: WP gate
                        (_shadow_vp52_positions,   _shadow_vp52_trades,   "_shadow_vp52_balance_cents"),
                        (_shadow_vp55_positions,   _shadow_vp55_trades,   "_shadow_vp55_balance_cents"),
                        (_shadow_vp57_positions,   _shadow_vp57_trades,   "_shadow_vp57_balance_cents"),
                        (_shadow_vp60_positions,   _shadow_vp60_trades,   "_shadow_vp60_balance_cents"),
                        (_shadow_vp62_positions,   _shadow_vp62_trades,   "_shadow_vp62_balance_cents"),
                        (_shadow_vp65_positions,   _shadow_vp65_trades,   "_shadow_vp65_balance_cents"),
                        # Group 3: Edge floor
                        (_shadow_g5_positions,     _shadow_g5_trades,     "_shadow_g5_balance_cents"),
                        (_shadow_g6_positions,     _shadow_g6_trades,     "_shadow_g6_balance_cents"),
                        (_shadow_g7_positions,     _shadow_g7_trades,     "_shadow_g7_balance_cents"),
                        (_shadow_g8_positions,     _shadow_g8_trades,     "_shadow_g8_balance_cents"),
                        (_shadow_g10_positions,    _shadow_g10_trades,    "_shadow_g10_balance_cents"),
                        # Group 4: Coin filter
                        (_shadow_cb_positions,     _shadow_cb_trades,     "_shadow_cb_balance_cents"),
                        (_shadow_ce_positions,     _shadow_ce_trades,     "_shadow_ce_balance_cents"),
                        (_shadow_cx_positions,     _shadow_cx_trades,     "_shadow_cx_balance_cents"),
                        (_shadow_cbe_positions,    _shadow_cbe_trades,    "_shadow_cbe_balance_cents"),
                        (_shadow_cbx_positions,    _shadow_cbx_trades,    "_shadow_cbx_balance_cents"),
                        # Group 5: Spread filter
                        (_shadow_sp1_positions,    _shadow_sp1_trades,    "_shadow_sp1_balance_cents"),
                        (_shadow_sp2_positions,    _shadow_sp2_trades,    "_shadow_sp2_balance_cents"),
                        (_shadow_sp3_positions,    _shadow_sp3_trades,    "_shadow_sp3_balance_cents"),
                        (_shadow_sp4_positions,    _shadow_sp4_trades,    "_shadow_sp4_balance_cents"),
                        # Group 6: Timing
                        (_shadow_tm6_positions,    _shadow_tm6_trades,    "_shadow_tm6_balance_cents"),
                        (_shadow_tm8_positions,    _shadow_tm8_trades,    "_shadow_tm8_balance_cents"),
                        (_shadow_tm10_positions,   _shadow_tm10_trades,   "_shadow_tm10_balance_cents"),
                        # Group 7: Signal weights
                        (_shadow_wg85_positions,   _shadow_wg85_trades,   "_shadow_wg85_balance_cents"),
                        (_shadow_wg88_positions,   _shadow_wg88_trades,   "_shadow_wg88_balance_cents"),
                        (_shadow_wg92_positions,   _shadow_wg92_trades,   "_shadow_wg92_balance_cents"),
                        (_shadow_wg95_positions,   _shadow_wg95_trades,   "_shadow_wg95_balance_cents"),
                        (_shadow_wg100_positions,  _shadow_wg100_trades,  "_shadow_wg100_balance_cents"),
                        # Group 8: Edge x Kelly
                        (_shadow_ek525_positions,  _shadow_ek525_trades,  "_shadow_ek525_balance_cents"),
                        (_shadow_ek535_positions,  _shadow_ek535_trades,  "_shadow_ek535_balance_cents"),
                        (_shadow_ek635_positions,  _shadow_ek635_trades,  "_shadow_ek635_balance_cents"),
                        (_shadow_ek725_positions,  _shadow_ek725_trades,  "_shadow_ek725_balance_cents"),
                        (_shadow_ek825_positions,  _shadow_ek825_trades,  "_shadow_ek825_balance_cents"),
                        # Group 9: WP + edge combined
                        (_shadow_pe5560_positions, _shadow_pe5560_trades, "_shadow_pe5560_balance_cents"),
                        (_shadow_pe5660_positions, _shadow_pe5660_trades, "_shadow_pe5660_balance_cents"),
                        (_shadow_pe6050_positions, _shadow_pe6050_trades, "_shadow_pe6050_balance_cents"),
                        (_shadow_pe6525_positions, _shadow_pe6525_trades, "_shadow_pe6525_balance_cents"),
                        # Group 10: Consensus alignment
                        (_shadow_xc55_positions,   _shadow_xc55_trades,   "_shadow_xc55_balance_cents"),
                        (_shadow_xc60_positions,   _shadow_xc60_trades,   "_shadow_xc60_balance_cents"),
                        (_shadow_xco_positions,    _shadow_xco_trades,    "_shadow_xco_balance_cents"),
                    ]:
                        for _sztk in list(_sz_pos.keys()):
                            _szsp  = _sz_pos[_sztk]
                            # Clean up stop-loss tombstones when market has closed/settled
                            if _szsp.get("_stopped_out"):
                                _szmkt_check = shadow_mkt_lookup.get(_sztk)
                                if not _szmkt_check or _szmkt_check.status not in ("open", "active"):
                                    del _sz_pos[_sztk]
                                continue
                            _szmkt = shadow_mkt_lookup.get(_sztk)
                            if not _szmkt:
                                try:
                                    _szgone = await asyncio.to_thread(kalshi.get_market, _sztk)
                                    if _szgone and _szgone.result in ("yes", "no"):
                                        _szwon = (_szgone.result == _szsp["side"])
                                        _szval = 100 if _szwon else 0
                                        if _szsp["side"] == "yes":
                                            _szpnl = int((_szval - _szsp["entry_price"]) * _szsp["count"])
                                            globals()[_sz_bal_attr] += int(_szval * _szsp["count"])
                                        else:
                                            _szpnl = int((_szval - _szsp["entry_price"]) * _szsp["count"])
                                            globals()[_sz_bal_attr] += int(_szval * _szsp["count"])
                                        _sz_trades.append({
                                            "time": now, "action": "settled",
                                            "ticker": _sztk, "side": _szsp["side"],
                                            "entry_price": _szsp["entry_price"],
                                            "exit_price": _szval, "pnl_cents": _szpnl,
                                            "reason": f"settled_{_szgone.result}", "won": _szwon,
                                        })
                                        _sz_bot_id = _sz_bal_attr.replace("_shadow_", "").replace("_balance_cents", "")
                                        _write_shadow_trade_db(_sz_bot_id, _sztk, _szsp, _szval, _szpnl, _szwon, now)
                                        del _sz_pos[_sztk]
                                        # Gap 1/2: Record outcome for adaptive weight fitting
                                        if "signal_components" in _szsp and "15M" in _sztk:
                                            _shadow_outcome_log.append({**_szsp["signal_components"], "won": _szwon})
                                            if len(_shadow_outcome_log) % 50 == 0:
                                                _fit_shadow_signal_weights()
                                except Exception:
                                    pass
                                continue
                            if _szmkt.status == "settled" and _szmkt.result in ("yes", "no"):
                                _szwon = (_szmkt.result == _szsp["side"])
                                _szval = 100 if _szwon else 0
                                if _szsp["side"] == "yes":
                                    _szpnl = int((_szval - _szsp["entry_price"]) * _szsp["count"])
                                    globals()[_sz_bal_attr] += int(_szval * _szsp["count"])
                                else:
                                    _szpnl = int((_szval - _szsp["entry_price"]) * _szsp["count"])
                                    globals()[_sz_bal_attr] += int(_szval * _szsp["count"])
                                _sz_trades.append({
                                    "time": now, "action": "settled",
                                    "ticker": _sztk, "side": _szsp["side"],
                                    "entry_price": _szsp["entry_price"],
                                    "exit_price": _szval, "pnl_cents": _szpnl,
                                    "reason": f"settled_{_szmkt.result}", "won": _szwon,
                                })
                                _sz_bot_id = _sz_bal_attr.replace("_shadow_", "").replace("_balance_cents", "")
                                _write_shadow_trade_db(_sz_bot_id, _sztk, _szsp, _szval, _szpnl, _szwon, now)
                                del _sz_pos[_sztk]
                                # Gap 1/2: Record outcome for adaptive weight fitting
                                if "signal_components" in _szsp and "15M" in _sztk:
                                    _shadow_outcome_log.append({**_szsp["signal_components"], "won": _szwon})
                                    if len(_shadow_outcome_log) % 50 == 0:
                                        _fit_shadow_signal_weights()
                            # Gap 4/5: Real-time probability update + emergency stop-loss
                            # Only exit early in truly hopeless situations: last 90 seconds
                            # AND win probability below 5%. We enter with a positive edge,
                            # so we let trades settle naturally. Stops only fire when outcome
                            # is essentially guaranteed against us with seconds remaining.
                            elif "15M" in _sztk and _szmkt.status in ("open", "active"):
                                _sz_yes_mid = ((_szmkt.yes_bid or 0) + (_szmkt.yes_ask or 100)) / 2
                                _sz_cur_win = (_sz_yes_mid / 100 if _szsp["side"] == "yes"
                                              else (100 - _sz_yes_mid) / 100)
                                _sz_secs_rem = None
                                try:
                                    import datetime as _dt2
                                    _sz_ct = _dt2.datetime.fromisoformat(
                                        str(_szsp.get("close_time", "")).replace("Z", "+00:00"))
                                    _sz_secs_rem = (_sz_ct - _dt2.datetime.now(_dt2.timezone.utc)).total_seconds()
                                except Exception:
                                    pass
                                if (_sz_secs_rem is not None and _sz_secs_rem < 90
                                        and _sz_cur_win < 0.05):
                                    _sz_exit = int(_sz_yes_mid) if _szsp["side"] == "yes" else int(100 - _sz_yes_mid)
                                    _szpnl = int((_sz_exit - _szsp["entry_price"]) * _szsp["count"])
                                    globals()[_sz_bal_attr] += int(_sz_exit * _szsp["count"])
                                    _sz_trades.append({
                                        "time": now, "action": "stop_exit",
                                        "ticker": _sztk, "side": _szsp["side"],
                                        "entry_price": _szsp["entry_price"],
                                        "exit_price": _sz_exit, "pnl_cents": _szpnl,
                                        "reason": f"stop_wp{_sz_cur_win:.2f}_t{int(_sz_secs_rem)}s",
                                        "won": False,
                                    })
                                    # Tombstone: keep ticker in positions to block re-entry this candle
                                    _sz_pos[_sztk] = {"_stopped_out": True, "close_time": _szsp.get("close_time")}
                                    # Record as loss for weight fitting
                                    if "signal_components" in _szsp:
                                        _shadow_outcome_log.append({**_szsp["signal_components"], "won": False})

                    # ── Shadow entry scan ──
                    shadow_markets = []
                    _s_crypto_total = 0
                    _s_filter_status = 0
                    _s_filter_spread = 0
                    _s_filter_mid = 0
                    _s_filter_strike = 0
                    for ev in raw_events:
                        for m in ev.markets:
                            tk = m.ticker or ""
                            if not any(tk.startswith(p) for p in _SHADOW_PREFIXES):
                                continue
                            _s_crypto_total += 1
                            if m.status not in ("open", "active"):
                                _s_filter_status += 1
                                continue
                            # Require both sides quoted — if open on Kalshi it has liquidity
                            if not (m.yes_ask or 0) or not (m.yes_bid or 0):
                                _s_filter_spread += 1
                                continue
                            _s_is_15m = "15M" in tk
                            if not _s_is_15m and (not m.floor_strike or m.floor_strike <= 0):
                                _s_filter_strike += 1
                                continue
                            shadow_markets.append(m)
                    print(
                        f"[shadow] FILTER crypto={_s_crypto_total} "
                        f"bad_status={_s_filter_status} bad_spread={_s_filter_spread} "
                        f"bad_mid={_s_filter_mid} no_strike={_s_filter_strike} "
                        f"eligible={len(shadow_markets)}",
                        flush=True
                    )

                    # Pre-compute directional + per-coin exposure for shadow bot
                    _s_yes_open = sum(1 for sp in _shadow_positions.values() if sp.get("side") == "yes")
                    _s_no_open  = sum(1 for sp in _shadow_positions.values() if sp.get("side") == "no")
                    _s_max_bet = max(5_000, int(_shadow_balance_cents * 0.20))  # 20% of balance, floor $50
                    _S_MAX_DIRECTIONAL = min(20, max(8, int(_shadow_balance_cents * 0.60 / max(1, _s_max_bet))))
                    _shadow_crypto_exposure = sum(
                        sp["entry_price"] * sp["count"] for sp in _shadow_positions.values()
                    )
                    _shadow_crypto_budget = int(_shadow_balance_cents * 0.40)
                    _shadow_available = max(0, _shadow_crypto_budget - _shadow_crypto_exposure)
                    _s_open_per_coin: dict[str, int] = {}
                    for _stk in _shadow_positions:
                        for _spx in _SHADOW_PREFIXES:
                            if _stk.startswith(_spx):
                                _s_open_per_coin[_spx] = _s_open_per_coin.get(_spx, 0) + 1
                                break

                    for m in shadow_markets:
                        if m.ticker in _shadow_positions:
                            continue  # Already have a shadow position
                        if len(_shadow_positions) >= 20:
                            break

                        # Per-coin position limit: max 4 per coin
                        _s_coin_prefix = next((px for px in _SHADOW_PREFIXES if m.ticker.startswith(px)), None)
                        if _s_coin_prefix and _s_open_per_coin.get(_s_coin_prefix, 0) >= 4:
                            continue

                        mid = m.mid_price_yes
                        yes_bid = m.yes_bid or 0
                        no_bid = m.no_bid or 0
                        total_bids = yes_bid + no_bid

                        secs_left = None
                        if m.close_time:
                            try:
                                close_dt = datetime.fromisoformat(m.close_time.replace("Z", "+00:00"))
                                secs_left = (close_dt - scan_start).total_seconds()
                            except Exception:
                                pass
                        if secs_left is not None and secs_left < 90:
                            continue

                        s_secs = secs_left if secs_left is not None else 300.0

                        # ── Half-window observation gate (shadow, daily only) ─────────
                        # Only gates DAILY markets (first seen with >4h remaining).
                        # 15M and hourly trade in real time — no delay.
                        _is_directional = any(m.ticker.startswith(pfx) for pfx in _SHADOW_BRACKET_PFXS)
                        if _is_directional:
                            _s_first = _dir_market_first_seen.get(m.ticker)
                            if _s_first is None:
                                _dir_market_first_seen[m.ticker] = s_secs
                                _s_first = s_secs
                            if _s_first > 14400 and s_secs > _s_first * 0.50:
                                continue  # Daily market still in first-half observation window

                        # ── Fair probability: quant model for all crypto markets ──────
                        # Use the same compute_fair_probability + signal combination
                        # as the live trader (not the ML model) so shadow exactly mirrors live.
                        s_fair_prob = 0.5  # fallback
                        _kx_signal_components: dict = {}   # Gap 1/2: populated for 15M markets

                        # Coin identity — needed by both the 15M and bracket fair_prob paths
                        # and by the funding rate signal below. Define once here.
                        _s_regime_coin = (
                            "bitcoin"     if m.ticker.startswith("KXBTC") else
                            "ethereum"    if m.ticker.startswith("KXETH") else
                            "ripple"      if m.ticker.startswith("KXXRP") else
                            "solana"      if m.ticker.startswith("KXSOL") else
                            "dogecoin"    if m.ticker.startswith("KXDOGE") else
                            "binancecoin" if m.ticker.startswith("KXBNB") else
                            "hyperliquid" if m.ticker.startswith("KXHYPE") else
                            "cardano"     if m.ticker.startswith("KXADA") else
                            "avalanche-2" if m.ticker.startswith("KXAVAX") else
                            "bitcoin"
                        )

                        _is_abovebelow = any(m.ticker.startswith(p) for p in (
                            "KXBTCD", "KXETHD", "KXXRPD",
                            "KXSOLD", "KXBNBD", "KXHYPED", "KXDOGED",
                        ))
                        _is_range = any(m.ticker.startswith(p) for p in (
                            "KXBTC-", "KXETH-", "KXXRP-", "KXDOGE-",
                            "KXSOLE-", "KXBNB-", "KXHYPE-",
                        ))

                        if _is_abovebelow:
                            # Log-normal + Student-t quant model for above/below markets.
                            # Price input: blend BRTI spot (60%) with Binance futures mark (40%).
                            # Futures mark price reflects professional hedgers and arbitrageurs —
                            # smarter money than Kalshi's retail bettors. For longer horizons
                            # it better approximates the expected settlement price.
                            _coin_abv = ("bitcoin"     if m.ticker.startswith("KXBTCD")
                                         else "ethereum"    if m.ticker.startswith("KXETHD")
                                         else "ripple"      if m.ticker.startswith("KXXRPD")
                                         else "solana"      if m.ticker.startswith("KXSOLD")
                                         else "binancecoin" if m.ticker.startswith("KXBNBD")
                                         else "hyperliquid" if m.ticker.startswith("KXHYPED")
                                         else "dogecoin"    if m.ticker.startswith("KXDOGED")
                                         else "bitcoin")
                            _spot_px    = live_prices.get(_coin_abv, 0) if live_prices else 0
                            _fut        = futures_data.get(_coin_abv, {})
                            _mark_px    = _fut.get("mark_price", 0)
                            # Use futures mark if it's reasonable (within 2% of spot — same market)
                            if _mark_px > 0 and _spot_px > 0 and abs(_mark_px - _spot_px) / _spot_px < 0.02:
                                _live_px = 0.60 * _spot_px + 0.40 * _mark_px
                            else:
                                _live_px = _spot_px
                            if _live_px > 0 and m.floor_strike and m.floor_strike > 0:
                                import math as _math
                                from scipy.stats import t as _student_t
                                # Annual vol → σ√T (log-normal)
                                _default_vols = {"bitcoin": 0.55, "ethereum": 0.70, "ripple": 0.85,
                                                 "solana": 1.10, "binancecoin": 0.80, "hyperliquid": 1.30, "dogecoin": 1.20}
                                _ann_vol = realized_vols.get(_coin_abv, _default_vols.get(_coin_abv, 0.65))
                                _days_left = max(s_secs / 86400, 1 / 1440)
                                _vol_horizon = _ann_vol * (_days_left / 365.0) ** 0.5
                                # Log-return: exact log-normal, not linear approx
                                _z = _math.log(_live_px / m.floor_strike) / _vol_horizon if _vol_horizon > 0 else 0
                                # Student-t CDF: fat tails for crypto
                                _df = {"bitcoin": 5, "ethereum": 4.5, "ripple": 4,
                                       "solana": 4, "binancecoin": 4.5, "hyperliquid": 3.5, "dogecoin": 3.5}.get(_coin_abv, 5)
                                s_fair_prob = float(_student_t.cdf(_z, df=_df))
                        elif _is_range:
                            # Hourly range/bracket: P(price stays between floor and cap at settlement)
                            # Uses compute_range_probability (GBM/log-normal, same as live scanner).
                            _rng_spot = live_prices.get(_s_regime_coin, 0) if live_prices else 0
                            _rng_low  = m.floor_strike or 0
                            _rng_high = m.cap_strike   or 0
                            if _rng_spot > 0 and _rng_low > 0 and _rng_high > _rng_low:
                                s_fair_prob = compute_range_probability(
                                    _s_regime_coin, _rng_spot, _rng_low, _rng_high, s_secs
                                )
                        else:
                            # 15M crypto: adaptive signal blend (Gap 1/2)
                            # Uses fitted weights from logistic regression when ≥50 settled
                            # outcomes are available, else falls back to empirical defaults.
                            try:
                                # Blend Binance mark price (40%) with spot (60%) for 15M, same
                                # as bracket model. Kalshi settles against CF Benchmarks (a
                                # composite of major spot exchanges) — Binance mark is closer
                                # to that than any single spot feed. Only blend when mark is
                                # within 2% of spot (avoids futures-basis distortion).
                                _s_blended_prices = dict(live_prices) if live_prices else {}
                                _s_fut_coin = futures_data.get(_s_regime_coin, {}) if futures_data else {}
                                _s_mark_px  = _s_fut_coin.get("mark_price", 0)
                                _s_spot_px  = _s_blended_prices.get(_s_regime_coin, 0)
                                if (_s_mark_px > 0 and _s_spot_px > 0
                                        and abs(_s_mark_px - _s_spot_px) / _s_spot_px < 0.02):
                                    _s_blended_prices[_s_regime_coin] = 0.60 * _s_spot_px + 0.40 * _s_mark_px
                                _s_p_price = compute_fair_probability(
                                    m.ticker, m.floor_strike or 0, s_secs, _s_blended_prices
                                )
                                _s_tod = max(0.01, min(0.99, 0.5 + compute_time_of_day_bias()))
                                # Logit components — stored for real-time updating + fitting
                                _s_logit_price = _cf_logit(_s_p_price)
                                _s_logit_cons  = _cf_logit(mid / 100)
                                _s_logit_tod   = _cf_logit(_s_tod)
                                _sw = _shadow_signal_weights  # [price, consensus, tod]
                                s_fair_prob = _cf_sigmoid(
                                    _sw[0] * _s_logit_price +
                                    _sw[1] * _s_logit_cons +
                                    _sw[2] * _s_logit_tod
                                )
                                s_fair_prob = max(0.01, min(0.99, s_fair_prob))
                                # Store raw signal components for W11/W12 shadow bots
                                # Imbalance: (yes_bid - no_bid) / total_bids → [0.41, 0.59]
                                _s_tb = (yes_bid or 0) + (no_bid or 0)
                                _s_imb = ((yes_bid or 0) - (no_bid or 0)) / max(_s_tb, 1)
                                _s_p_imb = max(0.01, min(0.99, 0.5 + _s_imb * 0.09))
                                # Funding: per-coin contrarian from live_futures (matches live bot exactly)
                                _s_fr_kx = float((futures_data.get(_s_regime_coin) or {}).get("funding_rate", 0) or 0)
                                _s_fr = max(-0.03, min(0.03, -_s_fr_kx * 3.0))  # contrarian sign
                                _s_p_fund = max(0.01, min(0.99, 0.5 + _s_fr * (10.0 / 3.0)))
                                _kx_signal_components = {
                                    "price_sig": round(_s_p_price, 4),
                                    "consensus": round(mid / 100, 4),
                                    "tod":       round(_s_tod, 4),
                                    "imbalance": round(_s_p_imb, 4),
                                    "funding":   round(_s_p_fund, 4),
                                }
                            except Exception as _qe:
                                logger.warning(f"[shadow] quant signal failed for {m.ticker}: {_qe}")

                        # Entry: use same quant signal + per-coin threshold as live trader.
                        # Per-coin floors from _COIN_MIN_PROB (BNB=0.75, HYPE=0.72, else 0.60).
                        # _s_regime_coin already defined above (before _is_abovebelow).
                        S_MIN_FAIR    = _COIN_MIN_PROB.get(_s_regime_coin, 0.60)
                        S_MIN_FAIR_NO = round(1.0 - S_MIN_FAIR, 4)

                        # ── Funding rate contrarian signal (±0.03) ─────────────────────────
                        # Positive funding = longs paying shorts = overbought → bearish bias.
                        # Negative funding = shorts paying longs = oversold → bullish bias.
                        # Contrarian: we fade the crowd. Kalshi 15M markets settle in minutes
                        # so mean-reversion is the dominant short-term dynamic.
                        _s_fr_adj = 0.0
                        if futures_data:
                            _s_fr_raw = float((futures_data.get(_s_regime_coin) or {}).get("funding_rate", 0) or 0)
                            # Typical range: ±0.01% per 8h. Scale: 0.01% → ~0.03 probability adj.
                            _s_fr_adj = max(-0.03, min(0.03, -_s_fr_raw * 3.0))  # contrarian sign
                        s_fair_prob = max(0.01, min(0.99, s_fair_prob + _s_fr_adj))


                        yes_ask = m.yes_ask or 0
                        no_ask  = m.no_ask  or 0

                        s_market_prob = mid / 100
                        s_edge = s_fair_prob - s_market_prob
                        # Only log when edge is potentially interesting (avoids 100+ lines/sec noise)
                        _s_near_threshold = (
                            s_fair_prob >= (S_MIN_FAIR - 0.10) or
                            s_fair_prob <= (S_MIN_FAIR_NO + 0.10)
                        )
                        if _s_near_threshold:
                            print(
                                f"[shadow] SCAN {m.ticker} fair={s_fair_prob:.3f} mkt={s_market_prob:.3f} "
                                f"edge={s_edge:+.3f} T={s_secs/60:.1f}min "
                                f"(need fair>={S_MIN_FAIR}|<={S_MIN_FAIR_NO})",
                                flush=True
                            )

                        # Approach 2: limit at min(ask-1, fair-1) — never pay more than
                        # our model says the contract is worth.
                        # - Crowd underprices (ask < fair): we buy at ask-1 → value buy
                        # - Crowd overprices (ask > fair): we rest at fair-1 in the book,
                        #   waiting for someone to cross down to our price
                        fair_cents = max(1, min(99, int(s_fair_prob * 100)))
                        no_fair_cents = 100 - fair_cents

                        # ── K-O: Smart direction (any pos cent-edge, not just ≥60% fair) ──
                        # Run BEFORE threshold gates so continues don't skip it.
                        # Picks whichever side our model says is underpriced — captures
                        # markets A-J miss (e.g. BTC NO when YES has negative edge).
                        _kx_yes_ce = fair_cents - (yes_ask if yes_ask > 0 else mid)
                        _kx_no_ce  = (100 - fair_cents) - (no_ask if no_ask > 0 else (100 - mid))
                        # No minimum edge floor — Kelly sizes down thin-edge trades naturally.
                        # Live trader's 2¢ default is overridden at deploy time via live_min_edge_cents=0.
                        _kx_side   = "yes" if s_fair_prob > 0.5 else "no"
                        # Use ask price for realistic cost basis (edge gate already used ask).
                        # Mid-price entry over-states P&L by ~½ spread per winning trade.
                        _kx_price  = (max(1, min(98, yes_ask if yes_ask > 0 else mid)) if _kx_side == "yes"
                                      else max(1, min(98, no_ask if no_ask > 0 else 100 - mid)) if _kx_side == "no"
                                      else 0)
                        # Effective entry price: signal price + slippage (simulates live execution lag).
                        # Used for Kelly sizing and cost basis — edge/WP filters still use _kx_price.
                        _kx_eff_price = min(_kx_price + _SHADOW_SLIPPAGE_CENTS, 98) if _kx_price > 0 else 0
                        _kx_ce     = _kx_yes_ce if _kx_side == "yes" else (_kx_no_ce if _kx_side == "no" else -999)

                        # ── Gap 8: Spread-width adjustment ───────────────────────────────
                        # Wide spreads signal market maker uncertainty / adverse selection.
                        # spread=5 → 1.0x, spread=10 → 0.875x, spread=20 → 0.625x, spread≥45 → 0.50x floor
                        _kx_spread_cents = max(0, (yes_ask or 100) - (yes_bid or 0))
                        _kx_spread_adj   = max(0.50, 1.0 - max(0, _kx_spread_cents - 5) / 40.0)

                        # ── Duration-adjusted Kelly ───────────────────────────────────────
                        # Capital tied up in a 1-day market has 96x the opportunity cost vs
                        # a 15-minute market. Scale bet size proportionally so long-duration
                        # bets don't crowd out the fast-cycling 15M opportunities.
                        # 15M (900s)=1.0, 1H=0.50, 4H=0.25, 1D≈0.10, 2D≈0.07
                        _kx_duration_adj = min(1.0, (900.0 / max(s_secs, 900.0)) ** 0.5)

                        # ── Long-duration capital efficiency guard ────────────────────────
                        # Daily/overnight markets (>2h to close) lock capital for hours.
                        # ── Shared helpers for all 39 shadow bots ──────────────────────
                        def _kx_coin_stem(pfx):
                            """Extract coin stem (e.g. 'KXBTC' from 'KXBTC15M' or 'KXBTCD')."""
                            if not pfx:
                                return ""
                            for s in ("KXDOGE","KXHYPE","KXBNB","KXSOL","KXAVAX","KXADA","KXBTC","KXETH","KXXRP"):
                                if pfx.startswith(s):
                                    return s
                            return pfx[:5]

                        def _kx_coin_dir(positions, coin_pfx):
                            """Return majority direction ('yes'/'no') for a coin in positions, or None."""
                            stem = _kx_coin_stem(coin_pfx)
                            if not stem:
                                return None
                            sides = [p.get("side") for tk, p in positions.items() if tk.startswith(stem)]
                            if not sides:
                                return None
                            yc = sides.count("yes")
                            nc = sides.count("no")
                            return "yes" if yc >= nc else "no"

                        # ── Gap 3: Correlated-position Kelly discount ────────────────────────
                        # When we already hold N positions in the same coin+direction, each
                        # additional bet is correlated → true portfolio risk > independent bets.
                        # Discount: 1/√(n+1)  →  1 open=0.71x, 2=0.58x, 3=0.50x, 4=0.45x
                        def _kx_corr_kelly_adj(positions, coin_stem, side):
                            n = sum(1 for tk, p in positions.items()
                                    if tk.startswith(coin_stem) and p.get("side") == side)
                            return 1.0 / ((n + 1) ** 0.5)

                        # ── Gap 6: Volatility-regime Kelly scaling ───────────────────────────
                        # High realized vol → price moves are larger relative to strike →
                        # directional signal is clearer → scale Kelly up (capped at 1.30x).
                        # Low vol → noisy signal → scale down (floored at 0.70x).
                        # √ dampening avoids over-reaction to vol spikes.
                        def _kx_vol_scale(coin_abv, r_vols):
                            _bvols = {"bitcoin": 0.55, "ethereum": 0.70, "ripple": 0.85,
                                      "solana": 1.10, "dogecoin": 1.20, "binancecoin": 0.80,
                                      "hyperliquid": 1.30, "cardano": 0.90, "avalanche-2": 1.00}
                            bl = _bvols.get(coin_abv, 0.65)
                            cur = r_vols.get(coin_abv, bl)
                            return max(0.70, min(1.30, (cur / bl) ** 0.5))

                        def _kx_edge_adj(threshold, wp):
                            """Scale Kelly 0→1 as win_prob rises from threshold to threshold+10%."""
                            return max(0.0, min(1.0, (wp - threshold) / 0.10))

                        def _kx_kelly_cnt(fair_p, pc, bal, kf, max_pct):
                            """Compute the number of contracts to buy for a shadow bot entry.

                            Parameters:
                              fair_p:   our model's probability of winning (e.g., 0.68 = 68%)
                              pc:       the entry price in cents (e.g., 57 = 57 cents per contract)
                              bal:      current virtual balance in cents (e.g., 33250)
                              kf:       Kelly fraction to use (e.g., 0.25 = quarter-Kelly)
                              max_pct:  maximum % of balance allowed in this one bet (e.g., 0.10 = 10%)

                            Returns: number of contracts (integer ≥ 1, or 0 if no positive EV)

                            STEP BY STEP KELLY CALCULATION:
                              _wp = fair_p = 0.68  (68% chance we win)
                              _g  = 100 - pc = 100 - 57 = 43 cents  (profit if YES pays out at 100c)
                              _fee = 0.01 × 57 × 43 / 100 = 0.245 cents  (Kalshi's trading fee)
                              _net = 43 - 0.245 = 42.755 cents  (net profit after fee)
                              _b   = 42.755 / 57 = 0.750  (net odds: win 0.75× your stake)

                            Apply Kelly formula:  f* = (p × b - q) / b
                              where q = 1 - p = 0.32 (probability of losing)
                              _f = (0.68 × 0.750 - 0.32) / 0.750
                                 = (0.510 - 0.320) / 0.750
                                 = 0.190 / 0.750
                                 = 0.2533  (full Kelly says bet 25.33% of bankroll)

                            Apply Kelly fraction (e.g., kf=0.25 = quarter-Kelly):
                              _kelly_bet = 0.2533 × 0.25 × 33250 = 2103 cents = $21.03

                            Apply per-bet cap (max_pct=0.10 = 10% of balance):
                              _bet = min(33250 × 0.10, 2103) = min(3325, 2103) = 2103 cents

                            Convert to contracts:
                              count = 2103 // 57 = 36 contracts  (36 × 57c = $20.52 total cost)

                            If _f ≤ 0: Kelly says don't bet (no positive expected value after fees).
                            If _kelly_bet < 100 cents: bet would be less than $1 — skip (too tiny
                            to be worth the friction of opening/closing the position).
                            """
                            _wp = max(0.001, min(0.999, fair_p))
                            _g  = 100 - pc  # gross gain per contract (cents)
                            # Correct Kalshi fee formula: fee = rate × price × (100-price) / 100
                            # This is probability-weighted — matches kelly_criterion_size() in crypto_feed.py.
                            # Rate = 0.01 (1%) because we place limit orders (maker = 0% fee),
                            # with 1% buffer for rare taker fills — same as live trader (fee_pct=0.01).
                            # Old formula "0.07 * gross" was 2-3x too high, causing under-betting.
                            _fee = 0.01 * pc * _g / 100
                            _net = _g - _fee  # net gain per contract after fee
                            if _net <= 0: return 0
                            _b = _net / max(pc, 1)  # net odds (gain per cent risked)
                            _f = (_wp * _b - (1 - _wp)) / _b  # Kelly fraction (see docstring above)
                            if _f <= 0: return 0  # Negative Kelly = negative EV = don't bet
                            _kelly_bet = int(_f * kf * bal)
                            # Skip if Kelly recommends less than $1.00 — avoids forced minimum over-betting
                            if _kelly_bet < 100: return 0
                            _bet = min(int(bal * max_pct), _kelly_bet)  # respect per-bet cap
                            return max(1, int(_bet // max(pc, 1)))  # convert dollars to contract count

                        def _shadow_pos_type_ok(positions, balance_cents, ticker):
                            """Entry gate: total capital cap + per-coin capital cap.

                            Rules:
                              TOTAL=30%:    stop all entries when 30%+ of free balance is locked
                              PER_COIN=20%: stop coin entries when 20%+ of free balance is in one coin
                              Multiple 15M positions per coin are allowed (matches live bot).

                            Returns True if the bot is ALLOWED to open a new position.
                            """
                            locked_total = sum(pos["entry_price"] * pos["count"] for pos in positions.values()
                                               if not pos.get("_stopped_out"))
                            free_balance = max(1, balance_cents)
                            # TOTAL cap: 30% of free balance (shadow bot — independent of live LIVE_DEPLOY_PCT)
                            if locked_total >= free_balance * _SHADOW_CAP_LOCKED_TOTAL:
                                return False
                            # Per-coin cap: max 20% of free balance locked in any single coin (matches live bot)
                            _coin_stems = ("KXDOGE","KXHYPE","KXBNB","KXSOL","KXAVAX","KXADA","KXBTC","KXETH","KXXRP")
                            _this_stem_cap = next((s for s in _coin_stems if ticker.startswith(s)), None)
                            if _this_stem_cap:
                                _coin_locked = sum(
                                    pos["entry_price"] * pos["count"]
                                    for tk, pos in positions.items()
                                    if not pos.get("_stopped_out") and tk.startswith(_this_stem_cap)
                                )
                                if _coin_locked >= free_balance * _SHADOW_CAP_LOCKED_PER_COIN:
                                    return False
                            # Per-coin-per-type restriction removed: shadow now allows multiple
                            # 15M positions per coin, matching live bot behavior (up to 4 per coin,
                            # capped by total 30% and per-coin 20% limits above).
                            return True

                        # NOTE: Freeze circuit breaker removed from experiment bot loop.
                        # _last_settlement_time tracks the MAIN shadow bot's range market
                        # settlements (hourly). Gating 15m experiment bots on hourly range
                        # settlement cadence was blocking all experiment entries for 30+ min
                        # stretches — defeating the purpose of independent bot testing.
                        # Each experiment bot has its own balance + position limits as guards.

                        if _kx_side:
                            _kx_pos = {
                                "side": _kx_side, "entry_price": _kx_eff_price,
                                "count": 1,  # placeholder, overridden per-exp below
                                "hour": shadow_hour, "entry_time": now,
                                "close_time": m.close_time,  # stored for stale-purge detection
                                "market_title": m.title or "",
                                "fair_prob": round(s_fair_prob, 3),
                                "market_prob": round(mid / 100, 3),
                                "edge": round(s_fair_prob - mid / 100, 3),
                                "tranches": [{"price": _kx_eff_price, "count": 1, "secs_left": s_secs}],
                                "t2_done": False, "t3_done": False,
                                "hedge_done": False, "window_secs": s_secs,
                                "signal_components": _kx_signal_components,  # Gap 1/2
                            }
                            _kx_trade = {
                                "time": now, "action": "entry_t1",
                                "ticker": m.ticker, "side": _kx_side,
                                "market_title": m.title or "",
                                "entry_price": _kx_eff_price, "count": 1,
                                "fair_prob": round(s_fair_prob, 3),
                                "market_prob": round(mid / 100, 3),
                                "edge": round(s_fair_prob - mid / 100, 3),
                                "bet_cents": _kx_price,
                            }
                            _kx_coin_pfx = next((px for px in _SHADOW_PREFIXES if m.ticker.startswith(px)), None)
                            _kx_is_15m = "15M" in m.ticker
                            # Daily/weekly = not 15m AND more than 4 hours to close.
                            # Hourly bracket markets also start with KXBTCD/KXETHD etc but
                            # have s_secs < 3600, so we can't use prefix alone.
                            _kx_is_daily = not _kx_is_15m and s_secs > 3600 * 4
                            # Skip daily/weekly markets — experiment bots trade 15m binary + hourly bracket.
                            # Hourly bracket (range) markets: s_secs < 3600, not "15M" in ticker.
                            # Backtest shows range markets deliver ~95% WR vs ~86% for 15m binary.
                            if _kx_is_daily:
                                continue
                            _kx_is_range_mkt = not _kx_is_15m  # True for hourly bracket markets
                            # ── Win probability for Kelly bots ─────────────────────────
                            _kx_win_prob = s_fair_prob if _kx_side == "yes" else (1 - s_fair_prob)
                            _kx_cs = _kx_coin_stem(_kx_coin_pfx)  # coin stem (e.g. "KXBTC")

                            # ── V2/V3 fair probs for formula-comparison bots ─────────────────
                            # Group 2 uses V2 (GARCH-proxy), Group 3 uses V3 (Jump-diffusion).
                            # Reuse V1's direction (_kx_side); only probability magnitude differs.
                            _v23_px = (locals().get("_s_blended_prices")
                                       or (dict(live_prices) if live_prices else {}))
                            try:
                                _raw_v2      = compute_fair_probability_v2(
                                    m.ticker, m.floor_strike or 0, s_secs, _v23_px, _kx_spread_cents)
                                s_fair_prob_v2 = max(0.01, min(0.99, _raw_v2 + _s_fr_adj))
                            except Exception:
                                s_fair_prob_v2 = s_fair_prob
                            _kx_fc_v2  = max(1, min(99, int(s_fair_prob_v2 * 100)))
                            _kx_ce_v2  = (_kx_fc_v2 - (yes_ask if yes_ask > 0 else mid)
                                          if _kx_side == "yes" else
                                          ((100 - _kx_fc_v2) - (no_ask if no_ask > 0 else 100 - mid)
                                           if _kx_side == "no" else -999))
                            _kx_wp_v2  = (s_fair_prob_v2 if _kx_side == "yes"
                                          else 1.0 - s_fair_prob_v2)

                            try:
                                _raw_v3      = compute_fair_probability_v3(
                                    m.ticker, m.floor_strike or 0, s_secs, _v23_px)
                                s_fair_prob_v3 = max(0.01, min(0.99, _raw_v3 + _s_fr_adj))
                            except Exception:
                                s_fair_prob_v3 = s_fair_prob
                            _kx_fc_v3  = max(1, min(99, int(s_fair_prob_v3 * 100)))
                            _kx_ce_v3  = (_kx_fc_v3 - (yes_ask if yes_ask > 0 else mid)
                                          if _kx_side == "yes" else
                                          ((100 - _kx_fc_v3) - (no_ask if no_ask > 0 else 100 - mid)
                                           if _kx_side == "no" else -999))
                            _kx_wp_v3  = (s_fair_prob_v3 if _kx_side == "yes"
                                          else 1.0 - s_fair_prob_v3)

                            # ── Strategy experiment variables ────────────────────────────────
                            # Option 2: Edge-based contrarian — bet whichever side market underprices
                            _kx_side_ev   = "yes" if _kx_yes_ce >= 0 else ("no" if _kx_no_ce >= 0 else None)
                            _kx_wp_ev     = (s_fair_prob if _kx_side_ev == "yes"
                                             else (1.0 - s_fair_prob) if _kx_side_ev else 0.0)
                            _kx_ce_ev     = (_kx_yes_ce if _kx_side_ev == "yes"
                                             else (_kx_no_ce if _kx_side_ev == "no" else -999))
                            _kx_price_ev  = (max(1, min(98, yes_ask if yes_ask > 0 else mid))
                                             if _kx_side_ev == "yes"
                                             else max(1, min(98, no_ask if no_ask > 0 else 100 - mid))
                                             if _kx_side_ev == "no" else 0)
                            _kx_eff_price_ev = min(_kx_price_ev + _SHADOW_SLIPPAGE_CENTS, 98) if _kx_price_ev > 0 else 0

                            # Option 1: Calibrated blend — 50% model + 50% market
                            s_fair_prob_bl = max(0.01, min(0.99, 0.5 * s_fair_prob + 0.5 * (mid / 100)))
                            _kx_side_bl   = "yes" if s_fair_prob_bl > 0.5 else "no"
                            _kx_fc_bl     = max(1, min(99, int(s_fair_prob_bl * 100)))
                            _kx_wp_bl     = (s_fair_prob_bl if _kx_side_bl == "yes"
                                             else 1.0 - s_fair_prob_bl)
                            _kx_ce_bl     = (_kx_fc_bl - (yes_ask if yes_ask > 0 else mid)
                                             if _kx_side_bl == "yes" else
                                             (100 - _kx_fc_bl) - (no_ask if no_ask > 0 else 100 - mid))
