                                    _w21kf     = _w21cfg["kelly"] * _w21_corr * _w21_vscl * _w21_sprd * _kx_duration_adj
                                    _w21cnt    = _kx_kelly_cnt(_w21wp_kelly, _w21price, _w21bal, _w21kf, _w21cfg.get("max_pct", 0.10))
