                                        _w22_sprd  = _kx_spread_adj if _w22cfg.get("spread_adj", True) else 1.0
                                        _w22kf     = _w22cfg["kelly"] * _w22_corr * _w22_vscl * _w22_sprd * _kx_duration_adj
                                        _w22cnt    = _kx_kelly_cnt(_w22wp_kelly, _w22price, _w22bal, _w22kf, _w22cfg.get("max_pct", 0.10))
