# ── Task 33: Graceful Degradation Helper ──────────────────────────────────────

def _get_degraded_services() -> list[str]:
    """Return a list of service names that are currently unavailable."""
    unavailable = []
    # Check Kalshi
    if not kalshi or not config.validate_kalshi():
        unavailable.append("kalshi")
    elif kalshi and kalshi._circuit_state == "open":
        unavailable.append("kalshi (circuit breaker open)")
    # Check local DB
    if not db or not db.is_connected:
        unavailable.append("local_db")
    # Check notifications
    if not notifier or not notifier.is_configured:
        unavailable.append("notifications")
    return unavailable


# ═══════════════════════════════════════════════════════════════════════════
# API ENDPOINTS
# ═══════════════════════════════════════════════════════════════════════════
# This section defines all the URL routes that the frontend can call.
# Each function decorated with @app.get, @app.post, or @app.patch is a
# "route handler" — it runs when the frontend (or CLI) sends an HTTP request
# to that URL.
#
# WHAT IS A REST API?
#   REST (Representational State Transfer) is a convention for how web
#   applications communicate over HTTP. The key ideas:
#
#   - Each URL (like /api/status) represents a "resource" (something you can
#     read or modify). The URL tells you WHAT you're working with.
#
#   - HTTP methods (GET, POST, PATCH) tell you WHAT TO DO with it:
#       GET:   Read data. Does not change anything. Safe to call repeatedly.
#              Example: GET /api/portfolio → returns your current positions.
#       POST:  Create or trigger something. Usually sends data in the body.
#              Example: POST /api/scan → triggers a new market scan.
#       PATCH: Partially update something. Sends only the fields to change.
#              Example: PATCH /api/config → update one setting without
#                       resetting all other settings to default.
#
#   - Responses are JSON (JavaScript Object Notation) — a human-readable
#     format for structured data:
#       {"balance_cents": 33250, "open_positions": 3, "auto_scan_enabled": true}
#     JSON is the universal language of web APIs. The frontend reads it and
#     updates the dashboard display accordingly.
#
# HTTP STATUS CODES:
#   200 OK:          Success — here's the data you asked for.
#   400 Bad Request: You sent invalid data (e.g., negative bet amount).
#   404 Not Found:   The resource you asked for doesn't exist.
#   500 Server Error: Something went wrong on our end.
#   503 Unavailable: An external service (Kalshi API) is unreachable.
#
# FastAPI automatically handles the routing: when the browser/CLI sends
# GET /api/status, FastAPI finds the get_status() function and calls it.
# The function's return value is automatically converted to JSON and sent
# back as the HTTP response body.
# ═══════════════════════════════════════════════════════════════════════════

# ── API Endpoints ────────────────────────────────────────────────────────────

# Fix #21: Cache for status endpoint
_status_cache: dict[str, Any] = {"data": None, "time": 0.0}
# _status_cache: stores the last /api/status response for 5 seconds.
# The frontend polls this endpoint every few seconds; without caching, each
# poll would rebuild the entire status dict (reading from Kalshi API, counting
# positions, etc.) — wasteful when nothing has changed. The 5-second TTL
# (time-to-live) means status is at most 5 seconds stale, which is fine.

@app.get("/api/status")
async def get_status():
    """Get bot status, connection state, configuration, and model info.

    Returns a comprehensive status object used by the frontend Dashboard tab to
    display connection indicators, config values, model state, paper trader state,
    and auto-scan/trade toggle states.
    """
    # Fix #21: Cache the response for 5 seconds to avoid rebuilding on every poll
    now = _time_mod.time()
    if _status_cache["data"] is not None and now - _status_cache["time"] < 5:
        return _status_cache["data"]

    result = {
        "kalshi_connected": config.validate_kalshi(),
        "kalshi_ws_connected": _kalshi_ws_connected,
        "kalshi_ws_markets": len(_kalshi_ws_prices),
        "anthropic_connected": config.validate_anthropic(),
        "local_db_connected": db.is_connected if db else False,
        "environment": "demo" if config.kalshi_use_demo else "production",
        # Fix #49: Add version field
        "version": _API_VERSION,
        # Fix #48: Add uptime_seconds field
        "uptime_seconds": round(_time_mod.time() - _server_start_time, 0),
        # Fix #50: Add last_retrain timestamp from cache
        "last_retrain": _cache.get("last_retrain"),
        "config": {
            "max_bet_amount_cents": config.max_bet_amount_cents,
            "min_edge_threshold": config.min_edge_threshold,
            "max_daily_loss_cents": config.max_daily_loss_cents,
            "max_open_positions": config.max_open_positions,
            "max_events_to_analyze": config.max_events_to_analyze,
            "kelly_fraction": config.kelly_fraction,
            "entry_threshold": config.entry_threshold,
            "min_confidence": config.min_confidence,
        },
        "model": {
            "n_features": len(FEATURE_NAMES),
            "feature_names": FEATURE_NAMES,
            "n_estimators": rf_generator.model.n_estimators if rf_generator else 0,
            "is_trained": rf_generator.model.is_trained if rf_generator else False,
            "drift": rf_generator.model.get_drift_status() if rf_generator else {},
            "model_version": paper_trader.model_version if paper_trader else 0,
            "model_comparison": _cache.get("model_comparison"),
        },
        "market_regime": rf_generator.regime_detector.detect_regime() if rf_generator else {},
        "dynamic_confidence": {
            "enabled": config.dynamic_confidence_enabled,
            "current_threshold": config.min_confidence,
            "adjustments": _cache.get("dynamic_confidence", {}).get("adjustments_log", [])[-5:],
        },
        "paper_trader": {
            "initialized": paper_trader is not None,
            "model_trained": paper_trader.generator.model.is_trained if paper_trader else False,
            "training_samples": paper_trader.training_store.count if paper_trader else 0,
            "balance_cents": paper_trader.balance_cents if paper_trader else 0,
            "open_positions": len(paper_trader.positions) if paper_trader else 0,
            "total_scans": paper_trader.total_scans if paper_trader else 0,
        },
        "auto_scan_enabled": _cache.get("auto_scan_enabled", False),
        "auto_trade_enabled": _cache.get("auto_trade_enabled", False),
        "shadow_crypto_enabled": _cache.get("shadow_crypto_enabled", False),
        "scan_interval_seconds": _cache.get("_scan_interval_seconds", 0.3),
        "fetch_interval_seconds": _cache.get("_fetch_interval_seconds", 10),
        "last_scan": _cache.get("last_scan"),
        "model_loading": _cache.get("model_loading", False),
        "degraded_mode": _get_degraded_services(),
        "circuit_breaker": kalshi.get_circuit_state() if kalshi else {},
        "ensemble_status": rf_generator.model.get_ensemble_status() if rf_generator and rf_generator.model.is_trained else {},
        "watchlist_count": len(_cache.get("watchlist", [])),
        "sse_clients": len(_sse_clients),
        # Live trading config — updated by PATCH /api/config or W33 auto-promotion
        "live_trading": {
            "signal_wp":        _live_signal_wp,
            "signal_wm":        _live_signal_wm,
            "signal_wi":        _live_signal_wi,
            "signal_wf":        _live_signal_wf,
            "min_edge_cents":   _live_min_edge_cents,
            "kelly_base":       _live_kelly_base,
            "min_win_prob":     _live_min_win_prob,
            "budget_15m_pct":   0.60,
            "budget_range_pct": 0.40,
            "last_promoted_bot": _w33_last_promoted_bot,
        },
    }
    # Fix #21: Store in cache
    _status_cache["data"] = result
    _status_cache["time"] = _time_mod.time()
    return result


@app.get("/api/portfolio")
async def get_portfolio():
    """Get portfolio summary."""
    if not kalshi or not config.validate_kalshi():
        raise HTTPException(400, "Kalshi not connected")
    try:
        # Fix #1: Proper error handling around kalshi.get_portfolio_summary()
        summary = await asyncio.to_thread(kalshi.get_portfolio_summary)
        logger.info("[/api/portfolio] Portfolio summary retrieved successfully")
        return summary.model_dump()
    except httpx.ConnectError:
        # Fix #4: Wrap kalshi calls in httpx.ConnectError handler
        raise HTTPException(503, "Kalshi API unreachable — connection failed")
    except Exception as e:
        raise HTTPException(500, f"[/api/portfolio] Failed to get portfolio: {str(e)}")


@app.get("/api/positions")
async def get_positions():
    """Get open positions enriched with current market prices and unrealized P&L.

    For each position, fetches the current market data to calculate the live
    unrealized P&L based on the difference between current ask price and entry price.
    """
    if not kalshi or not config.validate_kalshi():
        raise HTTPException(400, "Kalshi not connected")
    try:
        # Fix #2: Proper error handling with descriptive message
        positions = await asyncio.to_thread(kalshi.get_positions)

        # Build ticker->market map from cached events to avoid N+1 API calls
        ticker_market_map: dict[str, Any] = {}
        cached_events = _cache.get("_cached_events", [])
        for ev in cached_events:
            for m in ev.markets:
                ticker_market_map[m.ticker] = m

        result = []
        for pos in positions:
            market = ticker_market_map.get(pos.ticker)
            # Fall back to individual API call only if not in cache
            if market is None:
                market = await asyncio.to_thread(kalshi.get_market, pos.ticker)
            pos_dict = pos.model_dump()
            if market:
                pos_dict["current_price_cents"] = market.yes_ask if pos.side == "yes" else market.no_ask
                pos_dict["market_title"] = market.title
                if pos.side == "yes":
                    pos_dict["unrealized_pnl_cents"] = (
                        (pos_dict["current_price_cents"] - pos.avg_price_cents) * pos.quantity
                    )
                else:
                    # NO side: avg_price_cents is NO cost basis, current NO value = 100 - yes_ask
                    pos_dict["unrealized_pnl_cents"] = (
                        ((100 - pos_dict["current_price_cents"]) - pos.avg_price_cents) * pos.quantity
                    )
            result.append(pos_dict)
        logger.info(f"[/api/positions] Retrieved {len(result)} positions")
        return {"positions": result, "total": len(result)}
    except httpx.ConnectError:
        raise HTTPException(503, "Kalshi API unreachable — connection failed")
    except Exception as e:
        raise HTTPException(500, f"[/api/positions] Failed to get positions: {str(e)}")


@app.post("/api/scan")
async def run_scan(req: ScanRequest):
    """Run an on-demand market scan triggered by the frontend Signals tab.

    Pipeline:
      1. Fetch ALL events from Kalshi using cursor-based pagination.
      2. Generate entry signals using the RF+GB ensemble model.
      3. Optionally generate additional signals using Claude AI (if use_ai=true).
      4. Check open positions for exit signals (target hit or expiry approaching).
      5. Validate all signals through the RiskManager (balance, limits, edge checks).
      6. Cache results for the GET /api/signals endpoint.

    Returns signal counts and the full list of validated signals for the frontend.
    """
    # Task 32: Request deduplication
    # Clean stale inflight entries (e.g., if a request crashed without reaching finally)
    stale_cutoff = (datetime.now(timezone.utc) - timedelta(minutes=15)).isoformat()
    stale_keys = [k for k, v in _inflight_requests.items() if v < stale_cutoff]
    for k in stale_keys:
        _inflight_requests.pop(k, None)

    if "/api/scan" in _inflight_requests:
        return JSONResponse(
            {"status": "already_running", "started_at": _inflight_requests["/api/scan"]},
            status_code=409,
        )

    # Task 33: Graceful degradation — serve cached data if Kalshi is down
    if not kalshi or not config.validate_kalshi():
        cached_events = _cache.get("events", [])
        if cached_events:
            return {
                "events_scanned": len(cached_events),
                "signals": _cache.get("signals", []),
                "exit_signals_data": _cache.get("exit_signals", []),
                "scan_time": _cache.get("last_scan"),
                "cached": True,
                "degraded": True,
            }
        raise HTTPException(400, "Kalshi not connected")

    # Task 44: Return cached result if within 30s TTL
    cached_time = _cache.get("last_scan_result_time", 0)
    if _time_mod.time() - cached_time < 30 and _cache.get("last_scan_result"):
        return {**_cache["last_scan_result"], "cached": True}

    _inflight_requests["/api/scan"] = datetime.now(timezone.utc).isoformat()
    try:
        # Fix #53: Track scan duration
        _scan_start = _time_mod.time()
        # Fetch ALL events from Kalshi (run in thread to avoid blocking event loop)
        events = await asyncio.to_thread(kalshi.get_all_events)
        total_markets = sum(len(e.markets) for e in events)

        # Generate RF signals (run in thread — CPU-bound ML inference)
        rf_signals = await asyncio.to_thread(rf_generator.generate_signals, events) if rf_generator else []

        # Collect near-miss opportunities for display
        near_misses = getattr(rf_generator, '_last_near_misses', []) if rf_generator else []

        # Run AI analysis only when requested and available
        ai_signals = []
        if req.use_ai and ai_analyzer:
            logger.info(f"[/api/scan] Starting AI analysis (Claude + web search) on top 100 markets...")
            ai_start = _time_mod.time()
            ai_signals = await asyncio.to_thread(ai_analyzer.analyze_events, events)
            ai_elapsed = _time_mod.time() - ai_start
            logger.info(f"[/api/scan] AI analysis complete: {len(ai_signals)} total signals in knowledge base ({ai_elapsed:.1f}s)")
        elif req.use_ai and not ai_analyzer:
            logger.warning("[/api/scan] AI requested but not available — no ANTHROPIC_API_KEY configured")
        else:
            logger.info("[/api/scan] AI scan disabled — RF only")

        # Fix #72: Use asyncio.to_thread for blocking calls
        # Check exit signals for open positions
        positions = await asyncio.to_thread(kalshi.get_positions)
        exit_signals = await asyncio.to_thread(rf_generator.check_exits, events, positions) if rf_generator else []

        # Get portfolio for risk checks
        portfolio = await asyncio.to_thread(kalshi.get_portfolio_summary)

        # Validate signals through risk manager
        validated_signals = []
        for sig in rf_signals:
            allowed, reason = risk_manager.check_signal(sig, portfolio)
            sig_dict = sig.model_dump()
            sig_dict["risk_check"] = {"allowed": allowed, "reason": reason}
            sig_dict["source"] = "random_forest"
            validated_signals.append(sig_dict)

        for sig in ai_signals:
            allowed, reason = risk_manager.check_signal(sig, portfolio)
            sig_dict = sig.model_dump()
            sig_dict["risk_check"] = {"allowed": allowed, "reason": reason}
            sig_dict["source"] = "claude_ai"
            validated_signals.append(sig_dict)

        # Cache results (lock serializes with background auto-scan writes)
        async with _cache_lock:
            _cache["events"] = [e.model_dump() for e in events]
            _cache["signals"] = validated_signals
            _cache["exit_signals"] = [s.model_dump() for s in exit_signals]
            _cache["last_scan"] = datetime.now(timezone.utc).isoformat()

        # Fix #53: Add duration_ms to scan response
        _scan_elapsed_ms = round((_time_mod.time() - _scan_start) * 1000, 1)
        scan_result = {
            "events_scanned": len(events),
            "markets_scanned": total_markets,
            "rf_signals": len(rf_signals),
            "ai_signals": len(ai_signals),
            "ai_enabled": ai_analyzer is not None,
            "exit_signals": len(exit_signals),
            "signals": validated_signals,
            "exit_signals_data": [s.model_dump() for s in exit_signals],
            "near_misses": near_misses[:10],
            "worst_opportunities": getattr(rf_generator, '_last_worst_opportunities', [])[:10] if rf_generator else [],
            "scan_time": _cache["last_scan"],
            "duration_ms": _scan_elapsed_ms,
            "cached": False,
        }

        # Task 44: Cache for TTL
        _cache["last_scan_result"] = scan_result
        _cache["last_scan_result_time"] = _time_mod.time()

        logger.info(f"[/api/scan] Scan complete in {_scan_elapsed_ms:.0f}ms: {len(rf_signals)} RF + {len(ai_signals)} AI signals")
        return scan_result
    except httpx.ConnectError:
        raise HTTPException(503, "Kalshi API unreachable — connection failed")
    except Exception as e:
        raise HTTPException(500, f"[/api/scan] Scan failed: {str(e)}")
    finally:
        _inflight_requests.pop("/api/scan", None)


@app.get("/api/signals")
async def get_cached_signals():
    """Get the most recent scan results."""
    # Fix #22: Return cached signals with age indicator instead of empty list
    last_scan = _cache.get("last_scan")
    age_seconds = None
    if last_scan:
        try:
            scan_dt = datetime.fromisoformat(last_scan)
            age_seconds = round((datetime.now(timezone.utc) - scan_dt).total_seconds(), 1)
        except (ValueError, TypeError):
            pass
    signals = _cache.get("signals", [])
    return {
        "signals": signals,
        "exit_signals": _cache.get("exit_signals", []),
        "near_misses": _cache.get("near_misses", []),
        "worst_opportunities": _cache.get("worst_opportunities", []),
        "last_scan": last_scan,
        "cache_age_seconds": age_seconds,
        "total": len(signals),
    }


@app.post("/api/ai/toggle")
async def toggle_ai_scan():
    """Toggle AI scanning on/off. Affects both manual and auto-scan."""
    current = _cache.get("ai_scan_enabled", False)
    _cache["ai_scan_enabled"] = not current
    new_state = _cache["ai_scan_enabled"]
    logger.info(f"AI scanning toggled: {'ON' if new_state else 'OFF'}")
