@app.get("/api/model/features")
async def get_feature_importance():
    """Get Random Forest feature importance rankings.

    WHAT IS "FEATURE IMPORTANCE"?
      The Random Forest model uses 108 features to make predictions. Feature
      importance measures HOW MUCH each feature contributed to the model's
      accuracy during training. High importance = the model relies on this
      feature heavily; low importance = the model mostly ignores it.

      Examples of features and what they might capture:
        - "spread_pct": (ask - bid) / mid — tight spread = liquid market =
          more informed prices = more reliable signal
        - "time_to_close_norm": how close we are to settlement — near expiry,
          the market price is more predictive (less time for surprises)
        - "yes_bid_imbalance": order book skew toward YES side
        - "price_vs_strike_pct": how far current price is from the strike

      Understanding feature importance helps diagnose model behavior:
        - If "time_to_close" dominates, the model learned that timing matters most
        - If spread features dominate, liquidity is the key signal
        - Features with near-zero importance can be removed in future iterations
          (model simplification without losing accuracy)

      The feature importance values sum to 1.0 across all 108 features.
      They're computed by the Random Forest during training via the "mean
      decrease in impurity" method (how much each feature reduces uncertainty
      in each decision tree's splits).
    """
    # Fix #28: Return empty dict instead of raising if model not trained
    if not rf_generator:
        return {"features": {}, "feature_names": FEATURE_NAMES, "n_features": len(FEATURE_NAMES), "is_trained": False}
    if not rf_generator.model.is_trained:
        return {"features": {}, "feature_names": FEATURE_NAMES, "n_features": len(FEATURE_NAMES), "is_trained": False}
    try:
        importance = rf_generator.model.get_feature_importance()
    except Exception:
        importance = {}
    return {
        "features": importance,
        "feature_names": FEATURE_NAMES,
        "n_features": len(FEATURE_NAMES),
        "is_trained": rf_generator.model.is_trained,
    }


# ── Arbitrage Endpoints ─────────────────────────────────────────────────────

@app.get("/api/arbitrage")
async def scan_arbitrage():
    """Scan for cross-platform arbitrage opportunities.

    WHAT IS ARBITRAGE?
      Arbitrage means buying something cheap on one platform and selling it
      at a higher price on another — pocketing the difference risk-free.

      In prediction markets, if Kalshi prices "Will BTC close above $65K?"
      at YES=55¢ and DraftKings prices the same event at YES=70¢, then:
        - Buy YES on Kalshi at 55¢ (you win $45 per contract if YES)
        - Sell YES on DraftKings at 70¢ (you pay back $30 if YES wins)
        - Net: +15¢ per contract regardless of the outcome

      In practice, pure arbitrage in prediction markets is rare because:
        1. The platforms rarely cover the exact same events with exact same
           settlement criteria
        2. Execution is slow (you have to manually place orders on two platforms)
        3. By the time you see the gap, others have already closed it

      What this endpoint actually finds:
        NEAR-arbitrage: events that are similar enough between Kalshi and
        DraftKings that a large price discrepancy suggests one platform is
        "wrong." This is more of a signal to investigate than a guaranteed
        profit — it requires human judgment to confirm the events are truly
        the same and the settlement criteria match.

      The "recommended_action" field tells you which side to bet on which
      platform based on the detected spread. The spread_pct shows how large
      the discrepancy is as a percentage.
    """
    if not kalshi or not dk:
        raise HTTPException(400, "Clients not initialized")

    try:
        # Fix #72: Use asyncio.to_thread for blocking calls
        events = await asyncio.to_thread(kalshi.get_all_events)
        kalshi_markets = [m for e in events for m in e.markets if m.status == "open"]
        dk_markets = await asyncio.to_thread(dk.get_prediction_markets)

        opportunities = detect_arbitrage(kalshi_markets, dk_markets)

        return {
            "kalshi_markets": len(kalshi_markets),
            "dk_markets": len(dk_markets),
            "opportunities": [
                {
                    "kalshi_ticker": o.kalshi_ticker,
                    "dk_market_id": o.dk_market_id,
                    "title": o.title,
                    "kalshi_yes_price": o.kalshi_yes_price,
                    "dk_yes_price": o.dk_yes_price,
                    "spread_pct": o.spread_pct,
                    "recommended_action": o.recommended_action,
                }
                for o in opportunities
            ],
        }
    except httpx.ConnectError:
        raise HTTPException(503, "Kalshi API unreachable — connection failed")
    except Exception as e:
        raise HTTPException(500, f"[/api/arbitrage] Arbitrage scan failed: {str(e)}")


@app.patch("/api/config")
async def update_config(update: ConfigUpdate):
    """Update trading configuration with change history tracking and dry_run support.

    Task 27: If dry_run=true, returns what would change without applying.
    Also saves a config snapshot before applying changes so POST /api/config/rollback
    can revert the last change.

    WHAT SETTINGS CAN BE CHANGED LIVE (WITHOUT RESTARTING)?
      - max_bet_amount_cents: hard ceiling on a single bet (e.g., 1500 = $15)
      - min_edge_threshold: minimum edge (fair - market) to place a trade
      - max_daily_loss_cents: daily loss limit before trading halts
      - max_open_positions: max concurrent open positions
      - kelly_fraction: the base Kelly fraction multiplier
      - entry_threshold: RF model probability threshold to take a signal
      - min_confidence: minimum RF model confidence to trust a prediction
      - live_min_win_prob: override the live bot's win probability gate
      - live_min_edge_cents: override the live bot's edge requirement
      - live_kelly_base: override the live bot's Kelly fraction

    WHY "LIVE" OVERRIDES?
      The shadow bots find the best-performing parameter set. When one bot
      clearly wins, the auto-deploy monitor calls PATCH /api/config with
      live_min_win_prob, live_min_edge_cents, and live_kelly_base set to that
      winner's parameters. The live bot immediately starts using them without
      requiring a restart or code change.

    The PATCH method (not POST or PUT) is correct here because we're updating
    SOME fields of the config object — fields not mentioned keep their current
    values. POST would typically replace everything, PUT would require sending
    the complete object.
    """
    global _previous_config_snapshot

    changes = []
    fields = [
        ("max_bet_amount_cents", update.max_bet_amount_cents),
        ("min_edge_threshold", update.min_edge_threshold),
        ("max_daily_loss_cents", update.max_daily_loss_cents),
        ("max_open_positions", update.max_open_positions),
        ("max_events_to_analyze", update.max_events_to_analyze),
        ("kelly_fraction", update.kelly_fraction),
        ("entry_threshold", update.entry_threshold),
        ("min_confidence", update.min_confidence),
    ]
    for field_name, new_val in fields:
        if new_val is not None:
            old_val = getattr(config, field_name)
            if old_val != new_val:
                changes.append({
                    "field": field_name,
                    "old_value": old_val,
                    "new_value": new_val,
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                })

    # Task 27: Dry run mode -- return what would change without applying
    if update.dry_run:
        return {
            "status": "dry_run",
            "would_change": changes,
            "current_config": {
                "max_bet_amount_cents": config.max_bet_amount_cents,
                "min_edge_threshold": config.min_edge_threshold,
                "max_daily_loss_cents": config.max_daily_loss_cents,
                "max_open_positions": config.max_open_positions,
                "max_events_to_analyze": config.max_events_to_analyze,
                "kelly_fraction": config.kelly_fraction,
                "entry_threshold": config.entry_threshold,
                "min_confidence": config.min_confidence,
            },
        }

    # Task 27: Save snapshot before applying (for rollback)
    _previous_config_snapshot = {
        "max_bet_amount_cents": config.max_bet_amount_cents,
        "min_edge_threshold": config.min_edge_threshold,
        "max_daily_loss_cents": config.max_daily_loss_cents,
        "max_open_positions": config.max_open_positions,
        "max_events_to_analyze": config.max_events_to_analyze,
        "kelly_fraction": config.kelly_fraction,
        "entry_threshold": config.entry_threshold,
        "min_confidence": config.min_confidence,
        "snapshot_time": datetime.now(timezone.utc).isoformat(),
    }

    # Apply standard config changes
    for field_name, new_val in fields:
        if new_val is not None:
            setattr(config, field_name, new_val)

    # Apply live deployment overrides (module-level globals, not in config object)
    global _live_min_win_prob, _live_min_edge_cents, _live_kelly_base, _live_deployed_bot
    if update.live_min_win_prob is not None:
        _live_min_win_prob = update.live_min_win_prob
        changes.append({"field": "live_min_win_prob", "new_value": _live_min_win_prob})
    if update.live_min_edge_cents is not None:
        _live_min_edge_cents = update.live_min_edge_cents
        changes.append({"field": "live_min_edge_cents", "new_value": _live_min_edge_cents})
    if update.live_kelly_base is not None:
        _live_kelly_base = update.live_kelly_base
        changes.append({"field": "live_kelly_base", "new_value": _live_kelly_base})

    # Apply live signal weight overrides (W33 promotion formula update)
    global _live_signal_wp, _live_signal_wm, _live_signal_wi, _live_signal_wf
    if update.live_signal_wp is not None:
        _live_signal_wp = update.live_signal_wp
        changes.append({"field": "live_signal_wp", "new_value": _live_signal_wp})
    if update.live_signal_wm is not None:
        _live_signal_wm = update.live_signal_wm
        changes.append({"field": "live_signal_wm", "new_value": _live_signal_wm})
    if update.live_signal_wi is not None:
        _live_signal_wi = update.live_signal_wi
        changes.append({"field": "live_signal_wi", "new_value": _live_signal_wi})
    if update.live_signal_wf is not None:
        _live_signal_wf = update.live_signal_wf
        changes.append({"field": "live_signal_wf", "new_value": _live_signal_wf})

    # Force status cache refresh so /api/status reflects new config immediately
    _status_cache["time"] = 0

    # Log config changes (max 50 entries)
    if changes:
        config_history = _cache.get("config_changes", [])
        config_history.extend(changes)
        _cache["config_changes"] = config_history[-50:]
        for c in changes:
            # Fix #12: Log all config changes to logger.info
            logger.info(f"[/api/config] Config changed: {c['field']}: {c.get('old_value', 'N/A')} -> {c['new_value']}")
            _audit_log("config_change", f"{c['field']}: {c.get('old_value', 'N/A')} -> {c['new_value']}", user_action=True)

    return {"status": "updated", "config": {
        "max_bet_amount_cents": config.max_bet_amount_cents,
        "min_edge_threshold": config.min_edge_threshold,
        "max_daily_loss_cents": config.max_daily_loss_cents,
        "max_open_positions": config.max_open_positions,
        "max_events_to_analyze": config.max_events_to_analyze,
        "kelly_fraction": config.kelly_fraction,
        "entry_threshold": config.entry_threshold,
        "min_confidence": config.min_confidence,
    }, "changes": changes, "rollback_available": True}


@app.post("/api/config/rollback")
async def rollback_config():
    """Revert config to the snapshot saved before the last PATCH /api/config change.

    Task 27: Returns the restored config values or 404 if no snapshot exists.
    """
    global _previous_config_snapshot
    if not _previous_config_snapshot:
        raise HTTPException(404, "No config snapshot available for rollback")

    snapshot = _previous_config_snapshot
    rollback_fields = [
        "max_bet_amount_cents", "min_edge_threshold", "max_daily_loss_cents",
        "max_open_positions", "max_events_to_analyze", "kelly_fraction",
        "entry_threshold", "min_confidence",
    ]
    changes = []
    for field_name in rollback_fields:
        if field_name in snapshot:
            old_val = getattr(config, field_name)
            new_val = snapshot[field_name]
            if old_val != new_val:
                changes.append({"field": field_name, "old_value": old_val, "new_value": new_val})
            setattr(config, field_name, new_val)

    _previous_config_snapshot = None  # Consume the snapshot

    return {
        "status": "rolled_back",
        "snapshot_time": snapshot.get("snapshot_time", ""),
        "changes": changes,
        "config": {f: getattr(config, f) for f in rollback_fields},
    }


@app.get("/api/config/history")
async def get_config_history():
    """Get config change history (max 50 entries)."""
    return {"changes": _cache.get("config_changes", [])}


