    max_bet_cents: int = Field(25_00, gt=0, le=100_000_00, description="Maximum bet size in cents per trade")
    entry_threshold: float = Field(0.5, gt=0, le=1.0, description="Model probability threshold to trigger entry")
    exit_threshold: float = Field(0.9, gt=0, le=1.0, description="Model probability threshold to trigger exit")
    min_confidence: float = Field(0.70, ge=0, le=1.0, description="Minimum model confidence for trade signals")
    min_volume: int = Field(50, ge=0, le=100_000, description="Minimum market volume to consider for trading")
