@app.post("/api/paper/liquidate-non-crypto")
async def paper_liquidate_non_crypto():
    """Close all non-crypto-15M paper positions where current price recovers ≥90% of cost.

    For each open paper position that is NOT a 15-minute crypto market, fetches the
    current Kalshi price and closes the position if the sell proceeds are ≥90% of entry cost.
    Reallocates recovered capital to cash for redeployment into 15-minute crypto markets.
    """
    if not paper_trader:
        raise HTTPException(400, "Paper trader not initialized")

    _CRYPTO_15M_PREFIXES = ("KXBTC15M", "KXETH15M", "KXSOL15M", "KXXRP15M", "KXDOGE15M", "KXBNB15M", "KXHYPE15M")
    results: dict = {"closed": [], "skipped": [], "errors": []}
    tickers_to_close: list[str] = []
    now_iso = datetime.now(timezone.utc).isoformat()

    for ticker, pos in list(paper_trader.positions.items()):
        # Keep 15M crypto positions — they settle on their own
        if any(ticker.startswith(p) for p in _CRYPTO_15M_PREFIXES):
            results["skipped"].append({"ticker": ticker, "reason": "crypto_15m_keep"})
            continue

        # Try to get current YES mid price from Kalshi
        current_yes_mid: float | None = None
        try:
            if kalshi:
                mkt = await asyncio.to_thread(kalshi.get_market, ticker)
                if mkt:
                    current_yes_mid = mkt.mid_price_yes / 100.0
        except Exception as e:
            results["errors"].append({"ticker": ticker, "error": str(e)})

        # Fall back to entry price (assume market unchanged) if API unavailable
        if current_yes_mid is None:
            current_yes_mid = pos.entry_price

        # For NO positions, our value = current NO price = 1 - current YES mid
        # For YES positions, our value = current YES mid
        if pos.side == "no":
            current_side_price = 1.0 - current_yes_mid
            entry_side_price = pos.entry_price  # entry_price stored as YES for convention → NO paid
        else:
            current_side_price = current_yes_mid
            entry_side_price = pos.entry_price

        recovery_pct = current_side_price / entry_side_price if entry_side_price > 0 else 0.0

        if recovery_pct < 0.90:
            results["skipped"].append({
                "ticker": ticker,
                "reason": "below_90pct_threshold",
                "recovery_pct": round(recovery_pct * 100, 1),
                "current_side_price": round(current_side_price, 4),
                "entry_side_price": round(entry_side_price, 4),
            })
            continue

        # exit_price is always the YES price (paper_trader convention)
        exit_yes_price = current_yes_mid

        # Compute P&L and return capital
        if pos.side == "yes":
            pnl = (exit_yes_price - pos.entry_price) * 100 * pos.contracts
            paper_trader.balance_cents += int(exit_yes_price * 100 * pos.contracts)
            mae = max(0.0, pos.entry_price - pos.min_price_seen)
            mfe = max(0.0, pos.max_price_seen - pos.entry_price)
        else:
            pnl = (pos.entry_price - exit_yes_price) * 100 * pos.contracts
            paper_trader.balance_cents += int((1.0 - exit_yes_price) * 100 * pos.contracts)
            mae = max(0.0, pos.max_price_seen - pos.entry_price)
            mfe = max(0.0, pos.entry_price - pos.min_price_seen)

        paper_trader.tracker.record_trade(
            ticker=ticker,
            side=pos.side,
            entry_price=pos.entry_price,
            exit_price=exit_yes_price,
            contracts=pos.contracts,
            mae=mae,
            mfe=mfe,
            model_probability=pos.model_prob,
            market_probability_at_entry=pos.entry_price,
            entry_time=pos.entry_time,
            exit_time=now_iso,
            category=pos.category,
            notes="force_liquidate_non_crypto",
        )

        tickers_to_close.append(ticker)
        results["closed"].append({
            "ticker": ticker,
            "side": pos.side,
            "contracts": pos.contracts,
            "entry_price": pos.entry_price,
            "exit_yes_price": round(exit_yes_price, 4),
            "recovery_pct": round(recovery_pct * 100, 1),
            "pnl_cents": int(pnl),
        })

    for t in tickers_to_close:
        del paper_trader.positions[t]

    paper_trader._dirty = True
    await asyncio.to_thread(paper_trader.save_state, None, True)

    logger.info(
        f"[liquidate-non-crypto] Closed {len(tickers_to_close)} positions, "
        f"skipped {len(results['skipped'])}, errors {len(results['errors'])}. "
        f"New balance: {paper_trader.balance_cents}c"
    )
    return {
        "closed_count": len(results["closed"]),
        "skipped_count": len(results["skipped"]),
        "error_count": len(results["errors"]),
        "new_balance_cents": paper_trader.balance_cents,
        "details": results,
    }


@app.post("/api/paper/train")
async def paper_train():
    """Train the paper trader's model on historical settled market data.

    Fetches up to 1000 settled markets from Kalshi, extracts features from
    trade history, and trains the RF+GB ensemble cumulatively (new samples are
    merged with all previously seen data, deduplicated by ticker).
    """
    # Task 32: Request deduplication
    # Clean stale inflight entries
    stale_cutoff = (datetime.now(timezone.utc) - timedelta(minutes=15)).isoformat()
    stale_keys = [k for k, v in _inflight_requests.items() if v < stale_cutoff]
    for k in stale_keys:
        _inflight_requests.pop(k, None)

    if "/api/paper/train" in _inflight_requests:
        return JSONResponse(
            {"status": "already_running", "started_at": _inflight_requests["/api/paper/train"]},
            status_code=409,
        )
    if not kalshi or not config.validate_kalshi():
        raise HTTPException(400, "Kalshi not connected")
    if not paper_trader:
        raise HTTPException(400, "Paper trader not initialized")

    _inflight_requests["/api/paper/train"] = datetime.now(timezone.utc).isoformat()
    try:
        # Fix #56: Track training duration
        _train_start = _time_mod.time()
        fetcher = HistoricalDataFetcher(kalshi)
        _cs = ["KXBTC15M","KXETH15M","KXXRP15M","KXSOL15M","KXDOGE15M","KXBNB15M","KXHYPE15M"]
        settled = await asyncio.to_thread(fetcher.fetch_settled_markets, 5000, _cs)
        result = await asyncio.to_thread(paper_trader.train_model, settled)
        # Sync trained model to live rf_generator
        if rf_generator and paper_trader.generator.model.is_trained:
            rf_generator.model = paper_trader.generator.model
        _train_elapsed = round(_time_mod.time() - _train_start, 1)
        logger.info(f"[/api/paper/train] Training complete in {_train_elapsed}s")
        return {
            "status": "trained",
            "samples_fetched": len(settled),
            "total_cumulative_samples": result.get("total_cumulative_samples", len(settled)),
            "new_samples_added": result.get("new_samples_added", len(settled)),
            "duration_seconds": _train_elapsed,
            **result,
        }
    except httpx.ConnectError:
        raise HTTPException(503, "Kalshi API unreachable — connection failed")
    except Exception as e:
        raise HTTPException(500, f"[/api/paper/train] Training failed: {str(e)}")
    finally:
        _inflight_requests.pop("/api/paper/train", None)


# ── Auto-Scan / Auto-Trade Scheduler ──────────────────────────────────────

class AutoScanConfig(BaseModel):
    """Request body for POST /api/autoscan (toggle background scanning)."""
    enabled: bool = Field(True, description="Enable or disable the background scan loop")
    interval_seconds: float = Field(0.15, ge=0.1, le=3600, description="Seconds between RF evaluations (0.1-3600).")
    fetch_interval_seconds: int = Field(5, ge=5, le=300, description="Seconds between Kalshi API fetches (5-300).")


class AutoTradeConfig(BaseModel):
    """Request body for POST /api/autotrade (toggle live order execution)."""
    enabled: bool = True  # When true AND auto_scan is on, bot places real Kalshi orders


@app.post("/api/autoscan")
async def toggle_auto_scan(req: AutoScanConfig):
    """Enable/disable automatic background scanning.

    Two-loop architecture for maximum speed:
    - Fast loop (_auto_scan_job): runs every interval_seconds (default 0.3s),
      evaluates cached events with RF model. Pure computation, no API calls.
    - Slow loop (_fetch_events_job): runs every fetch_interval_seconds (default 10s),
      fetches fresh events from Kalshi API and caches them.

    This lets us scan at 3+ times per second without hammering Kalshi's API.

    WHAT IS A "BACKGROUND JOB"?
      A background job is a function that runs automatically on a schedule,
      even when no one is actively using the frontend. Think of it like a timer
      that goes off every second and does some work:

      In our case:
        - Every 0.3 seconds: run the RF model on cached market data to look
          for trading signals. If auto_trade is also enabled, place orders.
        - Every 5-10 seconds: fetch fresh market prices from Kalshi's API
          and update the cached data for the fast loop to use.

      APScheduler (Advanced Python Scheduler) manages this. Calling this
      endpoint with {enabled: true} adds the two jobs to the scheduler.
      {enabled: false} removes them, stopping the bot from scanning/trading.

    WHAT IS ASYNC?
      "async" before a function name means it's an "asynchronous" function —
      one that can pause and let other work happen while it waits. In Python
      with asyncio, when an async function hits "await something()", it
      temporarily gives control back to the event loop, which can then process
      other requests or run other tasks.

      This is how ONE Python process can handle the frontend polling /api/status,
      the background scan loop running every 0.3s, AND an active trade being
      placed — all "at the same time" without actual multi-threading complexity.
      It's cooperative multi-tasking: each task voluntarily yields at await points.
    """
    global scheduler
    if not scheduler:
        raise HTTPException(500, "Scheduler not initialized")

    fast_job_id = "auto_scan"
    fetch_job_id = "auto_fetch"

    if req.enabled:
        # Schedule the fast RF evaluation loop
        existing_fast = scheduler.get_job(fast_job_id)
        if existing_fast:
            scheduler.reschedule_job(fast_job_id, trigger="interval", seconds=req.interval_seconds)
        else:
            scheduler.add_job(
                _auto_scan_job,
                "interval",
                seconds=req.interval_seconds,
                id=fast_job_id,
                replace_existing=True,
                max_instances=1,
                misfire_grace_time=None,
            )

        # Schedule the slow Kalshi API fetch loop
        existing_fetch = scheduler.get_job(fetch_job_id)
        if existing_fetch:
            scheduler.reschedule_job(fetch_job_id, trigger="interval", seconds=req.fetch_interval_seconds)
        else:
            scheduler.add_job(
                _fetch_events_job,
                "interval",
                seconds=req.fetch_interval_seconds,
                id=fetch_job_id,
                replace_existing=True,
                max_instances=1,
                misfire_grace_time=None,
            )
            # Also run an immediate fetch + scan so results appear right away
            scheduler.add_job(_fetch_events_job, "date",
                              run_date=datetime.now(timezone.utc) + timedelta(seconds=1),
                              id="auto_fetch_initial")
            scheduler.add_job(_auto_scan_job, "date",
                              run_date=datetime.now(timezone.utc) + timedelta(seconds=15),
                              id="auto_scan_initial")

        _cache["auto_scan_enabled"] = True
        _cache["_fast_scan_count"] = 0
        _cache["_scan_interval_seconds"] = req.interval_seconds
        _cache["_fetch_interval_seconds"] = req.fetch_interval_seconds
        _audit_log("auto_scan_toggle",
                    f"Auto-scan ENABLED (eval={req.interval_seconds}s, fetch={req.fetch_interval_seconds}s)",
                    user_action=True)
    else:
        for jid in (fast_job_id, fetch_job_id):
            if scheduler.get_job(jid):
                scheduler.remove_job(jid)
        _cache["auto_scan_enabled"] = False
        _audit_log("auto_scan_toggle", "Auto-scan DISABLED", user_action=True)

    return {
        "auto_scan_enabled": _cache["auto_scan_enabled"],
        "interval_seconds": req.interval_seconds,
        "fetch_interval_seconds": req.fetch_interval_seconds,
    }


@app.post("/api/autotrade")
async def toggle_auto_trade(req: AutoTradeConfig):
    """Enable/disable automatic live trading (requires auto-scan to be on).

    This is the LIVE TRADING SWITCH. When enabled, the auto-scan loop will
    actually place real orders on Kalshi using real money (or demo money if
    KALSHI_USE_DEMO=true). When disabled, the bot still scans and generates
    signals, but no orders are placed.

    Think of it as:
      auto_scan = ON:  the bot is watching the markets and would trade
      auto_trade = ON: the bot is actually pulling the trigger on trades

    Enabling auto_scan without auto_trade is useful for:
      - Observing signal quality before committing real money
      - Running shadow bots to validate a strategy
      - Emergency pause: stop trading instantly without stopping analysis

    The "paused_by_alert" flag: if a risk threshold is crossed (daily loss
    limit, drawdown %, consecutive losses), auto_trade is automatically set
    to False with the paused_by_alert flag. Re-enabling it here will work,
    but first investigate WHY the alert triggered.
    """
    _cache["auto_trade_enabled"] = req.enabled
    _audit_log("auto_trade_toggle", f"Auto-trade {'ENABLED' if req.enabled else 'DISABLED'}", user_action=True)
    return {
        "auto_trade_enabled": _cache["auto_trade_enabled"],
        "auto_scan_enabled": _cache.get("auto_scan_enabled", False),
    }


class RFBotConfig(BaseModel):
    """Request body for POST /api/rf-bot/toggle — enable or disable the RF live bot."""
    enabled: bool
    min_confidence: float | None = None   # Optional override (default: 0.70)
    budget_pct: float | None = None       # Optional override (default: 0.20)


@app.post("/api/rf-bot/toggle")
async def toggle_rf_bot(req: RFBotConfig):
    """Enable/disable the parallel RF live bot (20% capital, ≥70% confidence tier).

    The RF bot runs alongside the quant crypto bot. It uses the ML ensemble
    (Random Forest + Gradient Boosting) to place live orders only when model
    confidence ≥ 0.70 — the calibration-verified 99.9% win-rate tier.

    Both auto_trade AND this toggle must be ON for the RF bot to place orders.
    """
    global _rf_live_bot_enabled, _rf_live_min_confidence, _rf_live_budget_pct
    _rf_live_bot_enabled = req.enabled
    _cache["rf_bot_enabled"] = req.enabled
    if req.min_confidence is not None:
        _rf_live_min_confidence = max(0.50, min(0.99, req.min_confidence))
    if req.budget_pct is not None:
        _rf_live_budget_pct = max(0.05, min(0.50, req.budget_pct))
    _audit_log(
        "rf_bot_toggle",
        f"RF bot {'ENABLED' if req.enabled else 'DISABLED'} "
        f"min_conf={_rf_live_min_confidence:.2f} budget={_rf_live_budget_pct:.0%}",
        user_action=True,
    )
    return {
        "rf_bot_enabled": _rf_live_bot_enabled,
        "min_confidence": _rf_live_min_confidence,
        "budget_pct": _rf_live_budget_pct,
    }


@app.get("/api/rf-bot/status")
async def rf_bot_status():
    """Status and performance of the parallel RF live bot.

    Returns current configuration, recent trades, and session P&L.
    The RF bot targets the 99.9% historical win-rate calibration tier
    (model confidence ≥ 0.70, verified across 1,186 samples).
    """
    trade_log = _cache.get("rf_bot_trade_log", [])
    entries = [t for t in trade_log if t.get("action") == "entry"]
    exits   = [t for t in trade_log if t.get("action") == "exit"]
    settled_pnl = sum(t.get("pnl_cents", 0) for t in exits)
    wins  = sum(1 for t in exits if t.get("pnl_cents", 0) > 0)
    total = len(exits)
    return {
        "enabled": _rf_live_bot_enabled,
        "min_confidence": _rf_live_min_confidence,
        "budget_pct": _rf_live_budget_pct,
        "session": {
            "trades_placed": len(entries),
            "settled_exits": total,
            "wins": wins,
            "losses": total - wins,
            "win_rate": round(wins / total, 4) if total > 0 else None,
            "pnl_cents": settled_pnl,
            "pnl_dollars": round(settled_pnl / 100, 2),
        },
        "recent_trades": trade_log[-20:],
    }


class ShadowConfig(BaseModel):
    """Request body for POST /api/shadow — enable or disable shadow crypto trading."""
    enabled: bool


def _shadow_bot_summary(experiment, bal, peak, positions, trades, bot_key=""):
    """Build a compact summary dict for one shadow bot — used by /api/shadow/all."""
    import math as _math
    settled = [t for t in trades if t.get("action") in ("settled", "stop_exit", "stop_loss")]
    wins = sum(1 for t in settled if t.get("won") is True)
    losses = sum(1 for t in settled if t.get("won") is False)
    trough = _shadow_trough_map.get(bot_key, bal) if bot_key else bal
    pnls = [t.get("pnl_cents", 0) for t in settled]
    if len(pnls) >= 2:
        mean_pnl = sum(pnls) / len(pnls)
        variance = sum((x - mean_pnl) ** 2 for x in pnls) / len(pnls)
        std_pnl = _math.sqrt(variance) if variance > 0 else 0
        sharpe = round(mean_pnl / std_pnl, 3) if std_pnl > 0 else None
    else:
        sharpe = None
    return {
        "experiment": experiment,
        "balance_cents": bal,
        "peak_cents": peak,
        "trough_cents": trough,
        "open_positions": len(positions),
        "total_trades": len(settled),
        "wins": wins,
        "losses": losses,
        "win_rate": round(wins / len(settled), 3) if settled else None,
        "total_pnl_cents": sum(pnls),
        "sharpe": sharpe,
    }


