@app.get("/api/shadow/wave7")
async def get_wave7_state():
    """Wave 7 tournament — 50-bot scientific experiment.

    Returns standings for all 50 bots, sorted by net PnL descending.
    Each entry includes balance, trades, win rate, Sharpe, and config.
    'winner' key marks the current leader (if eligible: ≥53% WR, ≥5 settled).
    'phase' shows current tournament phase (1=2h, 2=6h).
    'elapsed_min' shows minutes since tournament start.
    """
    import math as _wmath
    import time as _wtime
    elapsed = (_wtime.time() - _w7_start_ts) if _w7_start_ts > 0 else 0
    bots_out = {}
    for _bid, _bstate in _w7_bots.items():
        _bcfg    = _bstate["config"]
        _settled = [t for t in _bstate["trades"] if t.get("action") == "settled"]
        _wins    = sum(1 for t in _settled if t.get("won") is True)
        _losses  = sum(1 for t in _settled if t.get("won") is False)
        _pnls    = [t.get("pnl_cents", 0) for t in _settled]
        _tot_pnl = sum(_pnls)
        _wr      = round(_wins / len(_settled), 3) if _settled else None
        _sharpe  = None
        if len(_pnls) >= 2:
            _mu  = sum(_pnls) / len(_pnls)
            _var = sum((x - _mu) ** 2 for x in _pnls) / len(_pnls)
            _std = _wmath.sqrt(_var) if _var > 0 else 0
            _sharpe = round(_mu / _std, 3) if _std > 0 else None
        bots_out[_bid] = {
            "label":          _bcfg["label"],
            "config":         {k: v for k, v in _bcfg.items() if k != "id"},
            "balance_cents":  _bstate["balance"],
            "net_pnl_cents":  _bstate["balance"] - _W7_INIT_BAL,
            "peak_cents":     _bstate["peak"],
            "open_positions": len(_bstate["positions"]),
            "total_settled":  len(_settled),
            "wins":           _wins,
            "losses":         _losses,
            "win_rate":       _wr,
            "sharpe":         _sharpe,
        }
    # Find current leader: eligible = ≥5 settled AND ≥53% WR
    _eligible = {
        bid: d for bid, d in bots_out.items()
        if d["total_settled"] >= 5 and (d["win_rate"] or 0) >= 0.53
    }
    _leader = (max(_eligible, key=lambda b: _eligible[b]["net_pnl_cents"])
               if _eligible else None)
    return {
        "phase":        _W7_PHASE,
        "elapsed_min":  round(elapsed / 60, 1),
        "phase1_ends_min": round((_W7_DURATION - elapsed) / 60, 1) if elapsed < _W7_DURATION else 0,
        "started":      _w7_start_ts > 0,
        "leader":       _leader,
        "bots":         dict(sorted(bots_out.items(),
                                    key=lambda kv: kv[1]["net_pnl_cents"], reverse=True)),
    }


@app.get("/api/shadow/dyn")
async def get_shadow_dyn_state():
    """Wave 9 dynamic-edge shadow bots — gate function varies by secs_remaining.

    Returns DB-settled stats for each bot plus open positions.
    Bots:
      v9_dyn_lin   — gate decreases linearly from 13¢ to 4¢ over the window
      v9_dyn_exp   — gate decreases quadratically (slow early, sharp near close)
      v9_dyn_step3 — 3-step: 13¢ (>5min) / 8¢ (5min–90s) / 4¢ (<90s)
      v9_dyn_live  — mirrors live 2-step: 13¢ / 4¢ at final 90s
    """
    import sqlite3 as _sl, math as _dm
    _dyn_db = "/Users/colelevy/Desktop/Development/prediction-market-bot/bot.db"
    out = {}
    try:
        with _sl.connect(_dyn_db) as _dcon:
            _dcon.row_factory = _sl.Row
            for _bid in _SHADOW_DYN_BOTS:
                try:
                    rows = _dcon.execute(
                        "SELECT won, pnl_cents FROM shadow_trades WHERE bot_id=?", (_bid,)
                    ).fetchall()
                    _wins   = sum(1 for r in rows if r["won"])
                    _losses = sum(1 for r in rows if not r["won"])
                    _pnls   = [r["pnl_cents"] for r in rows]
                    _tot    = len(rows)
                    _wr     = round(_wins / _tot, 3) if _tot else None
                    _sharpe = None
                    if len(_pnls) >= 2:
                        _mu  = sum(_pnls) / len(_pnls)
                        _var = sum((x - _mu) ** 2 for x in _pnls) / len(_pnls)
                        _std = _dm.sqrt(_var) if _var > 0 else 0
                        _sharpe = round(_mu / _std, 3) if _std > 0 else None
                    out[_bid] = {
                        "total_settled": _tot,
                        "wins":   _wins,
                        "losses": _losses,
                        "win_rate": _wr,
                        "net_pnl_cents": sum(_pnls),
                        "sharpe": _sharpe,
                        "open_positions": len(_shadow_dyn_positions.get(_bid, {})),
                        "open": list(_shadow_dyn_positions.get(_bid, {}).keys()),
                    }
                except Exception:
                    out[_bid] = {"error": "no data yet"}
    except Exception as _e:
        return {"error": str(_e)}
    return {"bots": out}


