@app.get("/api/autoscan/status")
async def get_auto_scan_status():
    """Get auto-scan scheduler status, recent log, and scan efficiency metrics (Task 40)."""
    sm = _cache.get("scan_metrics", {})
    total_scans = sm.get("total_scans", 0)
    total_duration = sm.get("total_duration_ms", 0)
    total_markets = sm.get("total_markets_scanned", 0)
    total_signals = sm.get("total_signals_generated", 0)

    cached_events_age = _time_mod.time() - _cache.get("_cached_events_time", 0)

    return {
        "auto_scan_enabled": _cache.get("auto_scan_enabled", False),
        "auto_trade_enabled": _cache.get("auto_trade_enabled", False),
        "auto_trade_paused_by_alert": _cache.get("auto_trade_paused_by_alert", False),
        "interval_seconds": _cache.get("_scan_interval_seconds", 0.3),
        "fetch_interval_seconds": _cache.get("_fetch_interval_seconds", 10),
        "last_scan": _cache.get("last_scan"),
        "log": _cache.get("auto_scan_log", [])[-20:],
        "fast_scan_count": _cache.get("_fast_scan_count", 0),
        "cached_events_count": len(_cache.get("_cached_events", [])),
        "cached_events_age_seconds": round(cached_events_age, 1),
        "model_trained": paper_trader.generator.model.is_trained if paper_trader else False,
        "scan_efficiency": {
            "total_scans": total_scans,
            "avg_scan_duration_ms": round(total_duration / total_scans, 2) if total_scans else 0,
            "markets_scanned_per_second": round(total_markets / (total_duration / 1000), 2) if total_duration > 0 else 0,
            "signals_per_scan_ratio": round(total_signals / total_scans, 4) if total_scans else 0,
            "total_markets_scanned": total_markets,
            "total_signals_generated": total_signals,
        },
    }


@app.get("/api/trades/shadow")
async def get_shadow_trade_log(limit: int = 200):
    """Get the shadow (paper) trade log — every entry/exit the bot made."""
    log = _cache.get("paper_trade_log", [])
    # Also include historical trades from the paper trader itself
    trades = []
    if paper_trader:
        for t in paper_trader.tracker.get_trade_history():
            trades.append({
                "time": t.get("exit_time", t.get("entry_time", "")),
                "action": "closed",
                "ticker": t.get("ticker", ""),
                "side": t.get("side", ""),
                "entry_price": t.get("entry_price", 0),
                "exit_price": t.get("exit_price", 0),
                "pnl_cents": t.get("pnl_cents", 0),
                "won": t.get("won", False),
                "log_return": t.get("log_return", 0),
                "category": t.get("category", ""),
            })
    return {
        "live_log": log[-limit:],
        "completed_trades": trades[-limit:],
        "total_shadow_trades": len(trades),
        "open_positions": [
            {
                "ticker": p.ticker,
                "side": p.side,
                "entry_price": p.entry_price,
                "contracts": p.contracts,
                "model_prob": p.model_prob,
                "entry_time": p.entry_time,
            }
            for p in (paper_trader.positions.values() if paper_trader else [])
        ],
    }


