# ── Database History Endpoints ─────────────────────────────────────────────

@app.get("/api/history/trades")
async def get_trade_history(mode: str = "paper", limit: int = 100):
    """Get persistent trade history from Supabase."""
    # Fix #59: Validate source parameter
    if mode not in ("paper", "live"):
        raise HTTPException(400, "mode must be 'paper' or 'live'")
    if not db or not db.is_connected:
        return {"trades": [], "source": "none", "total": 0}
    trades = db.get_trades(mode=mode, limit=limit)
    return {"trades": trades, "source": "local_db", "total": len(trades)}


@app.get("/api/history/scans")
async def get_scan_history(limit: int = 50):
    """Get scan log history from Supabase."""
    # Fix #60: Validate limit is positive
    if limit < 1:
        raise HTTPException(400, "limit must be a positive integer")
    if not db or not db.is_connected:
        return {"scans": [], "source": "none", "total": 0}
    scans = db.get_scan_logs(limit=limit)
    return {"scans": scans, "source": "local_db", "total": len(scans)}


