# ── CSV Export ────────────────────────────────────────────────────────────

@app.get("/api/export/trades")
async def export_trades_csv(
    source: str = "paper",
    start_date: str | None = None,
    end_date: str | None = None,
    category: str | None = None,
    output_format: str = Query("csv", alias="format"),
):
    """Export trade history with optional date range, category filter, and format selection.

    Query params:
      - source: 'paper' or 'live'
      - start_date: ISO date string for range start (inclusive)
      - end_date: ISO date string for range end (inclusive)
      - category: Filter by market category
      - format: 'csv' (default) or 'json'
    """
    if source not in ("paper", "live"):
        raise HTTPException(400, "source must be 'paper' or 'live'")
    # Always export from main performance tracker (Kalshi history) if it has data
    trades = []
    if performance and performance.trades:
        trades = performance.get_trade_history()
    elif paper_trader:
        trades = paper_trader.tracker.get_trade_history()

    # Fix #38: Handle empty trade list without crash
    if not trades:
        if output_format == "json":
            return {"trades": [], "count": 0, "source": source, "message": "No trades found"}
        return StreamingResponse(
            io.BytesIO(b"No trades to export\n"),
            media_type="text/csv",
            headers={"Content-Disposition": f"attachment; filename=trades_{source}_empty.csv"},
        )

    # Apply date range filter
    if start_date:
        trades = [t for t in trades if t.get("entry_time", "") >= start_date]
    if end_date:
        # Include trades up to end of the end_date day
        end_cutoff = end_date + "T23:59:59" if "T" not in end_date else end_date
        trades = [t for t in trades if t.get("entry_time", "") <= end_cutoff]

    # Apply category filter
    if category:
        trades = [t for t in trades if t.get("category", "").lower() == category.lower()]

    if not trades:
        raise HTTPException(404, "No trades match the filters")

    # JSON format option
    if output_format == "json":
        return {"trades": trades, "count": len(trades), "source": source}

    # Default: CSV export
    output = io.StringIO()
    writer = csv.DictWriter(output, fieldnames=trades[0].keys())
    writer.writeheader()
    writer.writerows(trades)

    return StreamingResponse(
        io.BytesIO(output.getvalue().encode()),
        media_type="text/csv",
        headers={"Content-Disposition": f"attachment; filename=trades_{source}_{datetime.now(timezone.utc).strftime('%Y%m%d')}.csv"},
    )


