@app.get("/api/performance/by-category")
async def get_performance_by_category(source: str = "live"):
    """Get P&L breakdown by market category.

    Always uses the main PerformanceTracker (loaded from Kalshi history) as
    the primary source, since that holds real trade data. Falls back to the
    paper trader tracker if performance has no trades.
    """
    try:
        # Prefer the main performance tracker (Kalshi history) regardless of source
        if performance and performance.trades:
            cats = performance.get_metrics_by_category()
            return {"categories": cats if cats else {}, "source": "kalshi"}
        # Fall back to paper trader if no live data
        if paper_trader:
            cats = paper_trader.tracker.get_metrics_by_category()
            return {"categories": cats if cats else {}, "source": "paper"}
    except Exception as e:
        logger.error(f"[/api/performance/by-category] Failed: {e}")
        return {"categories": {}, "error": str(e)}
    return {"categories": {}, "source": source}


@app.get("/api/portfolio/heatmap")
async def get_portfolio_heatmap():
    """Get portfolio positions grouped by category for heatmap visualization.

    Returns paper trading positions organized by market category (politics, crypto,
    sports, etc.) with position count and value data for the frontend heatmap chart.
    """
    if not paper_trader:
        return {"categories": {}}

    # Fix #27: Handle empty portfolio
    if not paper_trader.positions:
        return {"categories": {}, "total_positions": 0}

    from collections import defaultdict
    cats = defaultdict(lambda: {"positions": [], "total_pnl_cents": 0, "count": 0})

    for ticker, pos in paper_trader.positions.items():
        cat = pos.category or "uncategorized"
        entry_val = pos.entry_price * 100 * pos.contracts
        cats[cat]["positions"].append({
            "ticker": ticker,
            "side": pos.side,
            "entry_price": pos.entry_price,
            "contracts": pos.contracts,
            "category": cat,
            "entry_value_cents": int(entry_val),
        })
        cats[cat]["count"] += 1

    return {"categories": dict(cats)}


