# ── Retrain Schedule ──────────────────────────────────────────────────────

class RetrainScheduleRequest(BaseModel):
    """Request body for POST /api/retrain/schedule (update cron schedule)."""
    days: str = "mon,wed,fri"  # Comma-separated day abbreviations for APScheduler CronTrigger
    hour: int = 3              # Hour (UTC) to run the retrain job


@app.get("/api/retrain/schedule")
async def get_retrain_schedule():
    """Get current retrain schedule."""
    job = scheduler.get_job("retrain") if scheduler else None
    return {
        "days": config.retrain_days,
        "hour": config.retrain_hour,
        "active": job is not None,
        "next_run": str(job.next_run_time) if job else None,
    }


@app.post("/api/retrain/schedule")
async def update_retrain_schedule(req: RetrainScheduleRequest):
    """Update the retrain schedule."""
    if not scheduler:
        raise HTTPException(500, "Scheduler not initialized")

    config.retrain_days = req.days
    config.retrain_hour = req.hour

    day_map = {"mon": "mon", "tue": "tue", "wed": "wed", "thu": "thu", "fri": "fri", "sat": "sat", "sun": "sun"}
    days = ",".join(day_map.get(d.strip().lower(), d.strip()) for d in req.days.split(","))

    job = scheduler.get_job("retrain")
    if job:
        scheduler.reschedule_job("retrain", trigger=CronTrigger(day_of_week=days, hour=req.hour))
    else:
        scheduler.add_job(
            _retrain_job,
            CronTrigger(day_of_week=days, hour=req.hour),
            id="retrain",
            replace_existing=True,
        )

    return {"days": req.days, "hour": req.hour, "status": "updated"}


@app.post("/api/retrain/now")
async def retrain_now():
    """Trigger an immediate model retrain with A/B comparison (Task 49)."""
    try:
        # Fix #57: Track retrain duration
        _retrain_start = _time_mod.time()
        prev_cv_score = None
        if rf_generator and rf_generator.model.is_trained:
            prev_cv_score = rf_generator.model.cv_score

        result = await _retrain_job()

        # Task 49: Compare new model with previous
        if prev_cv_score is not None and isinstance(result, dict):
            new_cv = result.get("cv_accuracy", 0)
            diff = new_cv - prev_cv_score
            comparison = {
                "previous_cv_accuracy": round(prev_cv_score, 4),
                "new_cv_accuracy": round(new_cv, 4),
                "accuracy_change": round(diff, 4),
                "warning": diff < -0.02,
                "timestamp": datetime.now(timezone.utc).isoformat(),
            }
            _cache["model_comparison"] = comparison
            if diff < -0.02:
                logger.warning(f"Model accuracy dropped by {abs(diff):.2%}: {prev_cv_score:.4f} -> {new_cv:.4f}")

        _retrain_elapsed = round(_time_mod.time() - _retrain_start, 1)
        _audit_log("model_retrain", f"Manual retrain: {result.get('total_cumulative_samples', 0) if isinstance(result, dict) else 0} samples", user_action=True)
        logger.info(f"[/api/retrain/now] Retrain complete in {_retrain_elapsed}s")
        return {
            "status": "retrain_complete",
            "duration_seconds": _retrain_elapsed,
            **(result if isinstance(result, dict) else {}),
            "model_comparison": _cache.get("model_comparison"),
        }
    except ValueError as e:
        raise HTTPException(400, str(e))
    except Exception as e:
        raise HTTPException(500, f"[/api/retrain/now] Retrain failed: {str(e)}")


