# ── Health Check Endpoint (Task 29) ──────────────────────────────────────────

@app.get("/api/health")
async def health_check():
    """Comprehensive health check for the local server.

    Returns connection status for all services, model state, resource usage,
    uptime, and error counts.
    """
    now = datetime.now(timezone.utc)
    uptime_seconds = _time_mod.time() - _server_start_time

    # Kalshi connection check
    kalshi_connected = False
    kalshi_last_ping = None
    if kalshi and config.validate_kalshi():
        kalshi_connected = True
        kalshi_last_ping = _cache.get("last_scan")

    # Local DB connection check
    local_db_connected = False
    if db:
        local_db_connected = db.is_connected

    # Model state
    model_trained = False
    if rf_generator:
        model_trained = rf_generator.model.is_trained

    # Auto-scan state
    auto_scan_running = _cache.get("auto_scan_enabled", False)

    # Memory usage
    memory_mb = 0.0
    try:
        import resource
        import sys as _sys
        rusage = resource.getrusage(resource.RUSAGE_SELF)
        if _sys.platform == "darwin":
            # macOS: ru_maxrss is in bytes
            memory_mb = round(rusage.ru_maxrss / 1024 / 1024, 1)
        else:
            # Linux: ru_maxrss is in kilobytes
            memory_mb = round(rusage.ru_maxrss / 1024, 1)
    except Exception:
        pass

    # Error count (total tracked)
    error_count = sum(d["error_count"] for d in _api_metrics.values())

    # Task 39: Extended system resource monitoring
    import threading
    thread_count = threading.active_count()

    cpu_time_seconds = 0.0
    try:
        rusage2 = resource.getrusage(resource.RUSAGE_SELF)
        cpu_time_seconds = round(rusage2.ru_utime + rusage2.ru_stime, 2)
    except Exception:
        pass

    open_fds = -1
    try:
        import os as _os2
        open_fds = len(_os2.listdir(f"/proc/{_os2.getpid()}/fd"))
    except Exception:
        pass  # Not available on macOS

    event_loop_lag_ms = -1.0
    try:
        start_lag = _time_mod.monotonic()
        await asyncio.sleep(0)
        event_loop_lag_ms = round((_time_mod.monotonic() - start_lag) * 1000, 2)
    except Exception:
        pass

    # Fix #52: Return checks in health response
    return {
        "status": "ok",
        "kalshi_connected": kalshi_connected,
        "kalshi_last_ping": kalshi_last_ping,
        "local_db_connected": local_db_connected,
        "model_trained": model_trained,
        "auto_scan_running": auto_scan_running,
        "memory_usage_mb": memory_mb,
        "cpu_time_seconds": cpu_time_seconds,
        "open_file_descriptors": open_fds,
        "thread_count": thread_count,
        "event_loop_lag_ms": event_loop_lag_ms,
        "uptime_seconds": round(uptime_seconds, 0),
        "last_scan_time": _cache.get("last_scan"),
        "error_count_last_hour": error_count,
        "paper_trader_positions": len(paper_trader.positions) if paper_trader else 0,
        "checks": _cache.get("startup_checks", {}),
        "startup_checks": _cache.get("startup_checks", {}),
        "error_rate_alert_active": _cache.get("error_alert_active", False),
        "error_spikes": _cache.get("error_spikes", [])[-5:],
        "degraded_mode": _get_degraded_services(),
        "timestamp": now.isoformat(),
    }


