# ── Config Validation Endpoint (Task 30) ──────────────────────────────────────

@app.post("/api/config/validate")
async def validate_config(update: ConfigUpdate):
    """Validate config changes without applying them. Returns warnings about aggressive settings."""
    warnings = []

    if update.kelly_fraction is not None:
        if update.kelly_fraction > 0.7:
            warnings.append({"field": "kelly_fraction", "message": f"Kelly fraction {update.kelly_fraction} is aggressive; values >0.7 risk large drawdowns. Recommended: 0.3-0.5."})
        elif update.kelly_fraction < 0.1:
            warnings.append({"field": "kelly_fraction", "message": f"Kelly fraction {update.kelly_fraction} is very conservative; may miss profitable opportunities."})

    if update.entry_threshold is not None:
        if update.entry_threshold < 0.3:
            warnings.append({"field": "entry_threshold", "message": f"Entry threshold {update.entry_threshold} is very loose; will enter many low-quality trades."})
        elif update.entry_threshold > 0.8:
            warnings.append({"field": "entry_threshold", "message": f"Entry threshold {update.entry_threshold} is very tight; may miss most opportunities."})

    if update.min_edge_threshold is not None:
        # Note: crypto loop uses Kelly as the sole EV gate (min_edge_threshold is RF-only).
        # A threshold of 0 is valid for crypto; only warn if it's RF-relevant (>0 but very low).
        if 0 < update.min_edge_threshold < 0.03:
            warnings.append({"field": "min_edge_threshold", "message": f"Min edge {update.min_edge_threshold:.1%} is very low for RF trades; Kelly criterion handles crypto edge automatically."})
        elif update.min_edge_threshold > 0.25:
            warnings.append({"field": "min_edge_threshold", "message": f"Min edge {update.min_edge_threshold:.1%} is very high; very few RF trades will qualify."})

    if update.max_bet_amount_cents is not None:
        if update.max_bet_amount_cents > 50_00:
            warnings.append({"field": "max_bet_amount_cents", "message": f"Max bet ${update.max_bet_amount_cents/100:.0f} is large; consider smaller sizes for risk management."})

    if update.max_daily_loss_cents is not None:
        if update.max_daily_loss_cents > 50_00:
            warnings.append({"field": "max_daily_loss_cents", "message": f"Daily loss limit ${update.max_daily_loss_cents/100:.0f} is high; consider tighter limits."})

    if update.min_confidence is not None:
        if update.min_confidence < 0.6:
            warnings.append({"field": "min_confidence", "message": f"Min confidence {update.min_confidence:.0%} is low; model predictions below 60% are unreliable."})

    if update.max_open_positions is not None:
        if update.max_open_positions > 20:
            warnings.append({"field": "max_open_positions", "message": f"Max positions {update.max_open_positions} is high; portfolio may be over-diversified."})

    valid = True
    try:
        _ = update.model_dump(exclude_none=True)
    except Exception as e:
        valid = False
        warnings.append({"field": "general", "message": f"Validation error: {e}"})

    return {
        "valid": valid,
        "warnings": warnings,
    }


