# ── Model Performance Dashboard (Task 38) ────────────────────────────────────

@app.get("/api/model/performance")
async def get_model_performance():
    """Get model prediction performance metrics for the current day.

    Computed from the rolling prediction cache: accuracy, avg confidence,
    false positive/negative rates, and calibration curve data.
    """
    predictions = _cache.get("predictions_cache", [])
    today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    today_preds = [p for p in predictions if p.get("timestamp", "").startswith(today)]

    if not today_preds:
        return {
            "predictions_today": 0, "accuracy_today": 0,
            "avg_confidence_today": 0, "false_positive_rate": 0,
            "false_negative_rate": 0, "calibration_curve": [],
        }

    total = len(today_preds)
    correct = sum(1 for p in today_preds if p.get("correct", False))
    avg_confidence = sum(p.get("confidence", 0) for p in today_preds) / total

    fp = sum(1 for p in today_preds if p.get("predicted_yes") and not p.get("actual_yes", True))
    fn = sum(1 for p in today_preds if not p.get("predicted_yes") and p.get("actual_yes", False))
    actual_neg = max(1, sum(1 for p in today_preds if not p.get("actual_yes", True)))
    actual_pos = max(1, sum(1 for p in today_preds if p.get("actual_yes", False)))

    # Calibration curve: 10 bins by predicted confidence
    bins = [[] for _ in range(10)]
    for p in today_preds:
        bin_idx = min(9, int(p.get("confidence", 0.5) * 10))
        bins[bin_idx].append(p)
    calibration = []
    for i, bucket in enumerate(bins):
        if bucket:
            calibration.append({
                "predicted": round((i + 0.5) / 10, 2),
                "actual": round(sum(1 for p in bucket if p.get("correct")) / len(bucket), 4),
                "count": len(bucket),
            })

    return {
        "predictions_today": total,
        "accuracy_today": round(correct / total, 4),
        "avg_confidence_today": round(avg_confidence, 4),
        "false_positive_rate": round(fp / actual_neg, 4),
        "false_negative_rate": round(fn / actual_pos, 4),
        "calibration_curve": calibration,
    }


# ── Trade Archival (Task 42) ──────────────────────────────────────────────────

@app.post("/api/trades/archive")
async def archive_old_trades(days: int = 30):
    """Archive trades older than N days by marking them in the database."""
    if not db or not db.is_connected:
        raise HTTPException(400, "Database not connected")
    try:
        cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).isoformat()
        result = db.archive_old_trades(cutoff)
        return {"status": "archived", "cutoff_date": cutoff, "days": days, **result}
    except Exception as e:
        raise HTTPException(500, str(e))


# ── Win Probability for Open Positions (Task 35) ─────────────────────────────

@app.get("/api/positions/win-probability")
async def get_positions_win_probability(source: str = "paper"):
    """Get estimated win probability for each open position."""
    positions = []
    tracker = None

    if source == "paper" and paper_trader:
        tracker = paper_trader.tracker
        for ticker, pos in paper_trader.positions.items():
            positions.append({
                "ticker": pos.ticker, "side": pos.side,
                "entry_price": pos.entry_price, "model_prob": pos.model_prob,
                "entry_time": pos.entry_time, "current_price": pos.max_price_seen,
            })
    elif source == "live" and kalshi and config.validate_kalshi():
        tracker = performance
        try:
            live_positions = await asyncio.to_thread(kalshi.get_positions)
            for pos in live_positions:
                market = await asyncio.to_thread(kalshi.get_market, pos.ticker)
                current = market.mid_price_yes / 100 if market else pos.avg_price_cents / 100
                positions.append({
                    "ticker": pos.ticker, "side": pos.side,
                    "entry_price": pos.avg_price_cents / 100, "model_prob": 0.5,
                    "entry_time": "", "current_price": current,
                })
        except Exception:
            pass

    if not tracker:
        return {"positions": [], "total": 0}

    # Fix #39: Handle empty positions
    if not positions:
        return {"positions": [], "total": 0}

    result = []
    for pos_data in positions:
        try:
            win_prob = tracker.estimate_win_probability(pos_data)
            result.append({**pos_data, **win_prob})
        except Exception as e:
            logger.warning(f"[/api/positions/win-probability] Failed for {pos_data.get('ticker', '?')}: {e}")
            result.append({**pos_data, "win_probability": None, "error": str(e)})
    return {"positions": result, "total": len(result)}


