# ── SSE Event Stream (Task 1 & 2) ─────────────────────────────────────────


async def broadcast_sse_event(event_type: str, data: dict):
    """Push an event to all connected SSE clients.

    Args:
        event_type: One of scan_complete, signal_found, trade_executed,
                    model_retrained, alert_triggered, scan_progress.
        data: JSON-serializable payload.
    """
    import json
    message = f"event: {event_type}\ndata: {json.dumps(data)}\n\n"
    dead_clients = set()
    for q in list(_sse_clients):
        # Fix #40: Add try/except around queue.put_nowait
        try:
            q.put_nowait(message)
        except asyncio.QueueFull:
            dead_clients.add(q)
        except Exception as e:
            logger.warning(f"[broadcast_sse_event] Failed to send to SSE client: {e}")
            dead_clients.add(q)
    _sse_clients.difference_update(dead_clients)


@app.get("/api/stream")
async def sse_stream():
    """Server-Sent Events endpoint for real-time updates.

    Streams events: scan_complete, signal_found, trade_executed,
    model_retrained, alert_triggered, scan_progress.
    Auto-disconnects after 5 minutes.
    """
    import json

    queue: asyncio.Queue = asyncio.Queue(maxsize=100)
    _sse_clients.add(queue)

    async def event_generator():
        try:
            # Send initial connection event
            yield f"event: connected\ndata: {json.dumps({'status': 'connected', 'timestamp': datetime.now(timezone.utc).isoformat()})}\n\n"

            # Auto-disconnect after 5 minutes
            deadline = asyncio.get_event_loop().time() + 300

            while asyncio.get_event_loop().time() < deadline:
                try:
                    # Wait for events with a 30s timeout (sends keepalive)
                    message = await asyncio.wait_for(queue.get(), timeout=30.0)
                    yield message
                except asyncio.TimeoutError:
                    # Send keepalive comment
                    yield ": keepalive\n\n"

            yield f"event: disconnect\ndata: {json.dumps({'reason': 'timeout', 'duration_seconds': 300})}\n\n"
        finally:
            _sse_clients.discard(queue)

    return StreamingResponse(
        event_generator(),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "Connection": "keep-alive",
            "X-Accel-Buffering": "no",
        },
    )


# ── Batch Trade Execution (Task 3) ────────────────────────────────────────

class BatchTradeItem(BaseModel):
    """Single trade in a batch request."""
    ticker: str
    side: str = "yes"
    price_cents: int = 50
    count: int = 1


class BatchTradeRequest(BaseModel):
    """Request body for POST /api/trades/batch."""
    trades: list[BatchTradeItem]


@app.post("/api/trades/batch")
async def batch_trades(req: BatchTradeRequest):
    """Execute multiple trades sequentially with per-trade error handling.

    Accepts an array of trade requests and executes them in order.
    Returns results array with success/fail per trade.
    """
    if not kalshi or not config.validate_kalshi():
        raise HTTPException(400, "Kalshi not connected")

    if len(req.trades) > 20:
        raise HTTPException(400, "Maximum 20 trades per batch")

    results = []
    for i, trade in enumerate(req.trades):
        try:
            order = OrderRequest(
                ticker=trade.ticker,
                side=Side(trade.side),
                price_cents=trade.price_cents,
                count=trade.count,
            )
            # Fix #72: Use asyncio.to_thread for blocking call
            result = await asyncio.to_thread(kalshi.place_order, order)
            if risk_manager:
                risk_manager.record_trade()
            results.append({
                "index": i,
                "ticker": trade.ticker,
                "success": True,
                "result": result.model_dump(),
            })
            # Broadcast to SSE
            await broadcast_sse_event("trade_executed", {
                "ticker": trade.ticker,
                "side": trade.side,
                "price_cents": trade.price_cents,
                "count": trade.count,
            })
        except Exception as e:
            results.append({
                "index": i,
                "ticker": trade.ticker,
                "success": False,
                "error": str(e),
            })

    succeeded = sum(1 for r in results if r["success"])
    return {
        "total": len(results),
        "succeeded": succeeded,
        "failed": len(results) - succeeded,
        "results": results,
    }


# ── Market Watchlist (Task 5) ─────────────────────────────────────────────

class WatchlistItem(BaseModel):
    """Request body for POST /api/watchlist."""
    ticker: str


@app.post("/api/watchlist")
async def add_to_watchlist(item: WatchlistItem):
    """Add a ticker to the watchlist. Max 100 items."""
    # Fix #14: Validate ticker format (non-empty, reasonable length)
    if not item.ticker or not item.ticker.strip():
        raise HTTPException(400, "Ticker must be a non-empty string")
    if len(item.ticker) > 100:
        raise HTTPException(400, "Ticker must be 100 characters or fewer")
    watchlist = _cache.get("watchlist", [])
    # Fix #15: Increase max to 100
    if len(watchlist) >= 100:
        raise HTTPException(400, "Watchlist full (max 100 items)")
    # Check against both string and dict entries
    existing_tickers = [
        (w["ticker"] if isinstance(w, dict) else w) for w in watchlist
    ]
    if item.ticker in existing_tickers:
        raise HTTPException(400, f"{item.ticker} already in watchlist")
    # Fix #69: Add added_at timestamp to each watchlist entry
    watchlist.append({"ticker": item.ticker, "added_at": datetime.now(timezone.utc).isoformat()})
    _cache["watchlist"] = watchlist
    logger.info(f"[/api/watchlist] Added {item.ticker} to watchlist")
    return {"watchlist": watchlist, "count": len(watchlist)}


@app.get("/api/watchlist")
async def get_watchlist():
    """Get watchlist with current prices and model predictions."""
    watchlist = _cache.get("watchlist", [])
    if not watchlist:
        return {"watchlist": [], "count": 0}

    items = []
    for entry in watchlist:
        # Support both old string format and new dict format
        ticker = entry["ticker"] if isinstance(entry, dict) else entry
        added_at = entry.get("added_at") if isinstance(entry, dict) else None
        item_data = {"ticker": ticker, "added_at": added_at}
        try:
            if kalshi and config.validate_kalshi():
                market = await asyncio.to_thread(kalshi.get_market, ticker)
                if market:
                    item_data["yes_bid"] = market.yes_bid
                    item_data["yes_ask"] = market.yes_ask
                    item_data["mid_price_yes"] = market.mid_price_yes
                    item_data["volume"] = market.volume
                    item_data["status"] = market.status

                    if rf_generator and rf_generator.model.is_trained:
                        from bot.models import Event as _Evt
                        event = _Evt(event_ticker=market.event_ticker, title=market.title)
                        features = extract_features(market, event)
                        model_prob = rf_generator.model.predict_probability(features)
                        market_price = market.mid_price_yes / 100
                        item_data["model_probability"] = round(model_prob, 4)
                        item_data["edge"] = round(model_prob - market_price, 4)
                        item_data["explanation"] = rf_generator.model.explain_prediction(features)
                else:
                    item_data["error"] = "Market not found"
        except Exception as e:
            item_data["error"] = str(e)
        items.append(item_data)

    return {"watchlist": items, "count": len(items)}


@app.delete("/api/watchlist/{ticker}")
async def remove_from_watchlist(ticker: str):
    """Remove a ticker from the watchlist."""
    watchlist = _cache.get("watchlist", [])
    # Support both old string format and new dict format
    existing_tickers = [
        (w["ticker"] if isinstance(w, dict) else w) for w in watchlist
    ]
    if ticker not in existing_tickers:
        raise HTTPException(404, f"{ticker} not in watchlist")
    watchlist = [w for w in watchlist if (w["ticker"] if isinstance(w, dict) else w) != ticker]
    _cache["watchlist"] = watchlist
    logger.info(f"[/api/watchlist] Removed {ticker} from watchlist")
    return {"watchlist": watchlist, "count": len(watchlist)}


