@app.get("/api/model/explain/{ticker}")
async def explain_market_prediction(ticker: str):
    """Get prediction explanation for a specific market ticker.

    Returns the top 3 features that most influence the prediction.
    """
    if not kalshi or not config.validate_kalshi():
        raise HTTPException(400, "Kalshi not connected")
    if not rf_generator or not rf_generator.model.is_trained:
        raise HTTPException(400, "Model not trained")

    market = await asyncio.to_thread(kalshi.get_market, ticker)
    if not market:
        raise HTTPException(404, f"Market {ticker} not found")

    from bot.models import Event as _Evt
    event = _Evt(event_ticker=market.event_ticker, title=market.title)
    features = extract_features(market, event)
    model_prob = rf_generator.model.predict_probability(features)
    explanation = rf_generator.model.explain_prediction(features)

    return {
        "ticker": ticker,
        "model_probability": round(model_prob, 4),
        "market_price": market.mid_price_yes / 100,
        "explanation": explanation,
    }


