# ── Advanced Analytics Endpoints (Tasks 11-15) ────────────────────────────

class MonteCarloRequest(BaseModel):
    """Request body for POST /api/backtest/monte-carlo."""
    n_simulations: int = 1000
    source: str = "paper"  # "paper" or "live"


@app.post("/api/backtest/monte-carlo")
async def run_monte_carlo(req: MonteCarloRequest):
    """Run Monte Carlo simulation on existing trade history.

    Randomly reorders the trade sequence n_simulations times and computes
    distribution of final P&L, max drawdown, and Sharpe ratio.
    """
    tracker = None
    if req.source == "paper" and paper_trader:
        tracker = paper_trader.tracker
    elif req.source == "live" and performance:
        tracker = performance

    if not tracker or len(tracker.trades) < 5:
        raise HTTPException(400, "Need at least 5 completed trades for Monte Carlo simulation")

    bt = Backtester()
    bt.tracker = tracker
    result = await asyncio.to_thread(
        bt.monte_carlo_sim,
        tracker.trades,
        min(req.n_simulations, 10000),
    )
    return result


class WalkForwardRequest(BaseModel):
    """Request body for POST /api/backtest/walk-forward."""
    n_windows: int = 4
    max_markets: int = 200


@app.post("/api/backtest/walk-forward")
async def run_walk_forward(req: WalkForwardRequest):
    """Run walk-forward optimization on historical data.

    Splits data into rolling train/test windows for more robust out-of-sample testing.
    """
    if not kalshi or not config.validate_kalshi():
        raise HTTPException(400, "Kalshi not connected")

    try:
        fetcher = HistoricalDataFetcher(kalshi)
        settled = await asyncio.to_thread(fetcher.fetch_settled_markets, req.max_markets)

        bt = Backtester(kalshi)
        result = await asyncio.to_thread(
            bt.walk_forward,
            settled,
            n_windows=min(req.n_windows, 10),
        )
        return result
    except httpx.ConnectError:
        raise HTTPException(503, "Kalshi API unreachable — connection failed")
    except Exception as e:
        raise HTTPException(500, f"[/api/backtest/walk-forward] Walk-forward failed: {str(e)}")


