@app.get("/api/monitor/history")
async def get_monitor_history(limit: int = 288):
    """Return recent monitor_events rows for the dashboard balance chart.
    Read-only — no bot logic. Default 288 rows = ~24h at 5-min intervals."""
    try:
        import sqlite3 as _mdb
        _mc = _mdb.connect("data/bot.db", check_same_thread=False)
        _mc.row_factory = _mdb.Row
        rows = _mc.execute(
            "SELECT iso, balance_cents, portfolio_value_cents, total_portfolio_cents, pct_from_base, floor_breach, note "
            "FROM monitor_events ORDER BY ts DESC LIMIT ?", (limit,)
        ).fetchall()
        _mc.close()
        return {"history": [dict(r) for r in reversed(rows)]}
    except Exception as e:
        return {"history": [], "error": str(e)}

@app.get("/api/monitor/skips")
async def get_monitor_skips(limit: int = 40):
    """Return recent SKIP lines from predbot.log for the dashboard. Read-only."""
    import subprocess as _sp
    try:
        result = _sp.run(
            ["grep", "-E", "SKIP|PLACING|FILLED|CRYPTO", "/tmp/predbot.log"],
            capture_output=True, text=True, timeout=3
        )
        lines = [l for l in result.stdout.splitlines()
                 if "shadow" not in l.lower() and "127.0.0.1" not in l
                 and "CHECK" not in l and "skipped" not in l.lower()]
        return {"skips": lines[-limit:]}
    except Exception as e:
        return {"skips": [], "error": str(e)}


@app.get("/api/shadow/w11")
async def get_w11_shadow_state():
    """Return Wave 11 shadow tournament state — all 50 bots."""
    import math as _math
    result = {}
    for bot_id, bot in _w11_bots.items():
        cfg = bot["config"]
        trades = bot["trades"]
        settled = [t for t in trades if t.get("action") in ("settled", "stop_exit")]
        wins = sum(1 for t in settled if t.get("won") is True)
        losses = sum(1 for t in settled if t.get("won") is False)
        pnls = [t.get("pnl_cents", 0) for t in settled]
        if len(pnls) >= 2:
            mean_pnl = sum(pnls) / len(pnls)
            variance = sum((x - mean_pnl) ** 2 for x in pnls) / len(pnls)
            std_pnl = _math.sqrt(variance) if variance > 0 else 0
            sharpe = round(mean_pnl / std_pnl, 3) if std_pnl > 0 else None
        else:
            sharpe = None
        result[bot_id] = {
            "label":          cfg.get("label", bot_id),
            "config":         {k: v for k, v in cfg.items() if k not in ("coins", "bad_hours")},
            "coins":          cfg.get("coins", []),
            "balance_cents":  bot["balance"],
            "peak_cents":     bot["peak"],
            "init_cents":     _W11_INIT_BAL,
            "pnl_cents":      bot["balance"] - _W11_INIT_BAL,
            "pnl_pct":        round((bot["balance"] - _W11_INIT_BAL) / _W11_INIT_BAL * 100, 2),
            "open_positions": len(bot["positions"]),
            "total_trades":   len(settled),
            "wins":           wins,
            "losses":         losses,
            "win_rate":       round(wins / len(settled), 3) if settled else None,
            "total_pnl_cents": sum(pnls),
            "sharpe":         sharpe,
        }
    return {"wave": 11, "bot_count": len(result), "init_balance_cents": _W11_INIT_BAL, "bots": result}


