def _shadow_wave_response(wave_num, bots_dict, init_bal):
    """Generic shadow wave API response builder."""
    import math as _mth
    result = {}
    for bot_id, bot in bots_dict.items():
        cfg = bot["config"]
        settled = [t for t in bot["trades"] if t.get("action") in ("settled", "stop_exit")]
        wins  = sum(1 for t in settled if t.get("won") is True)
        losses = sum(1 for t in settled if t.get("won") is False)
        pnls  = [t.get("pnl_cents", 0) for t in settled]
        sharpe = None
        if len(pnls) >= 2:
            mean_p = sum(pnls) / len(pnls)
            var = sum((x - mean_p)**2 for x in pnls) / len(pnls)
            std = _mth.sqrt(var) if var > 0 else 0
            sharpe = round(mean_p / std, 3) if std > 0 else None
        result[bot_id] = {
            "label":           cfg.get("label", bot_id),
            "config":          cfg,
            "balance_cents":   bot["balance"],
            "peak_cents":      bot["peak"],
            "init_cents":      init_bal,
            "pnl_cents":       bot["balance"] - init_bal,
            "pnl_pct":         round((bot["balance"] - init_bal) / init_bal * 100, 2),
            "open_positions":  len(bot["positions"]),
            "total_trades":    len(settled),
            "wins":            wins,
            "losses":          losses,
            "win_rate":        round(wins / len(settled), 3) if settled else None,
            "total_pnl_cents": sum(pnls),
            "sharpe":          sharpe,
            "pruned":          bot.get("pruned", False),
        }
    return {"wave": wave_num, "bot_count": len(result), "init_balance_cents": init_bal, "bots": result}

