@app.get("/api/shadow/w33/leader")
async def get_w33_leader():
    """Return the current W33 tournament leader and auto-promotion status.

    Returns the top bot by PnL with eligibility info for auto-promotion.
    A bot becomes eligible for live config promotion after 60+ minutes of
    profitable trading (4+ consecutive 15-min windows with ≥45% WR).
    """
    import time as _lt
    import math as _lm
    _now = _lt.time()
    _eligible = []
    _all_results = []
    for _bot_id, _bot in _w33_bots.items():
        _cfg = _bot["config"]
        _settled = [t for t in _bot["trades"] if t.get("action") == "settled"]
        if not _settled:
            continue
        _wins = sum(1 for t in _settled if t.get("won") is True)
        _pnls = [t.get("pnl_cents", 0) for t in _settled]
        _pnl  = _bot["balance"] - _W33_INIT_BAL
        _wr   = _wins / len(_settled)
        _sharpe = None
        if len(_pnls) >= 2:
            _mu = sum(_pnls) / len(_pnls)
            _var = sum((x - _mu)**2 for x in _pnls) / len(_pnls)
            _std = _lm.sqrt(_var) if _var > 0 else 0
            _sharpe = round(_mu / _std, 3) if _std > 0 else None
        _since  = _w33_profitable_since.get(_bot_id)
        _streak = round((_now - _since) / 60.0, 1) if _since else 0
        _entry = {
            "bot_id":       _bot_id,
            "label":        _cfg.get("label", _bot_id),
            "pnl_cents":    _pnl,
            "win_rate":     round(_wr, 3),
            "trades":       len(_settled),
            "profitable_streak_min": _streak,
            "eligible_for_promotion": (_pnl > 0 and _wr >= 0.45 and len(_settled) >= 4 and _streak >= 60.0),
            "config":       {k: v for k, v in _cfg.items() if k != "coins"},
        }
        _all_results.append(_entry)
        if _entry["eligible_for_promotion"]:
            _eligible.append(_entry)

    _all_results.sort(key=lambda x: x["pnl_cents"], reverse=True)
    _eligible.sort(key=lambda x: x["pnl_cents"], reverse=True)
    return {
        "wave": 33,
        "bot_count": len(_w33_bots),
        "init_balance_cents": _W33_INIT_BAL,
        "last_promoted_bot": _w33_last_promoted_bot,
        "promotion_eligible_count": len(_eligible),
        "top_10": _all_results[:10],
        "top_eligible": _eligible[:5],
        "live_config": {
            "edge":  _live_min_edge_cents,
            "kelly": _live_kelly_base,
            "wp":    _live_min_win_prob,
        },
    }


@app.get("/api/tournament/status")
async def get_tournament_status():
    """Return tournament pruning status and top survivors."""
    import math as _math
    import datetime as _dt
    _all_wave_dicts = [
        _w7_bots, _w11_bots, _w12_bots, _w13_bots, _w14_bots, _w15_bots,
        _w16_bots, _w17_bots, _w18_bots, _w19_bots, _w20_bots, _w21_bots, _w22_bots,
        _w23_bots, _w24_bots, _w25_bots, _w26_bots, _w27_bots,
        _w28_bots, _w29_bots, _w30_bots, _w31_bots, _w32_bots,
    ]
    _total = sum(len(d) for d in _all_wave_dicts)
    _alive = sum(1 for d in _all_wave_dicts for b in d.values() if not b.get("pruned"))
    _pruned = _total - _alive

    # Top 10 by PnL
    _all_bots = []
    for _wd in _all_wave_dicts:
        for _bid, _bot in _wd.items():
            _init = 8000
            _pnl  = _bot["balance"] - _init
            _settled = [t for t in _bot["trades"] if t.get("action") in ("settled", "stop_exit")]
            _all_bots.append((_pnl, _bid, _bot, len(_settled)))
    _all_bots.sort(key=lambda x: x[0], reverse=True)
    _survivors = []
    for _pnl, _bid, _bot, _ntrades in _all_bots[:10]:
        _survivors.append({
            "bot_id":    _bid,
            "label":     _bot["config"].get("label", _bid),
            "pnl_cents": _pnl,
            "trades":    _ntrades,
            "pruned":    _bot.get("pruned", False),
        })

    import time as _ttt
    _last_iso = None
    _next_in  = None
    if _tournament_last_prune > 0:
        _last_iso = _dt.datetime.utcfromtimestamp(_tournament_last_prune).isoformat() + "Z"
        _elapsed  = _ttt.time() - _tournament_last_prune
        _next_in  = max(0, int(_TOURNAMENT_PRUNE_INTERVAL_SEC - _elapsed))
    else:
        _next_in = int(_TOURNAMENT_PRUNE_INTERVAL_SEC)

    return {
        "prune_count":          _tournament_prune_count,
        "last_prune_iso":       _last_iso,
        "next_prune_in_seconds": _next_in,
        "total_bots":           _total,
        "alive_bots":           _alive,
        "pruned_bots":          _pruned,
        "survivors":            _survivors,
    }

